const RARITY_COLORS = { Common:"#95a5a6", Uncommon:"#27ae60", Rare:"#2980b9", Epic:"#9b59b6", Legendary:"#f39c12", Mythic:"#e74c3c" };
const RARITY_MULT   = { Common:1, Uncommon:1.35, Rare:1.85, Epic:2.6, Legendary:3.5, Mythic:5.5 };
const RARITY_SELL   = { Common:8, Uncommon:20, Rare:50, Epic:110, Legendary:250, Mythic:600 };

// Weapon damage ranges per rarity — intentionally overlapping between adjacent tiers
// A lucky Common CAN beat an Uncommon, but never beats a Rare.
const DMG_RANGE = {
  Common:    { min:4,  max:10 },
  Uncommon:  { min:8,  max:16 },  // overlaps Common top
  Rare:      { min:14, max:24 },  // overlaps Uncommon top
  Epic:      { min:21, max:35 },  // overlaps Rare top
  Legendary: { min:32, max:50 },  // overlaps Epic top
  Mythic:    { min:48, max:75 },  // overlaps Legendary top
};
function rollDmg(rarity) {
  const { min, max } = DMG_RANGE[rarity] || DMG_RANGE.Common;
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

