function GearIcon({ name, size=40, rarity, style={} }) {
  const coords = GEAR_COORDS[name];
  const rc = rarity ? (RARITY_COLORS[rarity] || "#c9a84c") : "#c9a84c";
  if (!coords) return (
    <div style={{ width:size, height:size, flexShrink:0, background:rc+"22",
      border:`1px solid ${rc}55`, borderRadius:4, display:"flex",
      alignItems:"center", justifyContent:"center",
      fontSize:Math.round(size*0.45)+"px", color:rc, fontWeight:700,
      lineHeight:1, ...style }}>
      {(name||"?")[0]}
    </div>
  );
  const [sx, sy, sheet] = coords;
  const isK  = sheet === 1;
  const cell = isK ? KYRISE_CELL : RAVEN_CELL;
  const srcW = isK ? KYRISE_W    : RAVEN_W;
  const srcH = isK ? KYRISE_H    : RAVEN_H;
  const src  = isK ? KYRISE_SHEET : RAVEN_SHEET;
  const sc2  = size / cell;
  return (
    <div style={{ width:size, height:size, flexShrink:0, overflow:"hidden",
      position:"relative", display:"inline-block", ...style }}>
      <img src={src} alt={name} style={{
        position:"absolute",
        left:Math.round(-(sx*sc2))+"px", top:Math.round(-(sy*sc2))+"px",
        width:Math.round(srcW*sc2)+"px", height:Math.round(srcH*sc2)+"px",
        imageRendering:"pixelated", display:"block", maxWidth:"none",
      }}/>
    </div>
  );
}

// ─── ITEM DATABASE ────────────────────────────────────────────────────────────
// Weapons have NO base stats — damage type is determined by weapon.type.
// All gear uses the 5 new stats: strength, dexterity, intelligence, constitution, charisma.
// Stamina, melee, range, magic are fully removed.
// Default damage types by weapon type. Multi-damage weapons override with dmgTypes on item.
const WEAPON_DAMAGE_TYPE = {
  Sword:"melee", Axe:"melee", Mace:"melee", Polearm:"melee",
  Dagger:"melee",
  Bow:"ranged", Crossbow:"ranged", Ranged:"ranged",
  Staff:"magic", Wand:"magic", Scepter:"magic", Tome:"magic", Orb:"magic", Grimoire:"magic",
};
// Get damage types for an equipped weapon item (uses item.dmgTypes if present, else lookup)
function getWeaponDmgTypes(item) {
  if (!item) return [];
  return item.dmgTypes || [WEAPON_DAMAGE_TYPE[item.type] || "melee"];
}

