// ─── DUNGEONS ─────────────────────────────────────────────────────────────────
// Boss HP scales continuously across ALL 100 floors (10 dungeons x 10 floors).
// Formula: bossHP(globalFloor) = round(150 * 1.055^(globalFloor-1))
// D1F1 boss=150 → D1F10 boss=243 → D2F1 boss=256 → ... → D10F10 boss=30,000

function globalFloorBossHP(dungeonIdx, floorIdx) {
  const gf = dungeonIdx * 10 + floorIdx + 1; // 1..100
  return Math.round(450 * Math.pow(1.055, gf - 1));
}
function globalFloorRegHP(dungeonIdx, floorIdx) {
  return Math.round(globalFloorBossHP(dungeonIdx, floorIdx) * 0.35);
}
function globalFloorBossAtk(dungeonIdx, floorIdx) {
  const gf = dungeonIdx * 10 + floorIdx + 1;
  return Math.round(20 * Math.pow(1.045, gf - 1));
}
function globalFloorRegAtk(dungeonIdx, floorIdx) {
  return Math.round(globalFloorBossAtk(dungeonIdx, floorIdx) * 0.6);
}

