// ─── COMBAT GEAR STAT RANGES ─────────────────────────────────────────────────
// Gear no longer adds to STR/DEX/INT/CON/CHA — those grow through leveling only.
// Armor/shields roll hp + dodge. Accessories roll crit/hp/dodge. magicDmg is weapon-only.
const GEAR_RANGES = {
  hp:       { Common:[5,15],  Uncommon:[12,25], Rare:[20,40],  Epic:[35,60],  Legendary:[55,90],  Mythic:[80,130] },
  dodge:    { Common:[0,1],   Uncommon:[1,2],   Rare:[2,4],    Epic:[3,6],    Legendary:[5,9],    Mythic:[8,14]   },
  crit:     { Common:[0,1],   Uncommon:[1,2],   Rare:[1,3],    Epic:[2,5],    Legendary:[4,8],    Mythic:[7,12]   },
  magicDmg: { Common:[1,4],   Uncommon:[3,7],   Rare:[6,12],   Epic:[10,18],  Legendary:[15,25],  Mythic:[22,35]  },
};
function rollGearStat(stat, rarity) {
  const [min, max] = GEAR_RANGES[stat][rarity];
  return Math.floor(Math.random() * (max - min + 1)) + min;
}
const ARMOR_SLOTS    = new Set(["head","body","hands","feet","offhand"]);
const ACCESSORY_SLOTS = new Set(["ring","necklace"]);

// ─── HELPERS ──────────────────────────────────────────────────────────────────
function weightedPick(pool) {
  const total = pool.reduce((s, e) => s + e.w, 0);
  let r = Math.random() * total;
  for (const entry of pool) { r -= entry.w; if (r <= 0) return entry.name; }
  return pool[pool.length - 1].name;
}

// fortune shifts rarity roll upward: each point = 0.4% luck bonus (capped at 30%)
function rollRarity(isFinalBoss, isFloorBoss, fortune, isWeeklyBoss, isMythicCreature) {
  const luck = Math.min(0.15, (fortune || 0) * 0.002);
  const clamp = v => Math.min(1, v + luck * v);
  const r = Math.random();

  // Mythic creature fights (e.g. special encounters) — 10% Mythic
  if (isMythicCreature) {
    if (r < clamp(0.10)) return "Common";
    if (r < clamp(0.25)) return "Uncommon";
    if (r < clamp(0.50)) return "Rare";
    if (r < clamp(0.75)) return "Epic";
    if (r < clamp(0.90)) return "Legendary";
    return "Mythic";                          // 10%
  }

  // Weekly boss — 1% Mythic
  if (isWeeklyBoss) {
    if (r < clamp(0.15)) return "Common";
    if (r < clamp(0.35)) return "Uncommon";
    if (r < clamp(0.60)) return "Rare";
    if (r < clamp(0.80)) return "Epic";
    if (r < clamp(0.99)) return "Legendary";
    return "Mythic";                          // 1%
  }

  // Final/dungeon boss — 0.1% Mythic
  if (isFinalBoss) {
    if (r < clamp(0.50)) return "Common";
    if (r < clamp(0.78)) return "Uncommon";
    if (r < clamp(0.93)) return "Rare";
    if (r < clamp(0.984)) return "Epic";
    if (r < clamp(0.9990)) return "Legendary";
    return "Mythic";                          // 0.1%
  }

  // Floor boss — 0.01% Mythic
  if (isFloorBoss) {
    if (r < clamp(0.60)) return "Common";
    if (r < clamp(0.87)) return "Uncommon";
    if (r < clamp(0.96)) return "Rare";
    if (r < clamp(0.994)) return "Epic";
    if (r < clamp(0.9999)) return "Legendary";
    return "Mythic";                          // 0.01%
  }

  // Regular enemy — 0.001% Mythic
  if (r < clamp(0.75)) return "Common";
  if (r < clamp(0.95)) return "Uncommon";
  if (r < clamp(0.985)) return "Rare";
  if (r < clamp(0.9995)) return "Epic";
  if (r < clamp(0.999990)) return "Legendary";
  return "Mythic";                            // 0.001%
}

function makeItem(name, rarity) {
  const t = ITEM_DB[name];
  if (!t) return null;

  // ── Weapons & offhand shields: roll dmg, no stats ──
  if (t.slot === "weapon") {
    const dmg = rollDmg(rarity);
    const dmgTypes = t.dmgTypes ? [...t.dmgTypes] : [WEAPON_DAMAGE_TYPE[t.type] || "melee"];
    return {
      id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
      name, rarity, slot: t.slot, icon: t.icon, type: t.type, desc: t.desc,
      dmg, dmgTypes, stats: {},
    };
  }

  // ── Armor (head/chest/legs/hands/feet/offhand): hp always + dodge by rarity ──
  if (ARMOR_SLOTS.has(t.slot)) {
    const combat = { hp: rollGearStat("hp", rarity) };
    // Dodge appears on Uncommon+ (higher rarity = more likely + higher value)
    const dodgeChance = { Common:0, Uncommon:0.4, Rare:0.7, Epic:0.9, Legendary:1.0, Mythic:1.0 };
    if (Math.random() < (dodgeChance[rarity] || 0)) {
      combat.dodge = rollGearStat("dodge", rarity);
    }
    // Mythic gets a crit bonus too
    if (rarity === "Mythic") {
      combat.crit = rollGearStat("crit", "Rare");
    }
    return {
      id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
      name, rarity, slot: t.slot, icon: t.icon, type: t.type, desc: t.desc,
      stats: combat,
    };
  }

  // ── Accessories (ring/necklace): roll from crit/hp/dodge ──
  if (ACCESSORY_SLOTS.has(t.slot)) {
    const pool = ["crit","hp","dodge"];
    const numStats = rarity === "Common" ? 1
      : rarity === "Uncommon" ? 1
      : rarity === "Rare"     ? 2
      : rarity === "Epic"     ? 2
      : rarity === "Legendary"? 3
      : 4; // Mythic gets all 4
    const picked = rarity === "Mythic"
      ? [...pool]
      : [...pool].sort(() => Math.random() - 0.5).slice(0, numStats);
    const combat = {};
    picked.forEach(k => { combat[k] = rollGearStat(k, rarity); });
    return {
      id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
      name, rarity, slot: t.slot, icon: t.icon, type: t.type, desc: t.desc,
      stats: combat,
    };
  }

  // ── Fallback (shouldn't happen after lantern removal) ──
  return {
    id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
    name, rarity, slot: t.slot, icon: t.icon, type: t.type, desc: t.desc,
    stats: {},
  };
}

function sellValue(item)  { return RARITY_SELL[item.rarity] || 8; }
function xpToLevel(xp)    { return Math.floor(Math.sqrt(xp / 200)) + 1; }
function xpForLevel(lv)   { return Math.pow(lv - 1, 2) * 200; }
function xpForNext(lv)    { return Math.pow(lv, 2) * 200; }
// Gear contributes combat stats only: hp, dodge, crit, magicDmg
function gearCombatStats(eq) {
  const t = { hp:0, dodge:0, crit:0, magicDmg:0 };
  Object.values(eq).forEach(item => {
    if (!item || !item.stats) return;
    Object.entries(item.stats).forEach(([k,v]) => { if (t[k] !== undefined) t[k] += v; });
  });
  return t;
}
// Keep gearBonus as alias returning empty stat object (stats now level-only)
function gearBonus(eq) {
  return { strength:0, dexterity:0, intelligence:0, constitution:0, fortune:0 };
}
// Returns the damage type of the equipped weapon: "melee"|"ranged"|"magic"|"none"
function weaponDamageType(eq) {
  const w = eq?.weapon;
  if (!w) return "none";
  // Use first dmgType for primary damage type
  return (w.dmgTypes && w.dmgTypes[0]) || WEAPON_DAMAGE_TYPE[w.type] || "melee";
}
// Weapon base damage from rolled dmg stat (fallback to 5 if old item without dmg)
function weaponBaseDmg(eq) {
  return eq?.weapon?.dmg || 5;
}
// Primary offensive stat for the equipped weapon
function primaryOffenseStat(eq, gb) {
  const dt = weaponDamageType(eq);
  if (dt === "magic")  return gb.intelligence;
  if (dt === "ranged") return gb.dexterity;
  return gb.strength; // melee or none
}
function sc(v) { return v > 0 ? "#27ae60" : v < 0 ? "#e74c3c" : "#8a8090"; }

// ─── LOOT MODAL ───────────────────────────────────────────────────────────────
// ─── FLOOR LOOT MODAL ────────────────────────────────────────────────────────
// Shows after boss kill (3 items + gold) or defeat (partial items + gold)
function FloorLootModal({ loot, equipped, onAction, onDone }) {
  // loot = { items:[], gold:number, type:"boss"|"defeat", isFinal:bool, kills:number }
  const [decisions, setDecisions] = useState({}); // itemId -> "equip"|"keep"|"sell"
  const [expanded, setExpanded] = useState(null);
  if (!loot) return null;
  const { items, gold, type, isFinal, kills } = loot;
  const isBossWin = type === "boss";
  const bannerColor = isBossWin ? "#c9a84c" : "#e74c3c";
  const bannerIcon  = isFinal ? "🏆" : isBossWin ? "⚔️" : "💀";
  const bannerTitle = isFinal ? "DUNGEON CLEARED!" : isBossWin ? "FLOOR CLEARED!" : "DEFEAT";
  const allDecided  = items.length === 0 || items.every(i => decisions[i.id]);
  function decide(item, action) {
    setDecisions(d => ({...d, [item.id]: action}));
    onAction(item, action);
    if (expanded === item.id) setExpanded(null);
  }
  return (
    <div className="modal-overlay">
      <div style={{
        background:"var(--bg)", borderRadius:"16px 16px 0 0",
        border:`2px solid ${bannerColor}66`,
        width:"100%", maxHeight:"90vh", display:"flex", flexDirection:"column",
        overflow:"hidden",
      }}>
        {/* Header */}
        <div style={{background:`${bannerColor}18`, borderBottom:`1px solid ${bannerColor}44`,
          padding:"1rem 1.25rem", textAlign:"center", flexShrink:0}}>
          <div style={{fontSize:"2rem",marginBottom:".2rem"}}>{bannerIcon}</div>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:"1.2rem",fontWeight:900,color:bannerColor,letterSpacing:".08em"}}>
            {bannerTitle}
          </div>
          {type==="defeat" && kills > 0 && (
            <div style={{fontSize:".78rem",color:"var(--text2)",marginTop:".2rem"}}>
              You fell after {kills} kill{kills!==1?"s":""} — partial spoils recovered
            </div>
          )}
          {type==="defeat" && kills === 0 && (
            <div style={{fontSize:".78rem",color:"var(--text2)",marginTop:".2rem"}}>
              No kills — a small consolation
            </div>
          )}
        </div>
        {/* Gold row */}
        <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:".5rem",
          padding:".65rem 1.25rem", background:"#c9a84c11",
          borderBottom:"1px solid var(--border)", flexShrink:0}}>
          <span style={{fontSize:"1.4rem"}}>💰</span>
          <span style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontSize:"1.1rem",fontWeight:700}}>
            +{gold.toLocaleString()} Gold
          </span>
          <span style={{fontSize:".75rem",color:"var(--text2)"}}>(auto-collected)</span>
        </div>
        {/* Items list */}
        <div style={{overflowY:"auto", flex:1, padding:".75rem 1rem"}}>
          {items.length === 0 ? (
            <div style={{textAlign:"center",color:"var(--text2)",fontSize:".85rem",padding:"1rem",fontStyle:"italic"}}>
              No items recovered.
            </div>
          ) : (
            <div style={{display:"flex",flexDirection:"column",gap:".6rem"}}>
              {items.map((item, idx) => {
                const rc = RARITY_COLORS[item.rarity];
                const sv = sellValue(item);
                const dec = decisions[item.id];
                const isOpen = expanded === item.id;
                const currentEquipped = equipped[item.slot];
                // Stat comparison helpers
                const newDmg = item.dmg ?? null;
                const oldDmg = currentEquipped?.dmg ?? null;
                const statKeys = [...new Set([...Object.keys(item.stats||{}), ...Object.keys(currentEquipped?.stats||{})])];
                return (
                  <div key={item.id} style={{
                    background:"var(--surface)", border:`1px solid ${dec ? rc+"44" : rc+"88"}`,
                    borderRadius:10, overflow:"hidden", opacity: dec ? 0.7 : 1,
                  }}>
                    {/* Item header — tap to expand */}
                    <div style={{display:"flex",alignItems:"center",gap:".65rem",padding:".7rem .85rem",cursor:"pointer"}}
                      onClick={() => !dec && setExpanded(isOpen ? null : item.id)}>
                      <div style={{position:"relative",flexShrink:0}}>
                        <GearIcon name={item.name} size={44} rarity={item.rarity}/>
                        {idx === 0 && isBossWin && (
                          <div style={{position:"absolute",top:-4,right:-4,background:bannerColor,color:"#000",
                            fontSize:".5rem",fontWeight:900,borderRadius:4,padding:"1px 4px"}}>BOSS</div>
                        )}
                      </div>
                      <div style={{flex:1,minWidth:0}}>
                        <div style={{fontFamily:"'Cinzel',serif",fontSize:".92rem",fontWeight:700}}>{item.name}</div>
                        <div style={{display:"flex",gap:".3rem",flexWrap:"wrap",marginTop:".15rem"}}>
                          <span style={{fontSize:".68rem",color:rc,fontWeight:700}}>{item.rarity}</span>
                          <span style={{fontSize:".68rem",color:"var(--text2)"}}>· {SLOT_LABELS[item.slot]}</span>
                          {item.dmg != null && <span style={{fontSize:".68rem",color:"#e74c3c",fontWeight:700}}>· ⚔️{item.dmg}</span>}
                        </div>
                        {Object.entries(item.stats||{}).length > 0 && (
                          <div style={{display:"flex",gap:".25rem",flexWrap:"wrap",marginTop:".2rem"}}>
                            {Object.entries(item.stats).map(([k,v]) => {
                              const labels={hp:"HP",dodge:"Dodge",crit:"Crit",magicDmg:"Magic"};
                              const suf={dodge:"%",crit:"%"}[k]||"";
                              return <span key={k} style={{fontSize:".65rem",color:sc(v),fontWeight:700}}>+{v}{suf} {labels[k]||k}</span>;
                            })}
                          </div>
                        )}
                        {/* Equipped comparison — show when slot is occupied */}
                        {currentEquipped && (
                          <div style={{marginTop:".3rem",paddingTop:".3rem",borderTop:"1px solid var(--border)"}}>
                            <div style={{fontSize:".6rem",color:"var(--text2)",marginBottom:".2rem",fontStyle:"italic"}}>
                              vs. {currentEquipped.name} ({currentEquipped.rarity})
                            </div>
                            <div style={{display:"flex",gap:".3rem",flexWrap:"wrap"}}>
                              {/* Damage comparison */}
                              {(newDmg != null || oldDmg != null) && (() => {
                                const diff = (newDmg||0) - (oldDmg||0);
                                return (
                                  <span style={{fontSize:".65rem",fontWeight:700,
                                    color: diff > 0 ? "#27ae60" : diff < 0 ? "#e74c3c" : "var(--text2)"}}>
                                    {diff > 0 ? "▲" : diff < 0 ? "▼" : "="} ⚔️{diff > 0 ? "+"+diff : diff === 0 ? "same" : diff}
                                  </span>
                                );
                              })()}
                              {/* Stat comparisons */}
                              {statKeys.map(k => {
                                const nv = (item.stats||{})[k] || 0;
                                const ov = (currentEquipped.stats||{})[k] || 0;
                                const diff = nv - ov;
                                if (diff === 0 && nv === 0) return null;
                                const labels={hp:"HP",dodge:"Dodge",crit:"Crit",magicDmg:"Magic"};
                                const suf={dodge:"%",crit:"%"}[k]||"";
                                return (
                                  <span key={k} style={{fontSize:".65rem",fontWeight:700,
                                    color: diff > 0 ? "#27ae60" : diff < 0 ? "#e74c3c" : "var(--text2)"}}>
                                    {diff > 0 ? "▲" : diff < 0 ? "▼" : "="} {diff > 0 ? "+"+diff : diff}{suf} {labels[k]||k}
                                  </span>
                                );
                              })}
                              {/* No stats to compare */}
                              {newDmg == null && oldDmg == null && statKeys.length === 0 && (
                                <span style={{fontSize:".6rem",color:"var(--text2)"}}>Different stats</span>
                              )}
                            </div>
                          </div>
                        )}
                        {/* New slot — nothing equipped yet */}
                        {!currentEquipped && (
                          <div style={{fontSize:".62rem",color:"#27ae60",marginTop:".25rem",fontStyle:"italic"}}>
                            ✦ Empty slot
                          </div>
                        )}
                      </div>
                      {dec ? (
                        <span style={{fontSize:".75rem",color:dec==="sell"?"var(--gold)":dec==="equip"?"#27ae60":"#3498db",fontWeight:700,flexShrink:0}}>
                          {dec==="sell"?`💰 ${sv}g`:dec==="equip"?"⚔️ Equip":"🎒 Keep"}
                        </span>
                      ) : (
                        <span style={{fontSize:".8rem",color:"var(--text2)"}}>{isOpen?"▲":"▼"}</span>
                      )}
                    </div>
                    {/* Action buttons — only when expanded and not decided */}
                    {isOpen && !dec && (
                      <div style={{display:"flex",gap:".4rem",padding:".5rem .85rem .7rem",borderTop:"1px solid var(--border)"}}>
                        <button onClick={() => decide(item,"equip")} style={{flex:1,padding:".5rem",background:"#27ae6022",border:"1px solid #27ae6066",borderRadius:8,color:"#27ae60",fontFamily:"'Cinzel',serif",fontSize:".8rem",fontWeight:700,cursor:"pointer"}}>
                          ⚔️ {equipped[item.slot] ? "Swap" : "Equip"}
                        </button>
                        <button onClick={() => decide(item,"keep")} style={{flex:1,padding:".5rem",background:"#3498db22",border:"1px solid #3498db66",borderRadius:8,color:"#3498db",fontFamily:"'Cinzel',serif",fontSize:".8rem",fontWeight:700,cursor:"pointer"}}>
                          🎒 Keep
                        </button>
                        <button onClick={() => decide(item,"sell")} style={{flex:1,padding:".5rem",background:"#c9a84c22",border:"1px solid #c9a84c66",borderRadius:8,color:"var(--gold)",fontFamily:"'Cinzel',serif",fontSize:".8rem",fontWeight:700,cursor:"pointer"}}>
                          💰 {sv}g
                        </button>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          )}
        </div>
        {/* Done button */}
        <div style={{padding:".75rem 1rem",borderTop:"1px solid var(--border)",flexShrink:0}}>
          {!allDecided && (
            <div style={{fontSize:".75rem",color:"var(--text2)",textAlign:"center",marginBottom:".5rem"}}>
              Tap each item to decide what to do with it
            </div>
          )}
          <button onClick={onDone} style={{
            width:"100%", padding:".75rem",
            background: allDecided ? `linear-gradient(135deg,${bannerColor},${bannerColor}cc)` : "var(--surface2)",
            border:"none", borderRadius:10,
            color: allDecided ? "#000" : "var(--text2)",
            fontFamily:"'Cinzel',serif", fontSize:".95rem", fontWeight:700, cursor:"pointer",
          }}>
            {allDecided ? (isBossWin ? (isFinal ? "Claim & Continue →" : "Next Floor →") : "Continue →") : `Decide all items first (${Object.keys(decisions).length}/${items.length})`}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── ITEM DETAIL MODAL ────────────────────────────────────────────────────────
function ItemModal({ item, currentlyEquipped, fromInventory, onEquip, onSellFromInventory, onClose }) {
  if (!item) return null;
  const rc = RARITY_COLORS[item.rarity];
  const diffKeys = currentlyEquipped
    ? [...new Set([...Object.keys(item.stats), ...Object.keys(currentlyEquipped.stats)])]
    : [];
  const isEquipped = currentlyEquipped?.id === item.id;
  const dmgDiff = (item.dmg != null && currentlyEquipped?.dmg != null)
    ? item.dmg - currentlyEquipped.dmg : null;
  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="item-modal" style={{borderColor:rc}} onClick={e => e.stopPropagation()}>
        <div className="im-header" style={{borderBottomColor:rc+"55"}}>
          <GearIcon name={item.name} size={40} rarity={item.rarity}/>
          <div style={{flex:1}}>
            <div style={{fontFamily:"'Cinzel',serif",fontSize:"1.1rem"}}>{item.name}</div>
            <div style={{display:"flex",gap:".25rem",fontSize:".8rem",flexWrap:"wrap",color:"var(--text2)"}}>
              <span style={{color:rc}}>{item.rarity}</span>
              <span>·</span><span>{item.type}</span>
              <span>·</span><span>{SLOT_LABELS[item.slot]}</span>
            </div>
          </div>
          <button className="btn-x" onClick={onClose}>✕</button>
        </div>
        <p style={{color:"var(--text2)",fontSize:".9rem",fontStyle:"italic",marginBottom:"1rem"}}>{item.desc}</p>
        <div style={{background:"var(--surface2)",borderRadius:"8px",padding:".5rem .75rem",marginBottom:"1rem"}}>
          {item.dmg != null && (
            <div style={{display:"flex",justifyContent:"space-between",padding:".35rem 0",borderBottom:"1px solid var(--border)"}}>
              <span style={{color:"#e74c3c",fontWeight:700}}>
                ⚔️ {(item.dmgTypes||["melee"]).map(t=>t.charAt(0).toUpperCase()+t.slice(1)).join(" / ")} Damage
              </span>
              <span style={{color:"#e74c3c",fontWeight:900,fontSize:"1.05rem"}}>{item.dmg}</span>
            </div>
          )}
          {Object.entries(item.stats).map(([k,v]) => {
            const labels = { hp:"❤️ HP", dodge:"💨 Dodge %", crit:"⚡ Crit %", magicDmg:"✨ Magic Dmg" };
            const suffix = { dodge:"%", crit:"%" };
            return (
              <div key={k} style={{display:"flex",justifyContent:"space-between",padding:".35rem 0",borderBottom:"1px solid var(--border)"}}>
                <span>{labels[k] || k}</span>
                <span style={{color:sc(v),fontWeight:700}}>+{v}{suffix[k]||""}</span>
              </div>
            );
          })}
        </div>
        {currentlyEquipped && !isEquipped && (
          <div style={{background:"var(--surface2)",borderRadius:"8px",padding:".75rem",marginBottom:"1rem"}}>
            <div style={{fontSize:".75rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".05em",marginBottom:".4rem"}}>vs. Equipped</div>
            <div style={{border:`1px solid ${RARITY_COLORS[currentlyEquipped.rarity]}`,borderRadius:"6px",padding:".4rem .6rem",display:"flex",justifyContent:"space-between",marginBottom:".4rem"}}>
              <span>{currentlyEquipped.icon} {currentlyEquipped.name}</span>
              <span style={{color:RARITY_COLORS[currentlyEquipped.rarity],fontSize:".75rem"}}>{currentlyEquipped.rarity}</span>
            </div>
            <div style={{display:"flex",flexWrap:"wrap",gap:".4rem"}}>
              {dmgDiff !== null && (
                <span style={{fontSize:".8rem",fontWeight:600,color:sc(dmgDiff)}}>⚔️ dmg {dmgDiff > 0 ? `+${dmgDiff}` : dmgDiff}</span>
              )}
              {item.dmg != null && currentlyEquipped?.dmg == null && (
                <span style={{fontSize:".8rem",fontWeight:600,color:"#27ae60"}}>⚔️ dmg +{item.dmg}</span>
              )}
              {diffKeys.map(k => {
                const d = (item.stats[k]||0) - (currentlyEquipped.stats[k]||0);
                if (!d) return null;
                const labels = { hp:"HP", dodge:"Dodge%", crit:"Crit%", magicDmg:"Magic+" };
                const suf = {dodge:"%",crit:"%"}[k]||"";
                return <span key={k} style={{fontSize:".8rem",fontWeight:600,color:sc(d)}}>{labels[k]||k} {d > 0 ? `+${d}${suf}` : `${d}${suf}`}</span>;
              })}
            </div>
          </div>
        )}
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",background:"var(--surface2)",borderRadius:"8px",padding:".5rem .75rem",marginBottom:"1rem",fontSize:".85rem"}}>
          <span style={{color:"var(--text2)"}}>Sell Value</span>
          <span style={{color:"var(--gold)",fontWeight:700}}>{sellValue(item)} Gold</span>
        </div>
        {fromInventory && !isEquipped && (
          <button className="btn-equip-now" onClick={onEquip} style={{marginBottom:".5rem"}}>
            {currentlyEquipped ? "⚔️ Swap Equip" : "⚔️ Equip"}
          </button>
        )}
        {fromInventory && isEquipped && (
          <button onClick={() => { onSellFromInventory && onSellFromInventory("unequip"); }}
            style={{width:"100%",background:"linear-gradient(135deg,#1a2a3a,#0a1a2a)",border:"1px solid #2a4a6a",borderRadius:"var(--radius)",padding:".75rem",color:"#74b9ff",fontFamily:"'Cinzel',serif",fontSize:".9rem",cursor:"pointer",marginBottom:".5rem"}}>
            🛡️ Unequip
          </button>
        )}
        {fromInventory && !isEquipped && (
          <button onClick={onSellFromInventory}
            style={{width:"100%",background:"linear-gradient(135deg,#3a2800,#5a3d00)",border:"1px solid #7a5a00",borderRadius:"var(--radius)",padding:".75rem",color:"var(--gold)",fontFamily:"'Cinzel',serif",fontSize:".9rem",cursor:"pointer"}}>
            💰 Sell for {sellValue(item)} Gold
          </button>
        )}
      </div>
    </div>
  );
}

