const TIER_COLOR = { easy:"#27ae60", medium:"#f39c12", hard:"#e74c3c" };
const TIER_LABEL = { easy:"Easy", medium:"Medium", hard:"Hard" };

function generateDailyQuests(dateStr, character) {
  const seed = dateStr.split("-").reduce((a, b) => a * 100 + parseInt(b), 0);
  let x = seed || 12345;
  const rng = () => { x ^= x << 13; x ^= x >> 17; x ^= x << 5; return Math.abs(x) / 2147483647; };
  function pickN(pool, n) {
    const shuffled = [...pool].sort(() => rng() - 0.5);
    return shuffled.slice(0, Math.min(n, pool.length));
  }

  // ── Build workout quests from today's assigned program day ─────────────────
  const DAY_ABBR = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  const todayAbbr = DAY_ABBR[new Date().getDay()];
  const goal = character?.goal || "Build Muscle";
  const daysCount = character?.days === "Every" ? 7 : parseInt(character?.days) || 3;
  const isManualPlan = character?.planning === "manual";
  const customPlan = character?.customPlan || [];

  // For manual planners: use their custom plan if they've built one, otherwise generic quests
  let exercises = [];
  let focus = "Train Today";
  let todayHeavy = [];

  if (isManualPlan) {
    // Find today's custom day if it exists and has exercises
    const todayCustom = customPlan.find(d => d.day === todayAbbr && d.exercises?.length > 0);
    const anyCustom = customPlan.find(d => d.exercises?.length > 0);
    const activeDay = todayCustom || anyCustom;
    if (activeDay) {
      exercises = activeDay.exercises || [];
      focus = activeDay.focus || "Train Today";
    }
  } else {
    const plan = (WORKOUT_PLANS[goal] || WORKOUT_PLANS["Build Muscle"]).slice(0, daysCount);
    const todayDay = plan.find(d => d.day === todayAbbr) || plan[0];
    exercises = todayDay.exercises || [];
    focus = todayDay.focus || "Today's Workout";
  }

  const HEAVY = new Set(["Deadlifts","Squats","Bench Press","Overhead Press","Barbell Row",
    "Pull-ups","Romanian DL","Leg Press","Hip Thrust","Pendlay Row","Bulgarian Split"]);
  todayHeavy = exercises.filter(e => HEAVY.has(e));

  // Q1 (Easy) — complete today's session
  const q1 = { id:"wdq_session", cat:"fitness", icon:"🏋️", tier:"easy",
    title: exercises.length > 0 ? focus : "Train Today",
    desc: exercises.length > 0
      ? `Complete today's workout: ${focus}.`
      : "Complete any workout session.",
    xp:250, gold:25, type:"workout" };

  // Q2 (Easy) — steps or time, alternates daily
  const q2 = rng() > 0.5
    ? { id:"wdq_steps", cat:"fitness", icon:"👟", tier:"easy",
        title:"Walk Today", desc:"Log 5,000 steps today.",
        xp:200, gold:20, type:"steps", target:5000 }
    : { id:"wdq_time", cat:"fitness", icon:"⏱️", tier:"easy",
        title:"Committed", desc:"Complete a session over 10 minutes.",
        xp:200, gold:20, type:"longSession" };

  // Q3 (Medium) — sets volume based on plan length
  const targetSets = Math.max(6, exercises.length * 2);
  const q3 = { id:"wdq_sets", cat:"fitness", icon:"💪", tier:"medium",
    title:"Volume Work",
    desc:`Log ${targetSets} or more sets in today's session.`,
    xp:350, gold:35, type:"sets", target:targetSets };

  // Q4 (Medium) — specific exercise anchor from the plan
  const anchor = todayHeavy.length > 0
    ? todayHeavy[Math.floor(rng() * todayHeavy.length)]
    : exercises[Math.floor(rng() * exercises.length)];
  const q4 = anchor
    ? { id:"wdq_exercise", cat:"fitness", icon:"🎯", tier:"medium",
        title:`${anchor} Focus`,
        desc:`Log 3 or more sets of ${anchor}.`,
        xp:350, gold:35, type:"exercise", exercise:anchor, target:3 }
    : { id:"wdq_heavy", cat:"fitness", icon:"🦴", tier:"medium",
        title:"Move the Iron",
        desc:"Log any heavy compound lift.",
        xp:300, gold:30, type:"heavy" };

  // Q5 (Hard) — big challenge from the plan
  const hardTarget = targetSets + 4;
  const q5 = todayHeavy.length >= 2
    ? { id:"wdq_heavymulti", cat:"fitness", icon:"🔱", tier:"hard",
        title:"Iron Session",
        desc:`Hit ${Math.min(todayHeavy.length, 3)} heavy lifts: ${todayHeavy.slice(0, 3).join(", ")}.`,
        xp:550, gold:55, type:"heavyCount", target:Math.min(todayHeavy.length, 3) }
    : { id:"wdq_maxvolume", cat:"fitness", icon:"⚡", tier:"hard",
        title:"Max Effort",
        desc:`Log ${hardTarget} or more sets in today's session.`,
        xp:550, gold:55, type:"sets", target:hardTarget };

  const workout = [q1, q2, q3, q4, q5];

  // ── Dungeon quests — exactly 5: 2 easy + 2 medium + 1 hard ────────────────
  const dEasy   = pickN(DUNGEON_QUEST_POOL.easy,   2).map(q => ({...q, tier:"easy"}));
  const dMed    = pickN(DUNGEON_QUEST_POOL.medium,  2).map(q => ({...q, tier:"medium"}));
  const dHard   = pickN(DUNGEON_QUEST_POOL.hard,    1).map(q => ({...q, tier:"hard"}));
  const dungeon = [...dEasy, ...dMed, ...dHard];

  return { workout, dungeon };
}

