const ENEMY_SPRITES = {
  "Armored_Goblin": "data:image/png;base64,",
  "Axe_Goblin": "data:image/png;base64,",
  "Bat": "data:image/png;base64,",
  "Demon_BullMan": "data:image/png;base64,",
  "Flame_Sprite": "data:image/png;base64,",
  "Gargoyle": "data:image/png;base64,",
  "Human_Gargoyle": "data:image/png;base64,",
  "Kraken": "data:image/png;base64,",
  "Magma_Golem": "data:image/png;base64,",
  "Orge_Brute": "data:image/png;base64,",
  "Rat": "data:image/png;base64,",
  "Recruit": "data:image/png;base64,",
  "Slime": "data:image/png;base64,",
  "Snow_Owl": "data:image/png;base64,",
  "Sprite-0027": "data:image/png;base64,",
  "Undead_Warlock": "data:image/png;base64,",
  "Warlock_Recruit": "data:image/png;base64,",
  "goblin": "data:image/png;base64,",
  "skeleton": "data:image/png;base64,",
};

function getEnemySprite(enemyName) {
  const n = enemyName.toLowerCase();
  if (n.includes("goblin") && n.includes("armor"))  return ENEMY_SPRITES["Armored_Goblin"];
  if (n.includes("goblin") && n.includes("axe"))    return ENEMY_SPRITES["Axe_Goblin"];
  if (n.includes("goblin"))                         return ENEMY_SPRITES["goblin"];
  if (n.includes("bat") || n.includes("cinder bat"))return ENEMY_SPRITES["Bat"];
  if (n.includes("bull") || n.includes("pit fiend") || n.includes("abyssal imp") || n.includes("inferno")) return ENEMY_SPRITES["Demon_BullMan"];
  if (n.includes("flame") || n.includes("fire imp") || n.includes("ember sprite") || n.includes("blaze")) return ENEMY_SPRITES["Flame_Sprite"];
  if (n.includes("human gargoyle") || n.includes("death knight") || n.includes("chaos knight") || n.includes("cursed knight") || n.includes("bone warrior")) return ENEMY_SPRITES["Human_Gargoyle"];
  if (n.includes("gargoyle"))                       return ENEMY_SPRITES["Gargoyle"];
  if (n.includes("kraken") || n.includes("mycelium") || n.includes("spore") || n.includes("fungus") || n.includes("fungal") || n.includes("plague beast") || n.includes("rot")) return ENEMY_SPRITES["Kraken"];
  if (n.includes("magma") || n.includes("lava golem") || n.includes("golem") || n.includes("rock troll") || n.includes("stone")) return ENEMY_SPRITES["Magma_Golem"];
  if (n.includes("ogre") || n.includes("troll") || n.includes("brute") || n.includes("titan") || n.includes("giant") || n.includes("war ogre")) return ENEMY_SPRITES["Orge_Brute"];
  if (n.includes("rat") || n.includes("sewer rat") || n.includes("grave rat") || n.includes("plague rat") || n.includes("mud crawler") || n.includes("cave spider") || n.includes("crawler")) return ENEMY_SPRITES["Rat"];
  if (n.includes("recruit") && !n.includes("warlock")) return ENEMY_SPRITES["Recruit"];
  if (n.includes("skeleton") || n.includes("bone archer") || n.includes("tomb archer") || n.includes("armored skeleton") || n.includes("ancient skeleton")) return ENEMY_SPRITES["skeleton"];
  if (n.includes("slime") || n.includes("slug") || n.includes("spore puff") || n.includes("rot grub") || n.includes("toad") || n.includes("mud toad")) return ENEMY_SPRITES["Slime"];
  if (n.includes("snow owl") || n.includes("owl") || n.includes("frost") || n.includes("chill")) return ENEMY_SPRITES["Snow_Owl"];
  if (n.includes("undead") || n.includes("lich") || n.includes("mummy") || n.includes("wraith") || n.includes("wight") || n.includes("banshee") || n.includes("zombie") || n.includes("poltergeist") || n.includes("ghost") || n.includes("specter")) return ENEMY_SPRITES["Undead_Warlock"];
  if (n.includes("warlock") || n.includes("witch") || n.includes("shaman") || n.includes("cursed priest") || n.includes("hex") || n.includes("dark shaman") || n.includes("grave witch")) return ENEMY_SPRITES["Warlock_Recruit"];
  if (n.includes("shadow") || n.includes("void") || n.includes("chaos") || n.includes("soul") || n.includes("abyssal") || n.includes("corrupted") || n.includes("ancient")) return ENEMY_SPRITES["Sprite-0027"];
  if (n.includes("orc") || n.includes("hobgoblin") || n.includes("war boar") || n.includes("siege")) return ENEMY_SPRITES["Orge_Brute"];
  return null;
}
function EnemySprite({ enemy, isHit }) {
  const boss = enemy.isBoss || enemy.isFinalBoss;
  const size = boss ? 96 : 72;
  const col = { "🐸":"#27ae60","👹":"#e74c3c","🌿":"#27ae60","🌑":"#2c3e50","🔥":"#e67e22","💎":"#3498db","👻":"#9b59b6","📚":"#8B4513","⚔️":"#95a5a6","👑":"#f39c12","😈":"#c0392b","🐉":"#27ae60","💀":"#7f8c8d","🧙":"#8e44ad","🪨":"#7f8c8d","🦇":"#2c3e50" }[enemy.icon] || "#e74c3c";
  const spriteUri = getEnemySprite(enemy.name);
  if (spriteUri) {
    return (
      <div style={{width:size,height:size,display:"flex",alignItems:"flex-end",justifyContent:"center",
        filter:isHit?"brightness(3) saturate(0)":"none",transition:"filter .1s"}}>
        <img src={spriteUri} alt={enemy.name}
          style={{maxWidth:size,maxHeight:size,objectFit:"contain",imageRendering:"pixelated"}}/>
      </div>
    );
  }
  return (
    <div style={{width:size,height:size,borderRadius:8,background:col+"33",border:`2px solid ${col}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:boss?"2.5rem":"1.8rem",filter:isHit?"brightness(3) saturate(0)":"none",transition:"filter .1s"}}>
      {enemy.icon}
    </div>
  );
}




// ─── DUNGEON TAB ──────────────────────────────────────────────────────────────
// Each dungeon has 10 floors (mkFloor). Each floor has 5 enemies + 1 floor boss.
// Floor 10's boss clears the dungeon. Combat is brutal — use gear and potions.
function DungeonTab({ character, onItemKept, onItemSold, onItemEquipped, onDungeonClear, onQuestProgress, onUsedPotion }) {
  const level = xpToLevel(character.xp);
  const clearedDungeons = character.clearedDungeons || [];
  // screen: "list" | "floors" | "combat"
  const [screen,  setScreen]  = useState("list");
  const [activeDungeonId, setActiveDungeonId] = useState(null);
  const [activeFloorNum,  setActiveFloorNum]  = useState(null); // 1-10
  const [combat,  setCombat]  = useState(null);
  const [toast,   setToast]   = useState(null);
  const [floats,  setFloats]  = useState([]);
  const [hitFlash,setHitFlash]= useState(null);
  const [paused,  setPaused]  = useState(false);
  const [tick,    setTick]    = useState(0);
  const [waveAnnounce, setWaveAnnounce] = useState(null);
  const [heroAnim,  setHeroAnim]  = useState(null); // "lunge" | "knockback"
  const [enemyAnim, setEnemyAnim] = useState(null); // "knockback" | "lunge" | "death"
  const autoRef               = useRef(null);
  const abilityRef            = useRef(null); // for volley rapid-fire
  const waveAnnounceRef       = useRef(null);

  // Scroll to top when navigating between dungeon list / floors / combat
  useEffect(() => { scrollTabTop(); }, [screen, activeDungeonId]);

  // Tick every second for cooldown display
  useEffect(() => {
    const id = setInterval(() => setTick(t => t+1), 1000);
    return () => clearInterval(id);
  }, []);

  // Auto-combat timer — must be declared at top level before any returns
  useEffect(() => {
    if (!combat || combat.defeat || combat.pendingLoot || combat.bossCleared || paused || waveAnnounce) {
      clearInterval(autoRef.current);
      return;
    }
    clearInterval(autoRef.current);
    const ab = combat.abilityActive;
    const speed = (ab?.type === "volley" && ab.hitsLeft > 0) ? 300
                : (ab?.type === "adrenaline" && Date.now() < ab.expiresAt) ? 600
                : 1200;
    autoRef.current = setInterval(() => { attackWithFX(); }, speed);
    return () => clearInterval(autoRef.current);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [combat?.enemyIdx, combat?.pHP, combat?.mHP, combat?.defeat, combat?.pendingLoot, combat?.bossCleared, combat?.abilityActive, paused, waveAnnounce]);

  // Wave announcement — show center-screen label between enemies
  useEffect(() => {
    setEnemyAnim(null); // clear death anim on new enemy
    if (!combat || combat.defeat || combat.pendingLoot || combat.bossCleared) return;
    const idx    = combat.enemyIdx;
    const total  = combat.enemies?.length || 6;
    const isLast = idx === total - 1;
    const pct    = (idx + 1) / total;
    const label  = isLast ? "⚠️ Final Wave" : `Wave ${idx + 1}`;
    const color  = isLast ? "#e74c3c" : pct <= 0.33 ? "#27ae60" : pct <= 0.66 ? "#f39c12" : "#e67e22";
    setWaveAnnounce({ label, color });
    clearTimeout(waveAnnounceRef.current);
    waveAnnounceRef.current = setTimeout(() => setWaveAnnounce(null), 1500);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [combat?.enemyIdx]);

  const unlockedUpTo = DUNGEON_UNLOCK_XP.reduce((acc, req, i) => character.xp >= req ? i : acc, 0);

  // Track per-dungeon floor clears: { dungeonId: [floorNum,...] }
  const floorClears = character.floorClears || {};

  function calcMaxHP() {
    const gc  = gearCombatStats(character.equipped);
    const _al = character.allocatedStats || {};
    const con = 8 + (character.cls?.statBonuses||[]).filter(b=>b.stat==="constitution").reduce((s,b)=>s+b.amt,0)
               + Math.floor(level*0.9) + (_al.constitution||0);
    return 50 + con * 8 + level * 10 + gc.hp;
  }


  function openDungeon(id, weeklyBossEnemy) {
    if (id === -1 && weeklyBossEnemy) {
      const hp = calcMaxHP();
      setActiveDungeonId(-1);
      setCombat({
        dungeonId: -1,
        enemies: [weeklyBossEnemy],
        enemyIdx: 0,
        pHP: hp, pMaxHP: hp,
        mHP: weeklyBossEnemy.hp, mMaxHP: weeklyBossEnemy.hp,
        gold: weeklyBossEnemy.reward?.gold || 500,
        defeat: false, pendingLoot: null, bossCleared: false,
        log: [`${weeklyBossEnemy.icon} ${weeklyBossEnemy.name} appears!`],
        floorNum: 0,
        statusEffects: [],
      });
      setScreen("combat");
    } else {
      setActiveDungeonId(id);
      setScreen("floors");
    }
  }

  function enterFloor(dungeonId, floorNum) {
    const dungeon = DUNGEONS[dungeonId] || DUNGEONS[DUNGEONS.length - 1];
    if (!dungeon) return;
    const floor = dungeon.floors[floorNum - 1];
    if (!floor) return;
    const fe = floor.enemies[0];
    const hp = calcMaxHP();
    setActiveFloorNum(floorNum);
    setCombat({
      dungeonId, floorNum,
      enemyIdx: 0,
      enemies: [...floor.enemies, floor.boss],
      pHP: hp, pHPMax: hp,
      mHP: fe.hp, mHPMax: fe.hp,
      log: [`Floor ${floorNum}: ${dungeon.name}`, `${fe.icon} ${fe.name} stands before you!`],
      defeat: false, pendingLoot: null,
      potionUsed: false,
      statusEffects: [],
    });
    setScreen("combat");
    onQuestProgress?.("enter");
  }

  function exitCombat()  { setCombat(null); setScreen("floors"); }
  function exitToList()  { setCombat(null); setActiveDungeonId(null); setScreen("list"); }

  function rematchFloor() {
    const { dungeonId, floorNum } = combat;
    const dungeon = DUNGEONS[dungeonId] || DUNGEONS[DUNGEONS.length - 1];
    const floor   = dungeon.floors[floorNum - 1];
    const fe = floor.enemies[0];
    const hp = calcMaxHP();
    setCombat({
      dungeonId, floorNum,
      enemyIdx: 0,
      enemies: [...floor.enemies, floor.boss],
      pHP: hp, pHPMax: hp,
      mHP: fe.hp, mHPMax: fe.hp,
      log: [`Rematch — Floor ${floorNum}: ${dungeon.name}`, `${fe.icon} ${fe.name} awaits!`],
      defeat: false, pendingLoot: null, bossCleared: null, potionUsed: false, floorLoot: [], killCount: 0,
    });
  }
  function showToast(msg){ setToast(msg); setTimeout(() => setToast(null), 2200); }

  // attack() replaced by attackWithFX() inside the auto-battler combat section

  function usePotion(type) {
    const pt = POTION_TYPES[type];
    if (!pt) return;
    const count = (character.potions||{})[type] || 0;
    if (count <= 0) return;
    // Bleed status blocks healing
    if ((combat?.statusEffects||[]).some(s => s.id === "bleed")) {
      showToast("🩸 Bleed active — potions blocked!");
      return;
    }
    onUsedPotion(type);
    setCombat(c => {
      if (!c) return c;
      const max = calcMaxHP();
      const heal = pt.heal >= 9999 ? max : pt.heal;
      return {...c, pHP:Math.min(max, c.pHP + heal), potionUsed: true,
        log:[`${pt.icon} ${pt.name}! +${pt.heal >= 9999 ? "FULL":heal} HP`,...(c.log||[])].slice(0,8)};
    });
    onQuestProgress?.("potion");
  }

  // After loot is resolved, auto-advance based on bossCleared flag
  function advanceAfterBoss(combatSnap) {
    if (!combatSnap) return;
    const { bossCleared, dungeonId, floorNum, pHP } = combatSnap;
    if (!bossCleared) return;

    if (bossCleared === "weekly") {
      // Weekly boss beaten — save status and return to list
      setCombat(null);
      setActiveDungeonId(null);
      setScreen("list");
      showToast("⚔️ Weekly Boss Defeated! Claim your spoils!");
      return;
    }

    if (bossCleared === "dungeon") {
      const nextDungeonId = dungeonId + 1;
      if (nextDungeonId < DUNGEONS.length) {
        const nextDungeon = DUNGEONS[nextDungeonId];
        const fe = nextDungeon.floors[0].enemies[0];
        const hp = calcMaxHP();
        setActiveDungeonId(nextDungeonId);
        setCombat({
          dungeonId: nextDungeonId, floorNum: 1,
          enemyIdx: 0,
          enemies: [...nextDungeon.floors[0].enemies, nextDungeon.floors[0].boss],
          pHP: hp, pHPMax: hp,
          mHP: fe.hp, mHPMax: fe.hp,
          log: [`Advancing to ${nextDungeon.name}!`, `Floor 1: ${fe.icon} ${fe.name} awaits!`],
          defeat: false, pendingLoot: null, bossCleared: null,
          statusEffects: [],
        });
        setScreen("combat");
      } else {
        setCombat(null);
        setActiveDungeonId(null);
        setScreen("list");
        showToast("All dungeons conquered!");
      }
      return;
    }

    if (bossCleared === "floor") {
      const nextFloorNum = floorNum + 1;
      const dungeon = DUNGEONS[dungeonId] || DUNGEONS[DUNGEONS.length - 1];
      if (nextFloorNum <= dungeon.floors.length) {
        const nextFloor = dungeon.floors[nextFloorNum - 1];
        const fe = nextFloor.enemies[0];
        const hp = calcMaxHP();
        setCombat({
          dungeonId, floorNum: nextFloorNum,
          enemyIdx: 0,
          enemies: [...nextFloor.enemies, nextFloor.boss],
          pHP: hp, pHPMax: hp,
          mHP: fe.hp, mHPMax: fe.hp,
          log: [`Floor ${nextFloorNum}: ${dungeon.name}`, `${fe.icon} ${fe.name} stands before you!`],
          defeat: false, pendingLoot: null, bossCleared: null,
          statusEffects: [],
        });
      } else {
        setCombat(null);
        setScreen("floors");
      }
    }
  }

  function handleLootAction(item, action) {
    if (action === "equip") { onItemEquipped(item); showToast("Equipped!"); }
    else if (action === "keep") { onItemKept(item); showToast("Added to inventory!"); }
    else { onItemSold(sellValue(item)); showToast(`+${sellValue(item)} Gold`); }
    // Don't clear pendingLoot here — modal stays open until all items decided
  }

  // ── DUNGEON LIST ──────────────────────────────────────────────────────────
  if (screen === "list") {
    return (
    <div>
      <h2 className="tab-title">Dungeons</h2>
      <WorldEventBanner/>
      {/* ── BOSS OF THE WEEK ── */}
      {(() => {
        const bLevel = xpToLevel(character.xp);
        const boss   = getWeekBoss(bLevel);
        const weekKey = getWeekKey();
        const botw    = character.bossOfTheWeek || {};
        const beaten  = botw.weekKey === weekKey && botw.beaten;
        const rc      = boss?.color || "#c9a84c";
        const weeklyXP = getPlayerWeeklyXP(character);
        const pct     = Math.min(100, (weeklyXP / boss.xpReq) * 100);
        if (!boss) return null;
        return (
          <div style={{background:"var(--surface)",border:`2px solid ${rc}66`,borderRadius:14,padding:"1rem",marginBottom:"1rem"}}>
            <div style={{display:"flex",alignItems:"center",gap:".75rem",marginBottom:".75rem"}}>
              <div style={{width:52,height:52,borderRadius:12,flexShrink:0,background:`${rc}22`,border:`2px solid ${rc}66`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.8rem"}}>{boss.icon}</div>
              <div style={{flex:1}}>
                <div style={{fontSize:".68rem",color:rc,fontWeight:700,textTransform:"uppercase",letterSpacing:".05em"}}>Boss of the Week</div>
                <div style={{fontFamily:"'Cinzel',serif",fontSize:"1rem",fontWeight:700,color:"var(--text)"}}>{boss.name}</div>
                <div style={{fontSize:".72rem",color:"var(--text2)"}}>{boss.theme} · {boss.hp.toLocaleString()} HP</div>
              </div>
              {beaten && <span style={{fontSize:".62rem",color:"#27ae60",fontWeight:700,background:"#27ae6022",border:"1px solid #27ae6044",borderRadius:10,padding:"2px 8px"}}>✓ Defeated</span>}
            </div>
            <div style={{display:"flex",gap:".4rem",marginBottom:".75rem"}}>
              {[{icon:"💰",label:`${boss.reward.gold}g`},{icon:"🎁",label:`${boss.reward.lootRarity}`},{icon:"⚡",label:`+${Math.round(boss.xpReq*0.5)} XP`}].map(r=>(
                <div key={r.label} style={{flex:1,background:"var(--surface2)",border:"1px solid var(--border)",borderRadius:8,padding:".3rem .4rem",textAlign:"center"}}>
                  <div style={{fontSize:".9rem"}}>{r.icon}</div>
                  <div style={{fontSize:".62rem",color:"var(--text2)",fontWeight:600}}>{r.label}</div>
                </div>
              ))}
            </div>
            <div style={{marginBottom:".75rem"}}>
              <div style={{display:"flex",justifyContent:"space-between",fontSize:".68rem",color:"var(--text2)",marginBottom:".2rem"}}>
                <span>Weekly training</span>
                <span style={{color:rc,fontWeight:700}}>{weeklyXP.toLocaleString()} / {boss.xpReq.toLocaleString()} XP</span>
              </div>
              <div style={{height:5,background:"var(--surface2)",borderRadius:3,overflow:"hidden"}}>
                <div style={{height:"100%",width:`${pct}%`,background:rc,borderRadius:3,transition:"width .4s"}}/>
              </div>
            </div>
            {beaten ? (
              <div style={{textAlign:"center",color:"#27ae60",fontSize:".85rem",fontStyle:"italic",padding:".4rem 0"}}>⚔️ Vanquished — return next Monday</div>
            ) : (
              <button
                onClick={() => {
                  const enemy = { name:boss.name, icon:boss.icon, hp:boss.hp, atk:boss.atk, isBoss:true, isFinalBoss:false, isWeeklyBoss:true, reward:boss.reward };
                  openDungeon(-1, enemy);
                }}
                style={{
                  width:"100%", padding:".85rem",
                  background:`linear-gradient(135deg,${rc},${rc}bb)`,
                  border:"none", borderRadius:10, color:"#000",
                  fontFamily:"'Cinzel',serif", fontSize:"1rem", fontWeight:700, cursor:"pointer",
                  touchAction:"manipulation",
                }}
              >
                ⚔️ Fight {boss.name}
              </button>
            )}
          </div>
        );
      })()}
      <p style={{color:"var(--text2)",fontSize:".85rem",marginBottom:"1rem"}}>
        Each dungeon has 10 floors. Earn Workout XP to unlock harder dungeons.
      </p>
      <div style={{display:"flex",flexDirection:"column",gap:".75rem"}}>
        {DUNGEONS.map((d, i) => {
          const unlocked = i <= unlockedUpTo;
          const cleared  = clearedDungeons.includes(i);
          const myFloors = floorClears[i] || [];
          const floorsCleared = myFloors.length;
          return (
            (() => {
              const tier = i; // 0-9
              const dangerLabel = ["Beginner","Novice","Apprentice","Journeyman","Adept","Veteran","Expert","Master","Grandmaster","Legendary"][tier] || "";
              const dangerColor = tier <= 2 ? "#27ae60" : tier <= 4 ? "#f39c12" : tier <= 6 ? "#e74c3c" : tier <= 8 ? "#8e44ad" : "#c9a84c";
              const skullCount  = tier <= 1 ? 0 : tier <= 3 ? 1 : tier <= 5 ? 2 : tier <= 7 ? 3 : 4;
              const skulls      = "💀".repeat(skullCount);
              const cardBg      = unlocked
                ? tier >= 8 ? `linear-gradient(135deg, #1a0a00, #2a1500)` : tier >= 6 ? `linear-gradient(135deg, #0d001a, #1a0028)` : "var(--surface)"
                : "var(--surface)";
              const borderColor = unlocked ? (tier >= 8 ? "#c9a84c55" : tier >= 6 ? "#8e44ad44" : d.color+"33") : "var(--border)";
              const noStamina   = false;
              return (
                <div key={d.id}
                  className={`dungeon-card ${unlocked?"":"locked"} ${cleared?"cleared":""}`}
                  style={{"--dc": unlocked ? d.color : "#333", background:cardBg, borderColor:cleared?"#27ae6033":borderColor, opacity: noStamina ? 0.55 : 1}}
                  onClick={() => unlocked && openDungeon(i)}>
                  <div className="dc-left">
                    <div className="dc-num" style={{color:unlocked?d.color:"#555",fontSize: tier>=7?"1.4rem":"1.1rem"}}>{i+1}</div>
                    <div className="dc-theme" style={{fontSize: tier>=7?"1.8rem":"1.4rem"}}>{unlocked ? d.theme : "🔒"}</div>
                  </div>
                  <div style={{flex:1}}>
                    <div style={{display:"flex",alignItems:"center",gap:".4rem",marginBottom:".1rem"}}>
                      <span style={{fontFamily:"'Cinzel',serif",fontSize: tier>=7?"1.05rem":"1rem",color:unlocked?d.color:"#555"}}>{d.name}</span>
                      {unlocked && skullCount>0 && <span style={{fontSize:".7rem"}}>{skulls}</span>}
                      {noStamina && <span style={{fontSize:".65rem",color:"#e74c3c",fontWeight:700}}>⚡ No stamina</span>}
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:".4rem",marginBottom:".15rem"}}>
                      <span style={{fontSize:".65rem",color:dangerColor,background:dangerColor+"22",padding:"1px 6px",borderRadius:6,fontWeight:700,border:`1px solid ${dangerColor}44`}}>{dangerLabel}</span>
                      <span style={{fontSize:".7rem",color:"var(--text2)"}}>Lv.{d.minLevel}+</span>
                    </div>
                    {unlocked
                      ? <div style={{fontSize:".76rem",color:"var(--text2)",fontStyle:"italic"}}>{d.desc}</div>
                      : <div style={{fontSize:".75rem",color:"#555"}}>Requires {DUNGEON_UNLOCK_XP[i].toLocaleString()} XP</div>}
                    {unlocked && floorsCleared > 0 && (
                      <div style={{marginTop:".3rem",display:"flex",gap:"2px",alignItems:"center"}}>
                        {Array.from({length:10}).map((_,fi)=>(
                          <div key={fi} style={{flex:1,height:5,borderRadius:2,
                            background:fi<floorsCleared?d.color:"var(--border)",
                            opacity:fi<floorsCleared?1:0.4,transition:"background .3s"}}/>
                        ))}
                        <span style={{fontSize:".65rem",color:"var(--text2)",marginLeft:4}}>{floorsCleared}/10</span>
                      </div>
                    )}
                  </div>
                  <div style={{display:"flex",flexDirection:"column",alignItems:"flex-end",gap:".3rem"}}>
                    {cleared && <span className="cleared-badge">✓ Cleared</span>}
                    {unlocked && !cleared && (
                      <span className="enter-badge" style={{background:tier>=7?dangerColor+"33":undefined,borderColor:tier>=7?dangerColor:undefined,color:tier>=7?dangerColor:undefined}}>
                        {floorsCleared > 0 ? `F${floorsCleared+1}` : "Enter"}
                      </span>
                    )}
                  </div>
                </div>
              );
            })()
          );
        })}
      </div>
      <div style={{marginTop:"1.25rem",background:"var(--surface)",border:"1px solid var(--border)",borderRadius:"var(--radius)",padding:".75rem 1rem"}}>
        <div style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontSize:".85rem",marginBottom:".5rem"}}>Progress</div>
        <div style={{fontSize:".85rem",color:"var(--text2)"}}>Workout XP: <span style={{color:"var(--gold)",fontWeight:600}}>{character.xp.toLocaleString()}</span></div>
        <div style={{fontSize:".85rem",color:"var(--text2)",marginTop:".25rem"}}>Dungeons Cleared: <span style={{color:"var(--green)",fontWeight:600}}>{clearedDungeons.length}/10</span></div>
      </div>
    </div>
  );
  }

  // ── FLOOR SELECT ──────────────────────────────────────────────────────────
  if (screen === "floors") {
    const dungeon = DUNGEONS[activeDungeonId] || DUNGEONS[DUNGEONS.length - 1];
    if (!dungeon) { setScreen("list"); return null; }
    const myFloors = floorClears[activeDungeonId] || [];
    const nextFloor = myFloors.length + 1;
    return (
      <div>
        <div className="dungeon-header">
          <button className="btn-back" onClick={exitToList}>Back</button>
          <div style={{flex:1,textAlign:"center"}}>
            <div style={{fontFamily:"'Cinzel',serif",color:dungeon.color,fontSize:"1.1rem"}}>{dungeon.theme} {dungeon.name}</div>
            <div style={{fontSize:".75rem",color:"var(--text2)"}}>
              {myFloors.length}/10 floors cleared
            </div>
          </div>
        </div>
        <p style={{fontSize:".82rem",color:"var(--text2)",marginBottom:"1rem",fontStyle:"italic"}}>{dungeon.desc}</p>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:".6rem",marginBottom:"1rem"}}>
          {dungeon.floors.map((floor, fi) => {
            const floorNum    = fi + 1;
            const isCleared   = myFloors.includes(floorNum);
            const isLocked    = floorNum > nextFloor;
            const isCurrent   = floorNum === nextFloor;
            const isFinalFloor= floorNum === 10;
            return (
              <div key={floorNum}
                className={`floor-select-card ${isCleared?"cleared":""} ${isLocked?"locked":""} ${isCurrent?"current":""}`}
                style={{"--fc": isFinalFloor ? "#e74c3c" : dungeon.color}}
                onClick={() => !isLocked && enterFloor(activeDungeonId, floorNum)}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:".3rem"}}>
                  <span style={{fontFamily:"'Cinzel',serif",fontSize:".8rem",color:isLocked?"#555":isFinalFloor?"var(--red)":dungeon.color}}>
                    Floor {floorNum}{isFinalFloor?" ★":""}
                  </span>
                  {isCleared && <span style={{color:"var(--green)",fontSize:".75rem"}}>✓</span>}
                  {isCurrent && <span style={{color:"var(--gold)",fontSize:".7rem"}}>▶</span>}
                  {isLocked  && <span style={{color:"#555",fontSize:".8rem"}}>🔒</span>}
                </div>
                <div style={{fontSize:"1.4rem",margin:".2rem 0"}}>{floor.boss.icon}</div>
                <div style={{fontSize:".7rem",color:isLocked?"#555":"var(--text2)",lineHeight:1.3}}>{floor.boss.name}</div>
                <div style={{fontSize:".68rem",color:"#555",marginTop:".2rem"}}>
                  {floor.enemies.length + 1} enemies · Boss HP: {floor.boss.hp.toLocaleString()}
                </div>
              </div>
            );
          })}
        </div>
        <div style={{background:"var(--surface2)",border:"1px solid var(--border)",borderRadius:"var(--radius)",padding:".75rem",fontSize:".82rem",color:"var(--text2)"}}>
          <strong style={{color:"var(--gold)"}}>How it works:</strong> Clear floors in order.
          Each floor has 5 enemies then a floor boss. Defeat all 10 floors to conquer the dungeon.
          You can replay cleared floors for loot.
        </div>
      </div>
    );
  }

  // ── COMBAT (Auto-battler) ──────────────────────────────────────────────────


  const dungeon     = DUNGEONS[combat.dungeonId] || DUNGEONS[DUNGEONS.length - 1];
  const enemy       = combat.enemies[combat.enemyIdx];
  const pHPMax      = combat.pHPMax || calcMaxHP();
  const totalWaves  = combat.enemies.length;
  const waveNum     = combat.enemyIdx + 1;
  const isBoss      = enemy.isBoss || enemy.isFinalBoss;

  // Dungeon background themes — painterly layered style
  const BG_THEMES = {
    0:{ skyGrad:"linear-gradient(180deg,#5ec8f2 0%,#a8ddf5 40%,#f5c97a 75%,#e8a44a 100%)",
        midGrad:"linear-gradient(180deg,#c8883a,#a06020)",
        groundGrad:"linear-gradient(180deg,#c1592a 0%,#8b3a18 100%)",groundEdge:"#7a2d10",
        clouds:[{y:18,x:"8%",w:90,h:28},{y:30,x:"55%",w:70,h:20},{y:10,x:"70%",w:50,h:16}],
        bgDecor:[{x:"8%",icon:"🌴",size:"48px"},{x:"28%",icon:"🌵",size:"28px"},{x:"50%",icon:"🌴",size:"36px"}]},
    1:{ skyGrad:"linear-gradient(180deg,#2d1b4e 0%,#4a2c6a 50%,#6b3d2a 100%)",
        midGrad:"linear-gradient(180deg,#2d4a1e,#1a2d0e)",
        groundGrad:"linear-gradient(180deg,#2d4a1e 0%,#1a2d0e 100%)",groundEdge:"#0d1f08",
        clouds:[{y:20,x:"10%",w:80,h:22},{y:35,x:"60%",w:60,h:18}],
        bgDecor:[{x:"6%",icon:"🍄",size:"40px"},{x:"30%",icon:"🌿",size:"30px"},{x:"55%",icon:"🍄",size:"28px"}]},
    2:{ skyGrad:"linear-gradient(180deg,#1a1a2e 0%,#16213e 50%,#2a1a1a 100%)",
        midGrad:"linear-gradient(180deg,#3d2b1f,#2a1a0e)",
        groundGrad:"linear-gradient(180deg,#3d2b1f 0%,#1e0e06 100%)",groundEdge:"#120800",
        clouds:[{y:25,x:"15%",w:70,h:18},{y:40,x:"65%",w:50,h:14}],
        bgDecor:[{x:"10%",icon:"💀",size:"32px"},{x:"35%",icon:"🦴",size:"24px"},{x:"58%",icon:"💀",size:"28px"}]},
    3:{ skyGrad:"linear-gradient(180deg,#050510 0%,#0d0a22 50%,#1a0a1a 100%)",
        midGrad:"linear-gradient(180deg,#1a1a2e,#0d0d1a)",
        groundGrad:"linear-gradient(180deg,#1a1a2e 0%,#080812 100%)",groundEdge:"#04040a",
        clouds:[{y:20,x:"5%",w:60,h:16},{y:38,x:"58%",w:44,h:12}],
        bgDecor:[{x:"8%",icon:"🌑",size:"36px"},{x:"40%",icon:"✨",size:"22px"},{x:"62%",icon:"🌑",size:"28px"}]},
    4:{ skyGrad:"linear-gradient(180deg,#1a0200 0%,#5a0800 40%,#c82000 80%,#ff4400 100%)",
        midGrad:"linear-gradient(180deg,#8b1500,#4a0800)",
        groundGrad:"linear-gradient(180deg,#6b1800 0%,#3a0800 100%)",groundEdge:"#220400",
        clouds:[{y:22,x:"12%",w:75,h:20},{y:35,x:"62%",w:55,h:16}],
        bgDecor:[{x:"6%",icon:"🔥",size:"40px"},{x:"32%",icon:"💥",size:"28px"},{x:"56%",icon:"🔥",size:"32px"}]},
    5:{ skyGrad:"linear-gradient(180deg,#050e22 0%,#0a1e3a 50%,#0d2e4a 100%)",
        midGrad:"linear-gradient(180deg,#1e3040,#0a1628)",
        groundGrad:"linear-gradient(180deg,#1e3040 0%,#0a1020 100%)",groundEdge:"#050a14",
        clouds:[{y:18,x:"8%",w:70,h:20},{y:32,x:"60%",w:52,h:16}],
        bgDecor:[{x:"8%",icon:"💎",size:"36px"},{x:"36%",icon:"✨",size:"24px"},{x:"58%",icon:"💎",size:"30px"}]},
    6:{ skyGrad:"linear-gradient(180deg,#1a0a2e 0%,#2e0a2e 50%,#1a0a0a 100%)",
        midGrad:"linear-gradient(180deg,#2a0a2a,#1a0a1a)",
        groundGrad:"linear-gradient(180deg,#2a0a2a 0%,#100510 100%)",groundEdge:"#080308",
        clouds:[{y:22,x:"10%",w:68,h:18},{y:38,x:"62%",w:50,h:14}],
        bgDecor:[{x:"8%",icon:"👻",size:"36px"},{x:"35%",icon:"🌑",size:"26px"},{x:"58%",icon:"👻",size:"30px"}]},
    7:{ skyGrad:"linear-gradient(180deg,#1a0a00 0%,#2e1500 50%,#3a1a00 100%)",
        midGrad:"linear-gradient(180deg,#2e1a0a,#1a0a00)",
        groundGrad:"linear-gradient(180deg,#2e1a0a 0%,#140800 100%)",groundEdge:"#0a0400",
        clouds:[{y:20,x:"10%",w:72,h:20},{y:36,x:"60%",w:54,h:16}],
        bgDecor:[{x:"6%",icon:"📚",size:"38px"},{x:"34%",icon:"📖",size:"26px"},{x:"56%",icon:"📚",size:"30px"}]},
    8:{ skyGrad:"linear-gradient(180deg,#1a0000 0%,#3a0000 50%,#5a0000 100%)",
        midGrad:"linear-gradient(180deg,#3a0000,#1a0000)",
        groundGrad:"linear-gradient(180deg,#3a0000 0%,#180000 100%)",groundEdge:"#0a0000",
        clouds:[{y:22,x:"12%",w:70,h:18},{y:38,x:"62%",w:52,h:14}],
        bgDecor:[{x:"8%",icon:"⚰️",size:"36px"},{x:"36%",icon:"💀",size:"28px"},{x:"58%",icon:"⚰️",size:"30px"}]},
    9:{ skyGrad:"linear-gradient(180deg,#000000 0%,#050005 40%,#0a000a 100%)",
        midGrad:"linear-gradient(180deg,#0a000a,#000000)",
        groundGrad:"linear-gradient(180deg,#0a000a 0%,#000000 100%)",groundEdge:"#000000",
        clouds:[{y:20,x:"8%",w:65,h:18},{y:36,x:"60%",w:48,h:14}],
        bgDecor:[{x:"8%",icon:"🌑",size:"36px"},{x:"36%",icon:"👁️",size:"28px"},{x:"58%",icon:"🌑",size:"30px"}]},
  };
  const theme = BG_THEMES[combat.dungeonId] || BG_THEMES[0];

  // Flash hit animation + combat movement animations
  function spawnFloat(val, isPlayer) {
    const id = Date.now() + Math.random();
    const x = isPlayer ? 20 + Math.random()*30 : 55 + Math.random()*30;
    setFloats(f => [...f.slice(-8), {id, val, x, isPlayer}]);
    setTimeout(() => setFloats(f => f.filter(e => e.id !== id)), 900);
    setHitFlash(isPlayer ? "player" : "enemy");
    setTimeout(() => setHitFlash(null), 150);
  }

  function triggerAttackAnims(dt, isCrit, dodged, mDmg) {
    setHeroAnim("lunge");
    setTimeout(() => setHeroAnim(null), 250);
    if (!dodged) {
      setTimeout(() => {
        setEnemyAnim("knockback");
        setTimeout(() => setEnemyAnim(null), 250);
      }, 100);
    }
    if (mDmg > 0) {
      setTimeout(() => {
        setEnemyAnim("lunge");
        setTimeout(() => setEnemyAnim(null), 200);
        setTimeout(() => {
          setHeroAnim("knockback");
          setTimeout(() => setHeroAnim(null), 250);
        }, 100);
      }, 350);
    }
  }

  function triggerHeavyAnims(dt) {
    setHeroAnim("lunge");
    setTimeout(() => {
      setHeroAnim(null);
      setEnemyAnim("knockback");
      setTimeout(() => setEnemyAnim(null), 350);
    }, 200);
  }

  function triggerEnemyDeath() {
    setEnemyAnim("death");
    // death anim lingers — cleared when enemyIdx advances or combat ends
  }

  // Wrap attack to spawn floats
  function attackWithFX() {
    if (!combat || combat.defeat || combat.pendingLoot) return;
    const dungeon  = DUNGEONS[combat.dungeonId] || DUNGEONS[DUNGEONS.length - 1];
    const enemy    = combat.enemies[combat.enemyIdx];
    const gc       = gearCombatStats(character.equipped);
    function clsB(stat) { return (character.cls?.statBonuses||[]).filter(b=>b.stat===stat).reduce((s,b)=>s+b.amt,0); }
    const _al  = character.allocatedStats || {};
    const str  = 8 + clsB("strength")     + Math.floor(level*0.8) + (_al.strength||0);
    const dex  = 8 + clsB("dexterity")    + Math.floor(level*0.7) + (_al.dexterity||0);
    const intl = 8 + clsB("intelligence") + Math.floor(level*0.5) + (_al.intelligence||0);
    const cha  = 5 + clsB("fortune")     + Math.floor(level*0.3) + (_al.fortune||0);
    const con  = 8 + clsB("constitution") + Math.floor(level*0.9) + (_al.constitution||0);
    const wDmg    = weaponBaseDmg(character.equipped);
    const dt      = weaponDamageType(character.equipped);
    const offense = dt==="magic" ? intl : dt==="ranged" ? dex : str;
    const magicBonus = dt==="magic" ? (gc.magicDmg||0) : 0;
    // Wellness buffs + inactivity debuffs
    const _buffs    = getWellnessBuffs(character);
    const _wBuff    = getWorkoutBuff(character);
    if (_wBuff) _buffs.push(_wBuff);
    const _debuffs  = getInactivityDebuffs(character);
    // Item set bonuses
    const _sets     = getActiveSetBonuses(character.equipped);
    const _setDmgMult = _sets.filter(b => b.stat==="meleeDmg" && dt==="melee").reduce((m,b) => m*(1+(b.amt||0)), 1)
                      * _sets.filter(b => b.stat==="magicDmg"  && dt==="magic").reduce((m,b) => m*(1+(b.amt||0)), 1)
                      * _sets.filter(b => b.stat==="rangedDmg" && dt==="ranged").reduce((m,b) => m*(1+(b.amt||0)), 1);
    const _setCrit  = _sets.filter(b => b.crit).reduce((s,b) => s+(b.crit||0)/100, 0);
    const _setDodge = _sets.filter(b => b.stat==="dodge").reduce((s,b) => s+(b.amt||0)/100, 0);
    const _setHP    = _sets.filter(b => b.hp).reduce((s,b) => s+(b.hp||0), 0);
    // World event bonus
    const _event    = getCurrentEvent();
    const _evDmg    = _event?.dmgMult || 1;
    const _dmgMult  = _debuffs.reduce((m,d) => m*(d.dmgMult||1), 1) * (_wBuff?.dmgMult||1) * _setDmgMult * _evDmg;
    const _critBonus= _buffs.reduce((s,b) => s+(b.stat==="crit"?(b.amt/100):0), 0) + (_wBuff?.critBonus||0) + _setCrit;
    const _dodgeBonus= _buffs.reduce((s,b) => s+(b.stat==="dodge"?(b.amt/100):0), 0) + _setDodge;
    const _dodgePen = _debuffs.reduce((s,d) => s+(d.dodgePen||0), 0);
    const critPct = dex*0.006 + (gc.crit||0)/100 + _critBonus;
    const isCrit  = Math.random() < critPct;
    const rawDmg  = wDmg + Math.floor(Math.random()*10) + level*3 + Math.floor(offense/2) + magicBonus;
    // Apply enemy resist/weak + fitness buffs/debuffs
    const traits  = getEnemyTraits(enemy.name);
    const dmgMult = (traits.resist === dt ? 0.5 : traits.weak === dt ? 1.5 : 1.0) * _dmgMult;
    // Apply active ability multipliers
    const _ab = combat.abilityActive;
    const warCryMult = _ab?.type === "war_cry" && _ab.hitsLeft > 0 ? 1.8 : 1.0;
    // Curse status effect reduces outgoing damage 25%
    const curseMult = (combat.statusEffects||[]).some(s => s.id === "curse") ? 0.75 : 1.0;
    const baseDmg = Math.floor((isCrit ? Math.floor(rawDmg*1.5) : rawDmg) * dmgMult * warCryMult * curseMult);
    const defense = Math.floor(con/5) + level;
    const dodgePct = Math.min(0.30, Math.max(0, dex*0.002 + (gc.dodge||0)/200 + _dodgeBonus*0.5 - _dodgePen));
    const dodged  = Math.random() < dodgePct;
    // Endure: block incoming damage
    const endureBlocking = _ab?.type === "endure" && _ab.blocksLeft > 0;
    // Player resistance/weakness to enemy attack type
    const playerResist = getPlayerResist(character);
    const enemyDmgType = enemy.dmgType || "melee"; // enemies default to melee
    const playerResMult = playerResist.resist === enemyDmgType ? 0.6
                        : playerResist.weak   === enemyDmgType ? 1.4 : 1.0;
    // Active status effect modifiers on incoming damage
    const activeStatus = combat?.statusEffects || [];
    const shattered = activeStatus.some(s => s.id === "shatter");
    const rawMDmg = (dodged || endureBlocking) ? 0 : Math.max(3, enemy.atk - (shattered ? 0 : defense) + Math.floor(Math.random()*10) - 5);
    const mDmg = Math.floor(rawMDmg * playerResMult);
    // Check if enemy inflicts a status effect this hit
    const possibleStatus = getEnemyStatusEffect(enemy.name);
    const statusInflictChance = enemy.isBoss ? 0.5 : 0.25;
    const inflictsStatus = possibleStatus && !dodged && Math.random() < statusInflictChance;

    // Class flavor attack words
    const MELEE_WORDS = { fighter:["Slash","Strike","Cleave","Smash","Crush"], rogue:["Stab","Pierce","Shiv","Backstab","Gouge"], explorer:["Hack","Jab","Swing","Hit"], nomad:["Strike","Smash","Hit"], default:["Hit","Strike","Slash"] };
    const RANGED_WORDS= { ranger:["Shoot","Arrow","Volley","Snipe"], nomad:["Sling","Hurl"], default:["Shot","Fire"] };
    const MAGIC_WORDS = { wizard:["Blast","Bolt","Surge","Zap","Arcane"], default:["Spell","Cast"] };
    const clsId = character.cls?.id || "default";
    function pickWord(pool) { const arr = pool[clsId]||pool.default; return arr[Math.floor(Math.random()*arr.length)]; }
    const flavorWord = dt==="magic" ? pickWord(MAGIC_WORDS) : dt==="ranged" ? pickWord(RANGED_WORDS) : pickWord(MELEE_WORDS);
    const dmgLabel = dmgMult === 0.5 ? `RESIST! -${baseDmg}` : dmgMult === 1.5 ? `WEAK! -${baseDmg}` : isCrit ? `${flavorWord}! CRIT -${baseDmg}` : `${flavorWord}! -${baseDmg}`;
    spawnFloat(dmgLabel, false);
    if (isCrit) onQuestProgress?.("crit");
    if (dodged) { spawnFloat("DODGE!", true); onQuestProgress?.("dodge"); }
    else if (mDmg > 0) {
      const inLabel = playerResMult < 1 ? `RESIST! -${mDmg}` : playerResMult > 1 ? `WEAK! -${mDmg}` : `-${mDmg}`;
      spawnFloat(inLabel, true);
    }
    if (inflictsStatus) spawnFloat(`${STATUS_EFFECTS[possibleStatus]?.icon} ${STATUS_EFFECTS[possibleStatus]?.label}!`, true);
    triggerAttackAnims(dt, isCrit, dodged, mDmg);

    setCombat(c => {
      if (!c || c.defeat || c.pendingLoot) return c;
      // Always compute from latest c.mHP / c.pHP — never stale closure values
      const newMHP = Math.max(0, c.mHP - baseDmg);

      // ── Process existing status effects ──────────────────────────────
      let statusEffects = [...(c.statusEffects || [])];
      let statusDmg = 0;
      let statusLog = [];
      const now = Date.now();
      statusEffects = statusEffects.filter(s => {
        if (s.expiresAt && now > s.expiresAt) return false; // expired
        if (s.hitsLeft !== undefined) { s.hitsLeft--; return s.hitsLeft > 0; }
        return true;
      });
      // Apply DoT from poison/burn
      statusEffects.forEach(s => {
        if (s.id === "poison") { statusDmg += 4; statusLog.push("☠️ Poison -4"); }
        if (s.id === "burn")   { statusDmg += 6; statusLog.push("🔥 Burn -6"); }
      });
      // Apply new status effect from this hit
      if (inflictsStatus && !statusEffects.some(s => s.id === possibleStatus)) {
        const newSt = { id: possibleStatus };
        if (possibleStatus === "poison") newSt.expiresAt = now + 15000;
        if (possibleStatus === "burn")   newSt.hitsLeft = 3;
        if (possibleStatus === "bleed")  newSt.expiresAt = now + 10000;
        if (possibleStatus === "curse")  newSt.hitsLeft = 5;
        if (possibleStatus === "chill")  newSt.expiresAt = now + 8000;
        if (possibleStatus === "shatter") newSt.hitsLeft = 3;
        statusEffects.push(newSt);
      }

      // Curse: -25% outgoing damage (already applied above via _dmgMult if we read it — handled separately below)
      const cursed = statusEffects.some(s => s.id === "curse");

      const totalPDmg = mDmg + statusDmg;
      const newPHP = Math.max(0, c.pHP - totalPDmg);
      const curEnemy = c.enemies[c.enemyIdx];

      if (newPHP <= 0) {
        // ── DEFEAT LOOT: 1 item per 2 enemies killed + small gold ─────────
        const kills = (c.killCount||0);
        const defeatItemCount = Math.max(0, Math.floor(kills / 2));
        const defeatGold = Math.max(10, kills * 8);
        const defeatItems = Array.from({length: defeatItemCount}, () =>
          makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, cha))
        );
        const defeatLoot = defeatItemCount > 0
          ? { items:defeatItems, gold:defeatGold, type:"defeat", kills }
          : { items:[], gold:defeatGold, type:"defeat", kills };
        setTimeout(() => onItemSold(defeatGold), 0);
        return {...c, pHP:0, defeat:true,
          pendingLoot: defeatLoot,
          log:[`💀 Defeated by ${curEnemy.name}!`,...(c.log||[])].slice(0,8)};
      }
      if (newMHP <= 0) {
        setTimeout(() => triggerEnemyDeath(), 0);
        const isFinalBoss = !!curEnemy.isFinalBoss;
        const isFloorBoss = !!curEnemy.isBoss;
        const killCount = (c.killCount||0) + 1;
        setTimeout(() => { onQuestProgress?.("kills", 1); }, 0);
        if (isFinalBoss || isFloorBoss) {
          // ── BOSS KILL: 3 items + gold reward ─────────────────────────────
          const _goldMult = _event?.goldMult || 1;
          const isWeekly  = !!curEnemy.isWeeklyBoss;
          const goldReward = isWeekly
            ? Math.floor((curEnemy.reward?.gold || 800) * _goldMult)
            : Math.floor((50 + (c.floorNum||1) * 25) * (isFinalBoss ? 2 : 1) * _goldMult);
          const bossItems = isWeekly ? [
            makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, cha, true, false)),
            makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, cha, true, false)),
            makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, cha, true, false)),
          ] : [
            makeItem(weightedPick(dungeon.lootPool), rollRarity(isFinalBoss, true, cha)),
            makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, cha)),
            makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, cha)),
          ];
          setTimeout(() => {
            const epicR = ["Epic","Legendary","Mythic"];
            const rareR = ["Rare","Epic","Legendary","Mythic"];
            bossItems.forEach(item => {
              if (rareR.includes(item.rarity)) onQuestProgress?.("rareItem");
              if (epicR.includes(item.rarity)) onQuestProgress?.("epicItem");
              if (["Legendary","Mythic"].includes(item.rarity)) onQuestProgress?.("legendItem");
              if (item.rarity === "Mythic") onQuestProgress?.("mythicItem");
            });
            onQuestProgress?.("boss");
            onQuestProgress?.("floor", !c.potionUsed);
            if (!c.potionUsed) onQuestProgress?.("boss", true);
          }, 0);
          if (isFinalBoss || isWeekly) {
            if (!isWeekly) onDungeonClear(c.dungeonId);
            setTimeout(() => onItemSold(goldReward), 0);
            return {...c, mHP:0, pHP:newPHP, killCount,
              pendingLoot:{ items:bossItems, gold:goldReward, type:"boss", isFinal:true },
              bossCleared: isWeekly ? "weekly" : "dungeon",
              log:[`🏆 ${curEnemy.name} DEFEATED!${isWeekly?" WEEKLY BOSS SLAIN!":""}`,...(c.log||[])].slice(0,8)};
          }
          onDungeonClear(c.dungeonId, c.floorNum);
          setTimeout(() => onItemSold(goldReward), 0);
          return {...c, mHP:0, pHP:newPHP, killCount,
            pendingLoot:{ items:bossItems, gold:goldReward, type:"boss", isFinal:false },
            bossCleared:"floor",
            log:[`🏆 Floor ${c.floorNum} cleared! ${curEnemy.name} defeated!`,...(c.log||[])].slice(0,8)};
        }
        // ── REGULAR KILL: no loot, just advance ──────────────────────────────
        const nextEnemy = c.enemies[c.enemyIdx + 1];
        return {...c, enemyIdx:c.enemyIdx+1, pHP:newPHP, killCount,
          mHP:nextEnemy.hp, mHPMax:nextEnemy.hp,
          log:[`✓ ${curEnemy.name} slain!`,`${nextEnemy.icon} ${nextEnemy.name} appears!`,...(c.log||[])].slice(0,8)};
      }
      // Tick down ability counters
      let updatedAbility = c.abilityActive;
      if (updatedAbility?.type === "war_cry" && updatedAbility.hitsLeft > 0) {
        updatedAbility = updatedAbility.hitsLeft <= 1 ? null : {...updatedAbility, hitsLeft: updatedAbility.hitsLeft - 1};
      } else if (updatedAbility?.type === "endure" && endureBlocking) {
        updatedAbility = updatedAbility.blocksLeft <= 1 ? null : {...updatedAbility, blocksLeft: updatedAbility.blocksLeft - 1};
      } else if (updatedAbility?.type === "adrenaline" && updatedAbility.expiresAt < Date.now()) {
        updatedAbility = null;
      }
      const warCryLabel = warCryMult > 1 ? ` 📯×${_ab?.hitsLeft}` : "";
      const endureLabel = endureBlocking ? ` 🛡️ BLOCKED` : "";
      const playerResLabel = playerResMult < 1 ? " (RESIST)" : playerResMult > 1 ? " (WEAK!)" : "";
      const statusLogStr = statusLog.length ? ` · ${statusLog.join(" · ")}` : "";
      return {...c, mHP:newMHP, pHP:newPHP, abilityActive: updatedAbility, statusEffects,
        log:[`⚔️ You deal ${baseDmg}!${warCryLabel}`,`💥 ${curEnemy.name} strikes ${totalPDmg}!${endureLabel}${playerResLabel}${statusLogStr}`,...(c.log||[])].slice(0,8)};
    });
  }



  const mHPPct = combat.mHPMax > 0 ? (combat.mHP / combat.mHPMax) * 100 : 0;
  const pHPPct = pHPMax > 0 ? (combat.pHP / pHPMax) * 100 : 0;
  const gc_hud = gearCombatStats(character.equipped);
  function clsBonusHud(stat) { return (character.cls?.statBonuses||[]).filter(b=>b.stat===stat).reduce((s,b)=>s+b.amt,0); }
  const _alHud   = character.allocatedStats || {};
  const str_hud  = 8 + clsBonusHud("strength")     + Math.floor(level*0.8) + (_alHud.strength||0);
  const dex_hud  = 8 + clsBonusHud("dexterity")    + Math.floor(level*0.7) + (_alHud.dexterity||0);
  const int_hud  = 8 + clsBonusHud("intelligence")  + Math.floor(level*0.5) + (_alHud.intelligence||0);
  const con_hud  = 8 + clsBonusHud("constitution") + Math.floor(level*0.9) + (_alHud.constitution||0);
  const defense  = Math.floor(con_hud/5) + level;
  const dodgePct_hud = Math.min(30, (dex_hud*0.2 + (gc_hud.dodge||0)*0.5)).toFixed(1);
  const dt_hud   = weaponDamageType(character.equipped);
  const off_hud  = dt_hud==="magic" ? int_hud : dt_hud==="ranged" ? dex_hud : str_hud;
  const wDmg_hud = weaponBaseDmg(character.equipped);
  const heavyDmg = Math.floor((wDmg_hud + 5 + level*3 + Math.floor(off_hud/2)) * 3);

  return (
    <div style={{display:"flex",flexDirection:"column",height:"100%",gap:0}}>
      {toast && <div className="sold-toast">{toast}</div>}

      {/* ══ BATTLE STAGE (full-width, portrait, Cup-Heroes style) ══ */}
      <div style={{position:"relative",width:"100%",height:340,overflow:"hidden",flexShrink:0,userSelect:"none"}}>

        {/* ── SKY layer ── */}
        <div style={{position:"absolute",inset:0,background:theme.skyGrad}}/>

        {/* ── FAR clouds ── */}
        {theme.clouds.map((c,i)=>(
          <div key={i} style={{position:"absolute",top:c.y,left:c.x,width:c.w,height:c.h,
            background:"rgba(255,255,255,.55)",borderRadius:"50%",filter:"blur(6px)",opacity:.7}}/>
        ))}

        {/* ── MID background (mountains/rocks) ── */}
        <div style={{position:"absolute",bottom:110,left:0,right:0,height:120,
          background:theme.midGrad,clipPath:"polygon(0 60%,8% 30%,18% 50%,30% 10%,44% 40%,58% 5%,72% 35%,85% 15%,100% 45%,100% 100%,0 100%)",
          opacity:.85}}/>

        {/* ── PALM / BG decor ── */}
        {theme.bgDecor.map((d,i)=>(
          <div key={i} style={{position:"absolute",bottom:108,left:d.x,fontSize:d.size,opacity:.9,filter:"saturate(1.2)",zIndex:2}}>{d.icon}</div>
        ))}

        {/* ── GROUND platform ── */}
        <div style={{position:"absolute",bottom:0,left:0,right:0,height:115,
          background:theme.groundGrad,borderTop:`4px solid ${theme.groundEdge}`,zIndex:3}}/>
        {/* ground detail strip */}
        <div style={{position:"absolute",bottom:88,left:0,right:0,height:12,
          background:theme.groundEdge,opacity:.5,zIndex:4}}/>
        {/* pebbles */}
        {[8,22,38,54,68,82].map(x=>(
          <div key={x} style={{position:"absolute",bottom:92,left:`${x}%`,width:8,height:4,
            background:"rgba(0,0,0,.18)",borderRadius:"50%",zIndex:5}}/>
        ))}

        {/* ── TOP HUD ── */}
        {/* Left: exit button */}
        <button onClick={exitCombat} style={{
          position:"absolute",top:10,left:10,zIndex:30,
          background:"rgba(255,255,255,.92)",border:"none",borderRadius:"50%",
          width:32,height:32,fontSize:"1rem",cursor:"pointer",
          display:"flex",alignItems:"center",justifyContent:"center",
          boxShadow:"0 2px 6px rgba(0,0,0,.35)",fontWeight:700,color:"#333",
        }}>✕</button>

        {/* Center: WAVE counter pill */}
        <div style={{
          position:"absolute",top:10,left:"50%",transform:"translateX(-50%)",zIndex:30,
          background:"rgba(255,255,255,.95)",borderRadius:"20px",
          padding:".22rem .9rem",boxShadow:"0 2px 8px rgba(0,0,0,.3)",
        }}>
          <div style={{fontFamily:"'Cinzel',serif",fontWeight:900,fontSize:".85rem",
            letterSpacing:".06em",color:"#222",lineHeight:1.1,textAlign:"center"}}>
            WAVE {waveNum}/{totalWaves}
          </div>
          {/* wave progress bar */}
          <div style={{height:3,background:"#ddd",borderRadius:3,marginTop:2,overflow:"hidden",width:80}}>
            <div style={{height:"100%",borderRadius:3,
              background:`linear-gradient(90deg,#f39c12,#e74c3c)`,
              width:`${(waveNum/totalWaves)*100}%`,transition:"width .5s"}}/>
          </div>
        </div>

        {/* ── HERO ── */}
        <div style={{
          position:"absolute",bottom:83,left:"4%",
          display:"flex",flexDirection:"column",alignItems:"center",gap:0,
          animation: heroAnim === "lunge"     ? "heroLunge .22s ease forwards"
                   : heroAnim === "knockback" ? "heroKnockback .25s ease forwards"
                   : !combat.defeat&&!paused  ? "heroIdle .55s ease-in-out infinite alternate"
                   : "none",
          zIndex:10,
        }}>
          {/* Stat bubble — shield + HP bar, like reference */}
          <div style={{
            display:"flex",alignItems:"center",gap:4,marginBottom:4,
            background:"rgba(0,0,0,.55)",borderRadius:20,padding:"2px 6px 2px 3px",
            border:"1px solid rgba(255,255,255,.15)",
          }}>
            {/* Stamina icon + value */}
            <div style={{
              background:"#e67e22",borderRadius:"50%",width:18,height:18,
              display:"flex",alignItems:"center",justifyContent:"center",
              fontSize:".55rem",fontWeight:900,color:"#fff",flexShrink:0,
              border:"1.5px solid #f39c12",
            }}>⚡</div>
            <span style={{fontFamily:"'Cinzel',serif",fontSize:".62rem",color:"#fff",fontWeight:700,lineHeight:1}}>⚡</span>
            {/* HP bar */}
            <div style={{width:52,height:5,background:"rgba(255,255,255,.2)",borderRadius:3,overflow:"hidden"}}>
              <div style={{height:"100%",borderRadius:3,
                background:pHPPct>50?"#2ecc71":pHPPct>25?"#f1c40f":"#e74c3c",
                width:`${pHPPct}%`,transition:"width .3s"}}/>
            </div>
            <span style={{fontFamily:"'Cinzel',serif",fontSize:".58rem",color:"rgba(255,255,255,.8)",lineHeight:1}}>
              {combat.pHP>=1000?`${(combat.pHP/1000).toFixed(1)}K`:combat.pHP}
            </span>
          </div>
          <HeroSprite cls={character.cls} isHit={hitFlash==="player"} character={character}/>
          {/* Status effect icons */}
          {(combat.statusEffects||[]).length > 0 && (
            <div style={{display:"flex",gap:2,marginTop:2,flexWrap:"wrap",justifyContent:"center",maxWidth:70}}>
              {(combat.statusEffects||[]).map((s,i) => (
                <div key={i} title={STATUS_EFFECTS[s.id]?.label} style={{
                  background:`${STATUS_EFFECTS[s.id]?.color}33`,
                  border:`1px solid ${STATUS_EFFECTS[s.id]?.color}88`,
                  borderRadius:4, padding:"1px 3px", fontSize:".55rem",
                  color:"#fff", fontWeight:700,
                }}>{STATUS_EFFECTS[s.id]?.icon}</div>
              ))}
            </div>
          )}
        </div>

        {/* ── ENEMY ── */}
        {!combat.bossCleared && (
          <div style={{
            position:"absolute",bottom:83,right:isBoss?"2%":"6%",
            display:"flex",flexDirection:"column",alignItems:"center",gap:0,
            animation: enemyAnim === "knockback" ? "enemyKnockback .25s ease forwards"
                     : enemyAnim === "lunge"     ? "enemyLunge .2s ease forwards"
                     : enemyAnim === "death"     ? "enemyDeath .5s ease forwards"
                     : !paused                   ? "enemyIdle .7s ease-in-out infinite alternate"
                     : "none",
            zIndex:15,
          }}>
            {/* Enemy resist/weak + player resist/weak + status warning */}
            {(() => {
              const t = getEnemyTraits(enemy.name);
              const pr = getPlayerResist(character);
              const dmgIcon = { melee:"⚔️", ranged:"🏹", magic:"✨" };
              const enemyStatus = getEnemyStatusEffect(enemy.name);
              return (
                <div style={{display:"flex",gap:3,marginBottom:3,flexWrap:"wrap",justifyContent:"flex-end",maxWidth:96}}>
                  {t.weak    && <span style={{fontSize:".5rem",fontWeight:700,padding:"1px 4px",borderRadius:6,background:"#c0392b",color:"#fff",border:"1px solid #e74c3c"}}>{dmgIcon[t.weak]} WEAK</span>}
                  {t.resist  && <span style={{fontSize:".5rem",fontWeight:700,padding:"1px 4px",borderRadius:6,background:"#1a2a3a",color:"#7fb3d3",border:"1px solid #2980b9"}}>{dmgIcon[t.resist]} RES</span>}
                  {pr.weak   && <span style={{fontSize:".5rem",fontWeight:700,padding:"1px 4px",borderRadius:6,background:"#6d1e1e",color:"#ff8a8a",border:"1px solid #e74c3c"}} title="You are weak to this">{dmgIcon[pr.weak]} YOU</span>}
                  {enemyStatus && <span style={{fontSize:".5rem",fontWeight:700,padding:"1px 4px",borderRadius:6,background:(STATUS_EFFECTS[enemyStatus]?.color||"#666")+"33",color:STATUS_EFFECTS[enemyStatus]?.color||"#fff",border:`1px solid ${STATUS_EFFECTS[enemyStatus]?.color||"#666"}88`}}>{STATUS_EFFECTS[enemyStatus]?.icon}</span>}
                </div>
              );
            })()}
            {/* Enemy HP bar above */}
            <div style={{
              display:"flex",alignItems:"center",gap:4,marginBottom:4,
              background:"rgba(0,0,0,.55)",borderRadius:20,padding:"2px 6px",
              border:"1px solid rgba(255,255,255,.15)",
              minWidth:60,
            }}>
              <div style={{flex:1,height:5,background:"rgba(255,255,255,.2)",borderRadius:3,overflow:"hidden"}}>
                <div style={{height:"100%",borderRadius:3,background:isBoss?"#e74c3c":"#c0392b",
                  width:`${mHPPct}%`,transition:"width .3s"}}/>
              </div>
              <span style={{fontFamily:"'Cinzel',serif",fontSize:".6rem",color:"#fff",fontWeight:700,flexShrink:0}}>
                {combat.mHP>=1000?`${(combat.mHP/1000).toFixed(1)}K`:combat.mHP}
              </span>
            </div>
            <EnemySprite enemy={enemy} isHit={hitFlash==="enemy"}/>
          </div>
        )}

        {/* ── WAVE ANNOUNCEMENT (center-screen between waves) ── */}
        {waveAnnounce && (
          <div style={{
            position:"absolute", top:"50%", left:"50%",
            transform:"translate(-50%,-50%)",
            zIndex:50, pointerEvents:"none",
            textAlign:"center",
            animation:"waveIn .3s ease",
          }}>
            <div style={{
              fontFamily:"'Cinzel',serif", fontWeight:900,
              fontSize:"1.6rem", letterSpacing:".12em",
              color:waveAnnounce.color,
              textShadow:`0 0 30px ${waveAnnounce.color}, 0 2px 12px rgba(0,0,0,.9)`,
              lineHeight:1.1,
            }}>{waveAnnounce.label}</div>
          </div>
        )}

        {/* ── FLOATING DAMAGE ── */}
        {floats.map(f=>(
          <div key={f.id} style={{
            position:"absolute",
            bottom:f.isPlayer?160:155,
            left:`${f.x}%`,
            fontFamily:"'Cinzel',serif",fontWeight:900,
            fontSize:f.val.length>5?".75rem":"1rem",
            color:f.isPlayer?"#ff6b6b":f.val.startsWith("WEAK")?"#ff4444":f.val.startsWith("RESIST")?"#7fb3d3":"#ffd700",
            textShadow:"0 2px 6px rgba(0,0,0,.95)",
            pointerEvents:"none",
            animation:"floatDmg .9s ease-out forwards",
            zIndex:25,
          }}>{f.val}</div>
        ))}

        {/* ── JOURNEY IN PROGRESS banner (bottom of stage, like reference) ── */}
        <div style={{
          position:"absolute",bottom:0,left:0,right:0,
          background:"linear-gradient(180deg,transparent,rgba(0,0,0,.7))",
          padding:"1.5rem 1rem .6rem",
          textAlign:"center",zIndex:6,
          pointerEvents:"none",
        }}>
          <div style={{
            fontFamily:"'Cinzel',serif",fontWeight:900,
            fontSize:"1.05rem",letterSpacing:".12em",
            color:"#fff",textShadow:"0 2px 8px rgba(0,0,0,.9)",
            lineHeight:1.2,
          }}>
            {combat.defeat ? "DEFEAT" : combat.bossCleared ? (combat.bossCleared==="dungeon"?"DUNGEON CLEARED!":"FLOOR CLEARED!") : `${enemy.name}`}
          </div>
        </div>

        {/* ── DEFEAT / CLEAR dim overlay ── */}
        {(combat.bossCleared||combat.defeat)&&!combat.pendingLoot&&(
          <div style={{position:"absolute",inset:0,
            background:combat.defeat?"rgba(0,0,0,.6)":"rgba(0,0,0,.35)",
            zIndex:5,pointerEvents:"none"}}/>
        )}
      </div>

      {/* ── BOTTOM PANEL ── */}
      <div style={{
        background:"linear-gradient(180deg,#0d0d14,#0a0a0f)",
        border:"1px solid rgba(255,255,255,.08)",
        borderTop:"2px solid rgba(255,255,255,.12)",
        padding:".65rem .75rem",
        display:"flex",
        flexDirection:"column",
        gap:".5rem",
      }}>

        {/* ── ACTION ROW — active combat only ── */}
        {!combat.defeat && !combat.bossCleared && (
          <div style={{display:"flex",gap:".4rem",alignItems:"stretch",minHeight:72}}>

            {/* Heavy Attack */}
            {(() => {
              const lastHeavy = combat.lastHeavy || 0;
              void tick; // reference tick so the 1s interval triggers a re-render
              const remaining = Math.max(0, Math.ceil((lastHeavy + 15000 - Date.now()) / 1000));
              const ready = remaining === 0;
              return (
                <button onClick={() => {
                  if (!ready || combat.defeat || combat.pendingLoot) return;
                  // Compute chaH and goldMult outside the setCombat updater — no side effects inside state updaters
                  const _alH = character.allocatedStats || {};
                  const chaH = 5 + (character.cls?.statBonuses||[]).filter(b=>b.stat==="fortune").reduce((s,b)=>s+b.amt,0) + Math.floor(level*0.3) + (_alH.fortune||0);
                  const _evH = getCurrentEvent();
                  const _goldMultH = _evH?.goldMult || 1;
                  triggerHeavyAnims(dt_hud);
                  setCombat(c => {
                    if (!c || c.defeat || c.pendingLoot) return c;
                    const hit = Math.max(1, heavyDmg + Math.floor(Math.random()*20) - 10);
                    const newMHP = Math.max(0, c.mHP - hit);
                    spawnFloat(`💥 -${hit}`, false);
                    setHitFlash("enemy");
                    setTimeout(() => setHitFlash(null), 150);
                    if (newMHP <= 0) {
                      // Inline kill logic — avoids stale-closure race with attackWithFX
                      setTimeout(() => triggerEnemyDeath(), 0);
                      const dungeon    = DUNGEONS[c.dungeonId] || DUNGEONS[DUNGEONS.length - 1];
                      const curEnemy   = c.enemies[c.enemyIdx];
                      const isFinalBoss = !!curEnemy.isFinalBoss;
                      const isFloorBoss = !!curEnemy.isBoss;
                      const killCount  = (c.killCount||0) + 1;
                      setTimeout(() => { onQuestProgress?.("kills", 1); }, 0);
                      if (isFinalBoss || isFloorBoss) {
                        const isWeekly = !!curEnemy.isWeeklyBoss;
                        const goldReward = isWeekly
                          ? Math.floor((curEnemy.reward?.gold || 800) * _goldMultH)
                          : Math.floor((50 + (c.floorNum||1) * 25) * (isFinalBoss ? 2 : 1) * _goldMultH);
                        const bossItems = isWeekly ? [
                          makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, chaH, true, false)),
                          makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, chaH, true, false)),
                          makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, chaH, true, false)),
                        ] : [
                          makeItem(weightedPick(dungeon.lootPool), rollRarity(isFinalBoss, true, chaH)),
                          makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, chaH)),
                          makeItem(weightedPick(dungeon.lootPool), rollRarity(false, false, chaH)),
                        ];
                        setTimeout(() => {
                          const epicR = ["Epic","Legendary","Mythic"];
                          const rareR = ["Rare","Epic","Legendary","Mythic"];
                          bossItems.forEach(item => {
                            if (rareR.includes(item.rarity)) onQuestProgress?.("rareItem");
                            if (epicR.includes(item.rarity)) onQuestProgress?.("epicItem");
                            if (["Legendary","Mythic"].includes(item.rarity)) onQuestProgress?.("legendItem");
                            if (item.rarity === "Mythic") onQuestProgress?.("mythicItem");
                          });
                          onQuestProgress?.("boss");
                          onQuestProgress?.("floor", !c.potionUsed);
                          if (!c.potionUsed) onQuestProgress?.("boss", true);
                        }, 0);
                        if (isFinalBoss || isWeekly) {
                          if (!isWeekly) onDungeonClear(c.dungeonId);
                          setTimeout(() => onItemSold(goldReward), 0);
                          return {...c, mHP:0, lastHeavy:Date.now(), killCount,
                            pendingLoot:{ items:bossItems, gold:goldReward, type:"boss", isFinal:true },
                            bossCleared: isWeekly ? "weekly" : "dungeon",
                            log:[`🏆 ${curEnemy.name} DEFEATED!${isWeekly?" WEEKLY BOSS SLAIN!":""}`,...(c.log||[])].slice(0,8)};
                        }
                        onDungeonClear(c.dungeonId, c.floorNum);
                        setTimeout(() => onItemSold(goldReward), 0);
                        return {...c, mHP:0, lastHeavy:Date.now(), killCount,
                          pendingLoot:{ items:bossItems, gold:goldReward, type:"boss", isFinal:false },
                          bossCleared:"floor",
                          log:[`🏆 Floor ${c.floorNum} cleared! ${curEnemy.name} defeated!`,...(c.log||[])].slice(0,8)};
                      }
                      // Regular enemy kill — advance to next
                      const nextEnemy = c.enemies[c.enemyIdx + 1];
                      return {...c, enemyIdx:c.enemyIdx+1, mHP:nextEnemy.hp, mHPMax:nextEnemy.hp,
                        lastHeavy:Date.now(), killCount,
                        log:[`💥 Heavy! ${curEnemy.name} slain!`,`${nextEnemy.icon} ${nextEnemy.name} appears!`,...(c.log||[])].slice(0,8)};
                    }
                    return {...c, mHP:newMHP, lastHeavy:Date.now(), log:[`💥 Heavy strike! -${hit}!`,...(c.log||[])].slice(0,8)};
                  });
                }} style={{
                  flex:2.5, padding:".5rem .4rem",
                  background: ready ? "linear-gradient(160deg,#6b0000,#c0392b)" : "rgba(255,255,255,.04)",
                  border:`1px solid ${ready?"#e74c3caa":"rgba(255,255,255,.08)"}`,
                  borderRadius:12, cursor:ready?"pointer":"not-allowed",
                  display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:3,
                  boxShadow: ready ? "0 0 12px #e74c3c44" : "none",
                  transition:"all .2s",
                }}>
                  <span style={{fontSize:"1.6rem"}}>{ready?"⚔️":"⏳"}</span>
                  <span style={{fontFamily:"'Cinzel',serif",fontSize:".72rem",fontWeight:700,
                    color:ready?"#ff8080":"rgba(255,255,255,.25)",letterSpacing:".04em"}}>
                    {ready ? "HEAVY" : `${remaining}s`}
                  </span>
                  {ready && <span style={{fontSize:".56rem",color:"rgba(255,100,100,.6)"}}>~{heavyDmg} dmg</span>}
                </button>
              );
            })()}

            {/* Potion buttons — all 3 always shown, dim if empty */}
            {Object.values(POTION_TYPES).map(pt => {
              const count = (character.potions||{})[pt.id] || 0;
              const canUse = count > 0 && !combat.defeat && !combat.pendingLoot;
              return (
                <button key={pt.id} onClick={() => canUse && usePotion(pt.id)} style={{
                  flex:1, padding:".4rem .15rem",
                  background: canUse ? `${pt.color}1e` : "rgba(255,255,255,.03)",
                  border:`1px solid ${canUse ? pt.color+"77" : "rgba(255,255,255,.06)"}`,
                  borderRadius:12, cursor:canUse?"pointer":"default",
                  display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2,
                  opacity:count>0?1:0.28,
                  transition:"all .15s",
                }}>
                  <span style={{fontSize:"1.45rem"}}>{pt.icon}</span>
                  <span style={{fontFamily:"'Cinzel',serif",fontSize:".66rem",fontWeight:700,
                    color:count>0?pt.color:"rgba(255,255,255,.2)"}}>
                    {count>0?`×${count}`:"×0"}
                  </span>
                  <span style={{fontSize:".52rem",color:"rgba(255,255,255,.3)"}}>
                    {pt.heal>=9999?"Full":`+${pt.heal}`}
                  </span>
                </button>
              );
            })}

            {/* Pause toggle */}
            {/* ── CLASS ABILITY BUTTON ── */}
            {(() => {
              const ability = CLASS_ABILITIES[character.cls?.id];
              if (!ability) return null;
              const lastUsed = combat.lastAbility || 0;
              void tick;
              const elapsed = Math.floor((Date.now() - lastUsed) / 1000);
              const remaining = Math.max(0, ability.cooldown - elapsed);
              const ready = remaining === 0 && !combat.defeat && !combat.pendingLoot && !combat.bossCleared;
              const isActive = !!combat.abilityActive;
              const ab = combat.abilityActive;
              // Status label
              const statusLabel = isActive ? (
                ab?.type === "war_cry"  ? `📯×${ab.hitsLeft}` :
                ab?.type === "endure"   ? `🛡️×${ab.blocksLeft}` :
                ab?.type === "volley"   ? `🏹×${ab.hitsLeft}` :
                ab?.type === "adrenaline" ? `⚡` : ability.icon
              ) : ready ? ability.icon : `${remaining}s`;

              function useAbility() {
                if (!ready) return;
                const cls = character.cls?.id;
                if (cls === "wizard" || cls === "rogue") {
                  // Instant abilities — apply directly via setCombat
                  const gc  = gearCombatStats(character.equipped);
                  const _al = character.allocatedStats || {};
                  const str  = 8 + (character.cls?.statBonuses||[]).filter(b=>b.stat==="strength").reduce((s,b)=>s+b.amt,0)     + Math.floor(level*0.8) + (_al.strength||0);
                  const dex  = 8 + (character.cls?.statBonuses||[]).filter(b=>b.stat==="dexterity").reduce((s,b)=>s+b.amt,0)    + Math.floor(level*0.7) + (_al.dexterity||0);
                  const intl = 8 + (character.cls?.statBonuses||[]).filter(b=>b.stat==="intelligence").reduce((s,b)=>s+b.amt,0) + Math.floor(level*0.5) + (_al.intelligence||0);
                  const dt   = weaponDamageType(character.equipped);
                  const wDmg = weaponBaseDmg(character.equipped);
                  const offense = dt==="magic" ? intl : dt==="ranged" ? dex : str;
                  const baseDmg = Math.floor((wDmg + level*3 + Math.floor(offense/2)) * (cls==="rogue" ? 4 : 2.5));
                  spawnFloat(cls==="rogue" ? `🗡️ BACKSTAB! -${baseDmg}` : `✨ ARCANE BURST! -${baseDmg}`, false);
                  setHitFlash("enemy");
                  setTimeout(() => setHitFlash(null), 200);
                  setCombat(c => {
                    if (!c) return c;
                    const newMHP = Math.max(0, c.mHP - baseDmg);
                    return {...c, mHP:newMHP, lastAbility:Date.now(),
                      log:[`${cls==="rogue"?"🗡️ BACKSTAB":"✨ Arcane Burst"}! -${baseDmg}!`,...(c.log||[])].slice(0,8)};
                  });
                } else if (cls === "explorer") {
                  // Adrenaline — heal + speed
                  const maxHP = calcMaxHP();
                  const heal  = Math.floor(maxHP * 0.25);
                  spawnFloat(`⚡ +${heal} HP`, true);
                  setCombat(c => {
                    if (!c) return c;
                    return {...c,
                      pHP: Math.min(maxHP, c.pHP + heal),
                      lastAbility: Date.now(),
                      abilityActive: {type:"adrenaline", expiresAt: Date.now()+10000},
                      log:[`⚡ Adrenaline! +${heal} HP!`,...(c.log||[])].slice(0,8)};
                  });
                } else {
                  // Fighter (war_cry), Ranger (volley), Nomad (endure) — set active state
                  setCombat(c => {
                    if (!c) return c;
                    const newState =
                      cls==="fighter" ? {type:"war_cry",   hitsLeft:5} :
                      cls==="ranger"  ? {type:"volley",    hitsLeft:5} :
                                        {type:"endure",    blocksLeft:3};
                    const logMsg =
                      cls==="fighter" ? "📯 War Cry! Next 5 hits +80% damage!" :
                      cls==="ranger"  ? "🏹 Volley! 5 rapid strikes incoming!" :
                                        "🛡️ Endure! Next 3 hits blocked!";
                    return {...c, abilityActive:newState, lastAbility:Date.now(),
                      log:[logMsg,...(c.log||[])].slice(0,8)};
                  });
                }
              }

              return (
                <button onClick={useAbility} disabled={!ready} style={{
                  width:52, padding:".3rem .15rem",
                  background: isActive ? `${ability.color}33` : ready ? `${ability.color}22` : "rgba(255,255,255,.03)",
                  border:`1px solid ${isActive ? ability.color+"bb" : ready ? ability.color+"66" : "rgba(255,255,255,.08)"}`,
                  borderRadius:12, cursor:ready?"pointer":"default",
                  display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:2,
                  boxShadow: ready ? `0 0 10px ${ability.color}44` : "none",
                  transition:"all .2s", opacity: combat.defeat||combat.bossCleared ? 0.3 : 1,
                }}>
                  <span style={{fontSize:"1.3rem"}}>{ability.icon}</span>
                  <span style={{fontFamily:"'Cinzel',serif",fontSize:".58rem",fontWeight:700,
                    color:isActive?ability.color:ready?ability.color:"rgba(255,255,255,.2)",
                    letterSpacing:".02em"}}>{statusLabel}</span>
                  {ready && !isActive && <span style={{fontSize:".48rem",color:ability.color+"99"}}>{ability.name}</span>}
                </button>
              );
            })()}

            {/* Pause toggle */}
            <button onClick={()=>setPaused(p=>!p)} style={{
              width:46, padding:".4rem .2rem",
              background:"rgba(255,255,255,.05)",
              border:"1px solid rgba(255,255,255,.1)",
              borderRadius:12, cursor:"pointer",
              display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:3,
            }}>
              <span style={{fontSize:"1.1rem"}}>{paused?"▶":"⏸"}</span>
              <span style={{fontSize:".52rem",color:"rgba(255,255,255,.3)"}}>{paused?"Go":"Pause"}</span>
            </button>

          </div>
        )}

        {/* Paused label */}
        {paused && !combat.defeat && !combat.bossCleared && (
          <div style={{textAlign:"center",fontSize:".72rem",color:"rgba(255,255,255,.3)",letterSpacing:".06em"}}>
            ⏸ PAUSED
          </div>
        )}

        {/* Victory buttons */}
        {combat.bossCleared && !combat.pendingLoot && (
          <div style={{display:"flex",gap:".5rem"}}>
            {combat.bossCleared !== "weekly" && (
              <button onClick={rematchFloor} style={{flex:1,background:"rgba(255,255,255,.06)",border:"1px solid rgba(255,255,255,.12)",borderRadius:8,padding:".65rem",color:"rgba(255,255,255,.7)",cursor:"pointer",fontFamily:"'Cinzel',serif",fontSize:".8rem"}}>↩ Rematch</button>
            )}
            <button onClick={() => advanceAfterBoss(combat)} style={{flex:2,background:"linear-gradient(135deg,#c9a84c,#f0c96a)",border:"none",borderRadius:8,padding:".65rem",color:"#000",cursor:"pointer",fontFamily:"'Cinzel',serif",fontSize:".9rem",fontWeight:700}}>
              {combat.bossCleared==="weekly" ? "⚔️ Return to Dungeons" : combat.bossCleared==="dungeon" ? "Next Dungeon →" : "Next Floor →"}
            </button>
          </div>
        )}

        {/* Defeat buttons */}
        {combat.defeat && (
          <div style={{display:"flex",gap:".5rem"}}>
            <button onClick={rematchFloor} style={{flex:1,background:"rgba(192,57,43,.15)",border:"1px solid rgba(192,57,43,.4)",borderRadius:8,padding:".65rem",color:"#e74c3c",cursor:"pointer",fontFamily:"'Cinzel',serif",fontSize:".8rem"}}>↩ Rematch</button>
            <button onClick={() => { setCombat(null); setActiveDungeonId(null); setScreen("list"); }} style={{flex:1,background:"rgba(255,255,255,.06)",border:"1px solid rgba(255,255,255,.1)",borderRadius:8,padding:".65rem",color:"rgba(255,255,255,.7)",cursor:"pointer",fontFamily:"'Cinzel',serif",fontSize:".8rem"}}>
              {combat.dungeonId === -1 ? "← Dungeons" : "Floor Select"}
            </button>
          </div>
        )}

      </div>

      {/* Floor loot modal */}
      {combat.pendingLoot && (
        <FloorLootModal
          loot={combat.pendingLoot}
          equipped={character.equipped}
          onAction={handleLootAction}
          onDone={() => {
            const snap = {...combat, pendingLoot: null};
            setCombat(c => ({...c, pendingLoot:null}));
            // For weekly boss (win or lose path that had loot), return to dungeon list
            if (combat.bossCleared === "weekly" || combat.dungeonId === -1) {
              setTimeout(() => { setCombat(null); setActiveDungeonId(null); setScreen("list"); }, 50);
            }
            // For regular bosses, advanceAfterBoss handles navigation after pendingLoot clears
          }}
        />
      )}
    </div>
  );
}

// Scroll the main tab content div to top (used by all nav effects)
function scrollTabTop() {
  // Hit every possible scroll container — works regardless of which one the browser is using
  try { window.scrollTo(0, 0); } catch(e) {}
  try { document.documentElement.scrollTop = 0; } catch(e) {}
  try { document.body.scrollTop = 0; } catch(e) {}
  var el = document.querySelector(".tab-content");
  if (el) el.scrollTop = 0;
  var app = document.querySelector(".app");
  if (app) app.scrollTop = 0;
  var main = document.querySelector(".main-app");
  if (main) main.scrollTop = 0;
}

// ─── SOCIAL TAB ───────────────────────────────────────────────────────────────
// Safe storage helper — module-level, never inside a component
const guildStore = {
  async get(key, shared=false) {
    try {
      if (typeof window !== "undefined" && window.storage)
        return await window.storage.get(key, shared);
      const v = localStorage.getItem("forged:" + key);
      return v ? { value: v } : null;
    } catch(e) { return null; }
  },
  async set(key, value, shared=false) {
    try {
      if (typeof window !== "undefined" && window.storage)
        return await window.storage.set(key, value, shared);
      localStorage.setItem("forged:" + key, value);
    } catch(e) {}
  },
};

// Dungeon progress bar — module-level component (never nest components inside components)
function GuildDungeonBar({ profile }) {
  const cleared = profile?.clearedDungeons || 0;
  const fc      = profile?.floorClears || {};
  const totalFloors = Object.values(fc).reduce((s,arr)=>s+(Array.isArray(arr)?arr.length:0), 0);
  const pct   = Math.round((cleared / 10) * 100);
  const color = cleared >= 8 ? "#c9a84c" : cleared >= 5 ? "#9b59b6" : cleared >= 2 ? "#2980b9" : "#27ae60";
  return (
    <div style={{marginTop:".4rem"}}>
      <div style={{display:"flex",justifyContent:"space-between",fontSize:".65rem",color:"var(--text2)",marginBottom:".2rem"}}>
        <span>🏰 Dungeons</span>
        <span style={{color}}>{cleared}/10 cleared · {totalFloors} floors</span>
      </div>
      <div style={{height:4,background:"rgba(255,255,255,.08)",borderRadius:4,overflow:"hidden"}}>
        <div style={{height:"100%",width:`${pct}%`,background:color,borderRadius:4,transition:"width .4s"}}/>
      </div>
    </div>
  );
}

// Friend card — module-level, receives callbacks as props
function GuildFriendCard({ username, profile, onMessage, onRemove }) {
  if (!profile) return (
    <div style={{padding:".75rem 1rem",background:"var(--surface)",border:"1px solid var(--border)",borderRadius:12,marginBottom:".5rem",color:"var(--text2)",fontSize:".8rem",fontStyle:"italic"}}>
      {username} · profile unavailable
    </div>
  );
  const c = profile.cls?.color || "#c9a84c";
  return (
    <div style={{background:"var(--surface)",border:`1px solid ${c}33`,borderRadius:14,padding:".85rem 1rem",marginBottom:".6rem",position:"relative",overflow:"hidden"}}>
      <div style={{position:"absolute",inset:0,background:`radial-gradient(ellipse at top right,${c}0d,transparent 60%)`,pointerEvents:"none"}}/>
      <div style={{display:"flex",alignItems:"center",gap:".7rem",position:"relative"}}>
        <div style={{width:42,height:42,borderRadius:10,flexShrink:0,background:`${c}22`,border:`2px solid ${c}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.35rem"}}>
          {profile.cls?.icon || "⚔️"}
        </div>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:".9rem",color:c,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
            {profile.displayName || username}
          </div>
          <div style={{fontSize:".7rem",color:"var(--text2)"}}>Lv.{profile.level} {profile.cls?.name||"Adventurer"}</div>
          <GuildDungeonBar profile={profile}/>
        </div>
      </div>
      <div style={{display:"flex",gap:".4rem",marginTop:".65rem",position:"relative"}}>
        <button onClick={()=>onMessage(username)}
          style={{flex:1,padding:".38rem",background:"#0d1a0d",border:"1px solid #27ae6055",borderRadius:8,color:"#27ae60",fontSize:".72rem",fontFamily:"'Cinzel',serif",cursor:"pointer"}}>
          💬 Message
        </button>
        <button onClick={()=>onRemove(username)}
          style={{padding:".38rem .7rem",background:"rgba(231,76,60,.08)",border:"1px solid #e74c3c33",borderRadius:8,color:"#e74c3c",fontSize:".72rem",cursor:"pointer"}}>
          Remove
        </button>
      </div>
    </div>
  );
}

// ─── SOCIAL TAB ───────────────────────────────────────────────────────────────
// Embedded inside CharacterTab as a "Guild" view.
// Uses persistent shared storage — profiles sync cross-device by username.
// Storage keys (all shared=true except friends list):
//   social:profile:<username>  → public profile snapshot
//   social:inbox:<username>    → messages received
//   social:requests:<username> → pending friend requests
//   social:friends:<username>  → friend list (local only)

// ─── LEADERBOARD VIEW ─────────────────────────────────────────────────────────
function LeaderboardView({ character }) {
  const [rows, setRows]     = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError]   = useState(null);
  const myUsername = character.username || character.displayName || "";

  useEffect(() => {
    async function load() {
      try {
        const data = await supaGetLeaderboard();
        setRows(data || []);
      } catch(e) {
        setError("Could not load leaderboard");
      }
      setLoading(false);
    }
    load();
  }, []);

  const weekStart = new Date();
  weekStart.setDate(weekStart.getDate() - weekStart.getDay());
  const weekLabel = weekStart.toLocaleDateString("en-US", {month:"short", day:"numeric"});

  if (loading) return (
    <div style={{textAlign:"center",padding:"2rem",color:"var(--text2)"}}>
      <div style={{fontSize:"1.5rem",marginBottom:".5rem"}}>🏆</div>
      <div style={{fontSize:".85rem"}}>Loading leaderboard...</div>
    </div>
  );

  if (error) return (
    <div style={{textAlign:"center",padding:"2rem",color:"#e74c3c"}}>
      <div style={{fontSize:".85rem"}}>{error}</div>
      <div style={{fontSize:".72rem",color:"var(--text2)",marginTop:".5rem"}}>Sign in to appear on the leaderboard</div>
    </div>
  );

  if (!rows.length) return (
    <div style={{textAlign:"center",padding:"2rem",color:"var(--text2)"}}>
      <div style={{fontSize:"2rem",marginBottom:".5rem"}}>🏆</div>
      <div style={{fontSize:".9rem",fontFamily:"'Cinzel',serif",color:"var(--gold)",marginBottom:".4rem"}}>No scores yet</div>
      <div style={{fontSize:".78rem"}}>Be the first on the leaderboard this week!</div>
      <div style={{fontSize:".72rem",marginTop:".3rem",opacity:.6}}>Week of {weekLabel}</div>
    </div>
  );

  const medals = ["🥇","🥈","🥉"];

  return (
    <div>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:".85rem"}}>
        <div style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontWeight:700}}>🏆 Weekly Top Heroes</div>
        <div style={{fontSize:".68rem",color:"var(--text2)"}}>Week of {weekLabel}</div>
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:".5rem"}}>
        {rows.map((row, i) => {
          const isMe = row.username === myUsername;
          const medal = medals[i] || `${i+1}.`;
          return (
            <div key={row.username} style={{
              background: isMe ? "#c9a84c18" : "var(--surface)",
              border: `1px solid ${isMe ? "var(--gold)" : "var(--border)"}`,
              borderRadius:10, padding:".6rem .85rem",
              display:"flex", alignItems:"center", gap:".75rem",
            }}>
              <div style={{fontSize:i<3?"1.3rem":".85rem",fontWeight:700,minWidth:24,textAlign:"center",
                color:i===0?"#f0c96a":i===1?"#aaa9ad":i===2?"#cd7f32":"var(--text2)",
                fontFamily:"'Cinzel',serif"}}>{medal}</div>
              <div style={{
                width:32,height:32,borderRadius:8,flexShrink:0,
                background:(row.cls_color||"#c9a84c")+"22",
                border:`1px solid ${row.cls_color||"#c9a84c"}66`,
                display:"flex",alignItems:"center",justifyContent:"center",
                fontSize:"1.1rem",
              }}>{row.cls_icon||"⚔️"}</div>
              <div style={{flex:1,minWidth:0}}>
                <div style={{fontWeight:700,fontSize:".85rem",color:isMe?"var(--gold)":"var(--text)",
                  whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>
                  {row.username}{isMe?" (you)":""}
                </div>
                <div style={{fontSize:".7rem",color:"var(--text2)"}}>
                  {row.cls_name||"Hero"} · Lv.{row.level}
                </div>
              </div>
              <div style={{textAlign:"right",flexShrink:0}}>
                <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,color:isMe?"var(--gold)":"var(--text)",fontSize:".88rem"}}>
                  {(row.weekly_xp||0).toLocaleString()}
                </div>
                <div style={{fontSize:".62rem",color:"var(--text2)"}}>Weekly XP</div>
              </div>
            </div>
          );
        })}
      </div>
      <div style={{textAlign:"center",fontSize:".68rem",color:"var(--text2)",marginTop:"1rem",fontStyle:"italic"}}>
        Leaderboard resets every Monday · Sign in to appear here
      </div>
    </div>
  );
}

function GuildView({ character }) {
  const myUsername = character.username || character.displayName || "Hero";
  const level      = xpToLevel(character.xp);
  const cls        = character.cls;

  const [subView,      setSubView]      = useState("friends"); // friends | messages | search | compose

  // Scroll to top when switching guild sub-views
  useEffect(() => { scrollTabTop(); }, [subView]);
  const [friends,      setFriends]      = useState([]);
  const [requests,     setRequests]     = useState([]);
  const [inbox,        setInbox]        = useState([]);
  const [unread,       setUnread]       = useState(0);
  const [searchQ,      setSearchQ]      = useState("");
  const [searchResult, setSearchResult] = useState(null); // null|"loading"|"not_found"|"self"|{username,profile}
  const [composeFor,   setComposeFor]   = useState(null);
  const [msgText,      setMsgText]      = useState("");
  const [toast,        setToast]        = useState(null);
  const [loading,      setLoading]      = useState(true);
  const [friendCode,   setFriendCode]   = useState("");

  function showToast(msg) { setToast(msg); setTimeout(() => setToast(null), 2500); }
  function timeAgo(ts) {
    const m = Math.floor((Date.now()-ts)/60000);
    if (m < 1) return "just now";
    if (m < 60) return `${m}m ago`;
    const h = Math.floor(m/60);
    if (h < 24) return `${h}h ago`;
    return `${Math.floor(h/24)}d ago`;
  }

  // Generate a short friend code from username (6 chars)
  const myFriendCode = btoa(myUsername).replace(/[^A-Z0-9]/gi,"").slice(0,6).toUpperCase() || "??????";

  // Publish own profile on mount and whenever key stats change
  useEffect(() => {
    async function publish() {
      const profile = {
        username:        myUsername,
        displayName:     character.displayName || myUsername,
        level,
        cls: cls ? { id:cls.id, name:cls.name, icon:cls.icon, color:cls.color } : null,
        clearedDungeons: (character.clearedDungeons||[]).length,
        floorClears:     character.floorClears || {},
        updatedAt:       Date.now(),
      };
      await guildStore.set(`social:profile:${myUsername}`, JSON.stringify(profile), true);
    }
    publish();
  }, []); // publish on every mount so you're always discoverable

  // Re-publish when stats change
  useEffect(() => {
    async function publish() {
      const profile = {
        username:        myUsername,
        displayName:     character.displayName || myUsername,
        level,
        cls: cls ? { id:cls.id, name:cls.name, icon:cls.icon, color:cls.color } : null,
        clearedDungeons: (character.clearedDungeons||[]).length,
        floorClears:     character.floorClears || {},
        updatedAt:       Date.now(),
      };
      await guildStore.set(`social:profile:${myUsername}`, JSON.stringify(profile), true);
    }
    publish();
  }, [character.xp, character.clearedDungeons?.length, myUsername]);

  // Load friends, requests, inbox — always resolves, never hangs
  useEffect(() => {
    let cancelled = false;
    async function load() {
      try {
        // Friend list (local)
        let unames = [];
        const fr = await guildStore.get(`social:friends:${myUsername}`);
        try { unames = fr ? JSON.parse(fr.value) : []; } catch(e) {}

        // Load each friend's profile with a per-item timeout
        const profiles = await Promise.all(unames.map(async u => {
          try {
            const r = await guildStore.get(`social:profile:${u}`, true);
            return { username:u, profile: r ? JSON.parse(r.value) : null };
          } catch(e) { return { username:u, profile:null }; }
        }));

        // Requests
        let reqs = [];
        try { const r = await guildStore.get(`social:requests:${myUsername}`, true); reqs = r ? JSON.parse(r.value) : []; } catch(e) {}

        // Inbox
        let msgs = [];
        try { const r = await guildStore.get(`social:inbox:${myUsername}`, true); msgs = r ? JSON.parse(r.value) : []; } catch(e) {}

        if (!cancelled) {
          setFriends(profiles);
          setRequests(reqs);
          setInbox(msgs);
          setUnread(msgs.filter(m=>!m.read).length);
        }
      } catch(e) {
        // Storage completely unavailable — still show UI
      } finally {
        if (!cancelled) setLoading(false);
      }
    }

    // Hard timeout — if storage hangs for >3s, show UI anyway
    const timeout = setTimeout(() => { if (!cancelled) { cancelled = false; setLoading(false); } }, 3000);
    load().then(() => clearTimeout(timeout));
    return () => { cancelled = true; clearTimeout(timeout); };
  }, [myUsername]);

  async function saveFriendList(list) {
    try { await guildStore.set(`social:friends:${myUsername}`, JSON.stringify(list)); } catch(e) {}
  }

  async function handleSearch(query) {
    const target = (query || searchQ).trim();
    if (!target) return;
    if (target.toLowerCase() === myUsername.toLowerCase()) { setSearchResult("self"); return; }
    setSearchResult("loading");
    try {
      const r = await guildStore.get(`social:profile:${target}`, true);
      setSearchResult(r ? { username:target, profile:JSON.parse(r.value) } : "not_found");
    } catch(e) { setSearchResult("not_found"); }
  }

  async function sendRequest(targetUsername) {
    try {
      let existing = [];
      try { const r = await guildStore.get(`social:requests:${targetUsername}`, true); existing = r ? JSON.parse(r.value) : []; } catch(e) {}
      if (!existing.some(r => r.from === myUsername)) {
        existing.push({ from:myUsername, profile:{ username:myUsername, displayName:character.displayName||myUsername, level, cls: cls?{id:cls.id,name:cls.name,icon:cls.icon,color:cls.color}:null }, ts:Date.now() });
        await guildStore.set(`social:requests:${targetUsername}`, JSON.stringify(existing), true);
      }
      showToast(`Request sent to ${targetUsername}!`);
    } catch(e) { showToast("Failed to send."); }
  }

  async function acceptRequest(req) {
    const newList = [...new Set([...friends.map(f=>f.username), req.from])];
    const newFriends = [...friends.filter(f=>f.username!==req.from), { username:req.from, profile:req.profile }];
    setFriends(newFriends);
    await saveFriendList(newList);
    const rem = requests.filter(r=>r.from!==req.from);
    setRequests(rem);
    try { await guildStore.set(`social:requests:${myUsername}`, JSON.stringify(rem), true); } catch(e) {}
    // Best-effort: add myself to their list
    try {
      let tf = []; try { const r = await guildStore.get(`social:friends:${req.from}`); tf = r?JSON.parse(r.value):[]; } catch(e) {}
      if (!tf.includes(myUsername)) { tf.push(myUsername); await guildStore.set(`social:friends:${req.from}`, JSON.stringify(tf)); }
    } catch(e) {}
    showToast(`${req.from} added!`);
  }

  async function declineRequest(req) {
    const rem = requests.filter(r=>r.from!==req.from);
    setRequests(rem);
    try { await guildStore.set(`social:requests:${myUsername}`, JSON.stringify(rem), true); } catch(e) {}
  }

  async function removeFriend(uname) {
    const upd = friends.filter(f=>f.username!==uname);
    setFriends(upd);
    await saveFriendList(upd.map(f=>f.username));
    showToast(`${uname} removed.`);
  }

  async function sendMessage() {
    if (!msgText.trim() || !composeFor) return;
    try {
      let inbox2 = [];
      try { const r = await guildStore.get(`social:inbox:${composeFor}`, true); inbox2 = r?JSON.parse(r.value):[]; } catch(e) {}
      inbox2 = [{ from:myUsername, text:msgText.trim(), ts:Date.now(), read:false }, ...inbox2].slice(0,50);
      await guildStore.set(`social:inbox:${composeFor}`, JSON.stringify(inbox2), true);
      setMsgText(""); setComposeFor(null); setSubView("friends");
      showToast(`Sent to ${composeFor}!`);
    } catch(e) { showToast("Failed to send."); }
  }

  async function markAllRead() {
    const upd = inbox.map(m=>({...m,read:true}));
    setInbox(upd); setUnread(0);
    try { await guildStore.set(`social:inbox:${myUsername}`, JSON.stringify(upd), true); } catch(e) {}
  }

  async function deleteMsg(i) {
    const upd = inbox.filter((_,j)=>j!==i);
    setInbox(upd); setUnread(upd.filter(m=>!m.read).length);
    try { await guildStore.set(`social:inbox:${myUsername}`, JSON.stringify(upd), true); } catch(e) {}
  }

  const isFriend = (u) => friends.some(f=>f.username===u);

  if (loading) return <div style={{padding:"2rem",textAlign:"center",color:"var(--text2)"}}>Loading guild...</div>;

  return (
    <div>
      {/* Toast */}
      {toast && (
        <div style={{position:"fixed",top:0,left:"50%",transform:"translateX(-50%)",zIndex:1000,pointerEvents:"none",
          background:"linear-gradient(135deg,#1a1200,#2a2000)",border:"1px solid var(--gold)",borderTop:"none",
          borderRadius:"0 0 14px 14px",padding:".4rem 1.2rem",color:"var(--gold)",fontFamily:"'Cinzel',serif",
          fontSize:".78rem",boxShadow:"0 4px 20px #c9a84c44"}}>
          {toast}
        </div>
      )}

      {/* Sub-nav */}
      <div style={{display:"flex",gap:".4rem",marginBottom:"1rem"}}>
        {[
          {id:"friends", label:"Party",    icon:"⚔️", badge: requests.length},
          {id:"messages",label:"Messages", icon:"💬", badge: unread},
          {id:"search",  label:"Find",     icon:"🔍", badge: 0},
          {id:"leaderboard", label:"Top",  icon:"🏆", badge: 0},
        ].map(n => (
          <button key={n.id} onClick={()=>setSubView(n.id)} style={{
            flex:1,padding:".48rem .2rem",position:"relative",
            background: subView===n.id ? "#c9a84c18" : "var(--surface)",
            border:`1px solid ${subView===n.id ? "var(--gold)" : "var(--border)"}`,
            borderRadius:9,color:subView===n.id?"var(--gold)":"var(--text2)",
            fontSize:".72rem",fontFamily:"'Cinzel',serif",cursor:"pointer",
          }}>
            {n.badge>0 && <span style={{position:"absolute",top:4,right:5,background:"#e74c3c",color:"#fff",borderRadius:"50%",width:13,height:13,fontSize:".55rem",fontWeight:900,display:"flex",alignItems:"center",justifyContent:"center"}}>{n.badge}</span>}
            {n.icon} {n.label}
          </button>
        ))}
      </div>

      {/* ── FRIENDS / PARTY ── */}
      {subView==="friends" && (
        <div>
          {/* My card + share instructions */}
          <div style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:12,padding:".85rem 1rem",marginBottom:"1rem"}}>
            <div style={{display:"flex",alignItems:"center",gap:".6rem",marginBottom:".6rem"}}>
              <div style={{width:38,height:38,borderRadius:9,background:`${cls?.color||"#c9a84c"}22`,border:`2px solid ${cls?.color||"#c9a84c"}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.25rem",flexShrink:0}}>
                {cls?.icon||"⚔️"}
              </div>
              <div>
                <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,color:"var(--gold)",fontSize:".9rem"}}>{character.displayName||myUsername}</div>
                <div style={{fontSize:".7rem",color:"var(--text2)"}}>Lv.{level} {cls?.name||"Adventurer"} · @{myUsername}</div>
              </div>
            </div>
            {/* Share username */}
            <div style={{background:"rgba(201,168,76,.07)",border:"1px solid var(--gold)33",borderRadius:8,padding:".5rem .75rem",marginBottom:".5rem"}}>
              <div style={{fontSize:".65rem",color:"var(--text2)",marginBottom:".25rem"}}>Your username — share this so others can find you:</div>
              <div style={{display:"flex",alignItems:"center",gap:".5rem"}}>
                <span style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontWeight:700,fontSize:".95rem",letterSpacing:".08em",flex:1}}>@{myUsername}</span>
                <button onClick={()=>{ navigator.clipboard?.writeText(myUsername); showToast("Username copied!"); }}
                  style={{padding:".3rem .7rem",background:"var(--gold)",border:"none",borderRadius:6,color:"#000",fontFamily:"'Cinzel',serif",fontSize:".7rem",fontWeight:700,cursor:"pointer"}}>
                  Copy
                </button>
              </div>
            </div>
            <div style={{fontSize:".65rem",color:"var(--text2)",lineHeight:1.5,opacity:.8}}>
              📋 Both players must be using the <strong style={{color:"var(--text)"}}>same Forged artifact</strong>. Share the artifact link + your username with a friend, then search for each other in the Find tab.
            </div>
          </div>

          {/* Pending requests */}
          {requests.length>0 && (
            <div style={{marginBottom:"1rem"}}>
              <div style={{fontFamily:"'Cinzel',serif",fontSize:".68rem",color:"var(--gold)",textTransform:"uppercase",letterSpacing:".06em",marginBottom:".5rem"}}>
                Requests ({requests.length})
              </div>
              {requests.map(req=>(
                <div key={req.from} style={{background:"var(--surface)",border:"1px solid #c9a84c44",borderRadius:11,padding:".7rem .9rem",marginBottom:".45rem"}}>
                  <div style={{display:"flex",alignItems:"center",gap:".6rem",marginBottom:".5rem"}}>
                    <span style={{fontSize:"1.2rem"}}>{req.profile?.cls?.icon||"⚔️"}</span>
                    <div>
                      <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:".82rem",color:"var(--gold)"}}>{req.profile?.displayName||req.from}</div>
                      <div style={{fontSize:".68rem",color:"var(--text2)"}}>Lv.{req.profile?.level||"?"} {req.profile?.cls?.name||"Adventurer"}</div>
                    </div>
                  </div>
                  <div style={{display:"flex",gap:".4rem"}}>
                    <button onClick={()=>acceptRequest(req)}
                      style={{flex:1,padding:".38rem",background:"#0d1a0d",border:"1px solid #27ae6066",borderRadius:8,color:"#27ae60",fontSize:".72rem",fontFamily:"'Cinzel',serif",cursor:"pointer"}}>✓ Accept</button>
                    <button onClick={()=>declineRequest(req)}
                      style={{flex:1,padding:".38rem",background:"rgba(231,76,60,.08)",border:"1px solid #e74c3c44",borderRadius:8,color:"#e74c3c",fontSize:".72rem",cursor:"pointer"}}>Decline</button>
                  </div>
                </div>
              ))}
            </div>
          )}

          {/* Friends list */}
          <div style={{fontFamily:"'Cinzel',serif",fontSize:".68rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em",marginBottom:".5rem"}}>
            Party ({friends.length})
          </div>
          {friends.length===0
            ? <div style={{textAlign:"center",color:"var(--text2)",fontSize:".82rem",padding:"2rem 1rem",fontStyle:"italic"}}>No party members yet. Use Find to search by username.</div>
            : friends.map(f=><GuildFriendCard key={f.username} username={f.username} profile={f.profile} onMessage={u=>{setComposeFor(u);setSubView("compose");}} onRemove={removeFriend}/>)
          }

          {/*
            ── RAIDS (COMING SOON) ──────────────────────────────────────────────
            Design notes for when this gets built:

            MECHANIC: Turn-based async raids via shared storage.
              - Host creates a raid, picks boss type, invites friends by username.
              - Raid stored as shared:  raid:<raidId>  →  {
                  id, hostUsername, type, boss, maxHP, currentHP,
                  status: "open"|"active"|"victory"|"expired",
                  participants: [{ username, dmgDealt, turns, lastTurn }],
                  log: [{ username, dmg, ts, isCrit }],
                  createdAt, expiresAt (7 days), lootRolled: bool
                }
              - Each participant reads the raid from shared storage, takes their
                turn (attacks once, damage based on their own character stats),
                writes updated HP + log entry back. Optimistic locking: read → modify → write.
              - Boss HP persists across all participants. Anyone can check in anytime.
              - Raid expires after 7 days — mark status "expired", no loot.

            RAID TYPES (all 4 requested):
              1. Weekly Boss  — uses current WEEKLY_BOSSES[weekNum % len] entry.
                               HP scales to avg party level. Changes weekly.
              2. Dungeon Boss — host picks any of the 10 dungeons; uses that dungeon's
                               floor 10 final boss (isFinalBoss:true). Good for farming.
              3. Special Raid Creatures — unique bosses not found in solo dungeons.
                               Mythic-tier creatures with massive HP pools.
                               e.g. "The Primordial Forge", "Aether Leviathan", "The Null God"
                               Should live in a RAID_BOSSES const array near WEEKLY_BOSSES.
              4. World Event Raid — one special boss tied to getCurrentEvent().
                               Higher goldMult/xpMult based on event. Resets weekly.

            LOOT: Everyone gets their own independent roll on victory.
              - Loot quality scales with contribution pct: dmgDealt / maxHP.
              - ≥50% contribution → rollRarity(isFinalBoss:true, isFloorBoss:true, cha)
              - ≥20% contribution → rollRarity(false, true, cha)
              - <20% contribution → rollRarity(false, false, cha)
              - Loot pool: use host's dungeon lootPool for dungeon bosses;
                           use any dungeon's lootPool for weekly/event/special.
              - Each participant claims their loot via a "Claim" button that writes
                to their local inventory (stored locally, not shared).
              - lootRolled flag on raid prevents double-claiming.

            UI FLOW:
              Party tab → "⚔️ Raids" section → list of active raids you're in or invited to.
              "Create Raid" button → pick type → pick boss → invite friends from party list.
              Raid card shows: boss name/icon, HP bar (current/max), participant avatars,
              turn log (last 5 entries), "Take Your Turn" button (disabled if already took
              turn this round, or if raid is over).
              Victory screen: show all participants + dmg dealt + loot rolls.

            STORAGE KEYS:
              shared: raid:<raidId>           → full raid object (see above)
              shared: raids:user:<username>   → [raidId, ...] list of raids this user is in
              local:  raidLoot:<raidId>       → claimed loot for this user (prevents re-claim)
          */}

          {/* ── RAIDS COMING SOON BUTTON ── */}
          <div style={{marginTop:"1.25rem",padding:"1rem",background:"linear-gradient(135deg,#0d0d1a,#1a1a2e)",border:"1px dashed #8e44ad66",borderRadius:14,textAlign:"center"}}>
            <div style={{fontSize:"1.6rem",marginBottom:".4rem"}}>⚔️</div>
            <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:".9rem",color:"#8e44ad",marginBottom:".25rem"}}>Guild Raids</div>
            <div style={{fontSize:".72rem",color:"var(--text2)",marginBottom:".75rem",lineHeight:1.45}}>
              Team up with your party to take down powerful bosses together. Weekly bosses, dungeon lords, world event raids, and mythic creatures.
            </div>
            <div style={{display:"inline-block",padding:".4rem 1.1rem",background:"rgba(142,68,173,.12)",border:"1px solid #8e44ad44",borderRadius:20,color:"#8e44ad",fontFamily:"'Cinzel',serif",fontSize:".72rem",letterSpacing:".06em",fontWeight:700}}>
              🔮 Coming Soon
            </div>
          </div>
        </div>
      )}

      {/* ── MESSAGES ── */}
      {subView==="messages" && (
        <div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:".7rem"}}>
            <div style={{fontFamily:"'Cinzel',serif",fontSize:".68rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em"}}>Inbox ({inbox.length})</div>
            {unread>0 && <button onClick={markAllRead} style={{background:"none",border:"none",color:"var(--gold)",fontSize:".72rem",cursor:"pointer"}}>Mark all read</button>}
          </div>
          {inbox.length===0
            ? <div style={{textAlign:"center",color:"var(--text2)",fontSize:".82rem",padding:"2rem 1rem",fontStyle:"italic"}}>No messages yet.</div>
            : inbox.map((msg,i)=>(
              <div key={i} style={{
                background:msg.read?"var(--surface)":"linear-gradient(135deg,#1a1400,#231d00)",
                border:`1px solid ${msg.read?"var(--border)":"var(--gold)44"}`,
                borderRadius:12,padding:".75rem 1rem",marginBottom:".5rem",position:"relative"
              }}>
                {!msg.read && <div style={{position:"absolute",top:10,right:10,width:7,height:7,borderRadius:"50%",background:"var(--gold)"}}/>}
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:".3rem"}}>
                  <span style={{fontFamily:"'Cinzel',serif",fontSize:".78rem",fontWeight:700,color:msg.read?"var(--text)":"var(--gold)"}}>@{msg.from}</span>
                  <span style={{fontSize:".63rem",color:"var(--text2)"}}>{timeAgo(msg.ts)}</span>
                </div>
                <div style={{fontSize:".82rem",color:"var(--text)",lineHeight:1.45}}>{msg.text}</div>
                <div style={{display:"flex",gap:".4rem",marginTop:".5rem"}}>
                  {isFriend(msg.from) && (
                    <button onClick={()=>{ setComposeFor(msg.from); setSubView("compose"); }}
                      style={{fontSize:".68rem",padding:".28rem .6rem",background:"rgba(39,174,96,.1)",border:"1px solid #27ae6044",borderRadius:7,color:"#27ae60",cursor:"pointer"}}>Reply</button>
                  )}
                  <button onClick={()=>deleteMsg(i)}
                    style={{fontSize:".68rem",padding:".28rem .6rem",background:"rgba(231,76,60,.08)",border:"1px solid #e74c3c33",borderRadius:7,color:"#e74c3c",cursor:"pointer"}}>Delete</button>
                </div>
              </div>
            ))
          }
        </div>
      )}

      {/* ── COMPOSE ── */}
      {subView==="compose" && (
        <div>
          <button onClick={()=>setSubView("friends")} style={{background:"none",border:"none",color:"var(--gold)",fontSize:".8rem",cursor:"pointer",marginBottom:".75rem"}}>← Back</button>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:".85rem",color:"var(--gold)",marginBottom:".75rem"}}>
            Message to @{composeFor}
          </div>
          <textarea value={msgText} onChange={e=>setMsgText(e.target.value)} maxLength={280}
            placeholder="Write your message..."
            style={{width:"100%",minHeight:90,padding:".7rem",boxSizing:"border-box",background:"var(--surface)",border:"1px solid var(--border)",borderRadius:10,color:"var(--text)",fontSize:".84rem",resize:"none",fontFamily:"inherit",outline:"none"}}
          />
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:".4rem"}}>
            <span style={{fontSize:".68rem",color:"var(--text2)"}}>{msgText.length}/280</span>
            <button onClick={sendMessage}
              style={{padding:".48rem 1.2rem",background:"linear-gradient(135deg,var(--gold),var(--gold2))",border:"none",borderRadius:9,color:"#000",fontFamily:"'Cinzel',serif",fontSize:".8rem",fontWeight:700,cursor:"pointer"}}>
              Send ⚔️
            </button>
          </div>
        </div>
      )}

      {/* ── SEARCH ── */}
      {subView==="search" && (
        <div>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:".68rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em",marginBottom:".6rem"}}>Find by Username</div>
          {/* How it works */}
          <div style={{background:"rgba(201,168,76,.06)",border:"1px solid var(--gold)22",borderRadius:9,padding:".6rem .75rem",marginBottom:".75rem",fontSize:".7rem",color:"var(--text2)",lineHeight:1.6}}>
            <strong style={{color:"var(--gold)"}}>How to add a friend:</strong><br/>
            1. Share this artifact link with them<br/>
            2. Both set a username in your profile<br/>
            3. Search for each other here
            <div style={{marginTop:".4rem"}}>
              <button onClick={()=>{ navigator.clipboard?.writeText(window.location.href); showToast("Artifact link copied!"); }}
                style={{width:"100%",padding:".38rem",background:"var(--surface)",border:"1px solid var(--gold)44",borderRadius:7,color:"var(--gold)",fontFamily:"'Cinzel',serif",fontSize:".72rem",cursor:"pointer"}}>
                📋 Copy Artifact Link
              </button>
            </div>
          </div>
          <div style={{display:"flex",gap:".45rem",marginBottom:".85rem"}}>
            <input value={searchQ} onChange={e=>{ setSearchQ(e.target.value); setSearchResult(null); }}
              onKeyDown={e=>e.key==="Enter"&&handleSearch()}
              placeholder="Enter exact username..."
              style={{flex:1,padding:".58rem .75rem",background:"var(--surface)",border:"1px solid var(--border)",borderRadius:9,color:"var(--text)",fontSize:".84rem",outline:"none"}}
            />
            <button onClick={()=>handleSearch()}
              style={{padding:".58rem .9rem",background:"#1a1200",border:"1px solid var(--gold)",borderRadius:9,color:"var(--gold)",fontFamily:"'Cinzel',serif",fontSize:".78rem",cursor:"pointer"}}>
              Search
            </button>
          </div>
          {searchResult==="loading" && <div style={{textAlign:"center",color:"var(--text2)",padding:"1rem",fontSize:".82rem"}}>Searching...</div>}
          {searchResult==="not_found" && <div style={{textAlign:"center",color:"var(--text2)",padding:"1rem",fontSize:".82rem",fontStyle:"italic"}}>No adventurer found. Usernames are case-sensitive.</div>}
          {searchResult==="self" && <div style={{textAlign:"center",color:"var(--text2)",padding:"1rem",fontSize:".82rem",fontStyle:"italic"}}>That's you!</div>}
          {searchResult && typeof searchResult==="object" && (
            <div style={{background:"var(--surface)",border:`1px solid ${searchResult.profile?.cls?.color||"var(--border)"}44`,borderRadius:14,padding:".85rem 1rem"}}>
              <div style={{display:"flex",alignItems:"center",gap:".7rem",marginBottom:".65rem"}}>
                <div style={{width:42,height:42,borderRadius:10,background:`${searchResult.profile?.cls?.color||"#c9a84c"}22`,border:`2px solid ${searchResult.profile?.cls?.color||"#c9a84c"}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.3rem",flexShrink:0}}>
                  {searchResult.profile?.cls?.icon||"⚔️"}
                </div>
                <div>
                  <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:".9rem",color:searchResult.profile?.cls?.color||"var(--gold)"}}>
                    {searchResult.profile?.displayName||searchResult.username}
                  </div>
                  <div style={{fontSize:".7rem",color:"var(--text2)"}}>Lv.{searchResult.profile?.level||"?"} {searchResult.profile?.cls?.name||"Adventurer"}</div>
                  <GuildDungeonBar profile={searchResult.profile}/>
                </div>
              </div>
              {isFriend(searchResult.username)
                ? <div style={{textAlign:"center",fontSize:".75rem",color:"#27ae60",padding:".3rem"}}>✓ Already in your party</div>
                : <button onClick={()=>sendRequest(searchResult.username)}
                    style={{width:"100%",padding:".48rem",background:"linear-gradient(135deg,#1a1200,#2a2000)",border:"1px solid var(--gold)55",borderRadius:9,color:"var(--gold)",fontFamily:"'Cinzel',serif",fontSize:".78rem",cursor:"pointer"}}>
                    ⚔️ Send Friend Request
                  </button>
              }
            </div>
          )}
        </div>
      )}

      {/* ── LEADERBOARD ── */}
      {subView === "leaderboard" && (
        <LeaderboardView character={character}/>
      )}
    </div>
  );
}

// ─── CHARACTER TAB ────────────────────────────────────────────────────────────
function CharacterTab({ character, onEquip, onUnequip, onSellItem, onAllocateStat, onAvatarClick, onClearNew }) {
  const [view, setView]         = useState("equip");
  const [modal, setModal]       = useState(null);
  const [activeSlot, setActiveSlot] = useState(null);
  const level = xpToLevel(character.xp);
  const curXP = character.xp - xpForLevel(level);
  const nxtXP = xpForNext(level) - xpForLevel(level);

  // Scroll to top when switching equipment/stats/inventory/guild tabs
  useEffect(() => { scrollTabTop(); }, [view]);

  // Stats grow through leveling only — gear no longer contributes
  function clsBonus(stat) {
    return (character.cls?.statBonuses||[]).filter(b=>b.stat===stat).reduce((s,b)=>s+b.amt,0);
  }
  const alloc = character.allocatedStats || {};
  const charStats = {
    Strength:     8 + clsBonus("strength")     + Math.floor(level*0.8) + (alloc.strength||0),
    Dexterity:    8 + clsBonus("dexterity")    + Math.floor(level*0.7) + (alloc.dexterity||0),
    Intelligence: 8 + clsBonus("intelligence") + Math.floor(level*0.5) + (alloc.intelligence||0),
    Constitution: 8 + clsBonus("constitution") + Math.floor(level*0.9) + (alloc.constitution||0),
    Fortune:     5 + clsBonus("fortune")     + Math.floor(level*0.3) + (alloc.fortune||0),
  };
  const gc = gearCombatStats(character.equipped);

  function openSlot(slot) { setActiveSlot(s => s===slot?null:slot); setModal(null); }
  function openItem(item, fromInv) { setModal({ item, fromInventory:fromInv }); if(onClearNew) onClearNew(item.id); }
  function doEquip() { if(!modal)return; onEquip(modal.item); setModal(null); }
  function doSell(action)  {
    if(!modal)return;
    if(action === "unequip") { onUnequip(modal.item.slot); setModal(null); return; }
    onSellItem(modal.item); setModal(null);
  }
  // Ring items appear in both ring slots' inventory lists
  const invForSlot = slot => character.inventory.filter(i => i.slot === slot);

  function getEquippedForSlot(slot) {
    return character.equipped[slot] || null;
  }

  return (
    <div>
      <div className="char-header">
        <div className="char-avatar" style={{borderColor:character.cls?.color, cursor:"pointer", overflow:"hidden", padding:0}} onClick={onAvatarClick}><img src="data:image/png;base64," alt="Hero" style={{width:"100%",height:"100%",objectFit:"cover",imageRendering:"pixelated"}}/></div>
        <div style={{flex:1}}>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:"1.2rem"}}>{character.displayName}</div>
          <div style={{fontSize:".9rem",fontWeight:600,color:character.cls?.color}}>{character.cls?.name}</div>
          <div style={{fontSize:".8rem",color:"var(--text2)"}}>Level {level}</div>
        </div>
        <div style={{textAlign:"right",fontSize:".82rem",display:"flex",flexDirection:"column",gap:".25rem"}}>
          <span>❤️ {50+charStats.Constitution*8+level*10+(gc.hp||0)} HP</span>
          {character.equipped?.weapon && (
            <span style={{color:"#e74c3c",fontWeight:600}}>⚔️ {character.equipped.weapon.dmg} {((character.equipped.weapon.dmgTypes||["melee"])[0]||"melee").charAt(0).toUpperCase()+((character.equipped.weapon.dmgTypes||["melee"])[0]||"melee").slice(1)}</span>
          )}
          <span style={{color:"var(--gold)"}}>💰 {character.gold.toLocaleString()}</span>
        </div>
      </div>
      <div style={{marginBottom:"1.25rem"}}>
        <div style={{display:"flex",justifyContent:"space-between",fontSize:".8rem",color:"var(--text2)",marginBottom:".3rem"}}><span>Workout XP</span><span>{curXP}/{nxtXP}</span></div>
        <div className="xp-track"><div className="xp-fill" style={{width:`${Math.min(100,(curXP/nxtXP)*100)}%`}}/></div>
      </div>
      <div className="char-vtabs">
        {[["equip","Equipment"],["stats","Stats"],["inventory",`Inventory (${character.inventory.length})`],["guild","Guild 👥"]].map(([v,l]) => (
          <button key={v} className={`cvtab ${view===v?"active":""}`} onClick={() => { setView(v); setActiveSlot(null); setModal(null); }}>
            {l}
            {v==="stats" && (character.statPoints||0)>0 && (
              <span style={{marginLeft:".3rem",background:"var(--gold)",color:"#000",borderRadius:"50%",width:16,height:16,fontSize:".65rem",fontWeight:900,display:"inline-flex",alignItems:"center",justifyContent:"center"}}>
                {character.statPoints}
              </span>
            )}
          </button>
        ))}
      </div>

      {view==="equip" && (
        <div>
          <div className="equip-layout">
            <div className="eslot-col">
              {["weapon","head","body","feet"].map(slot => (
                <div key={slot} className={`eslot ${character.equipped[slot]?"filled":""} ${activeSlot===slot?"selected":""}`}
                  onClick={() => character.equipped[slot] ? openItem(character.equipped[slot], true) : openSlot(slot)}>
                  <div className="eslot-label">{SLOT_LABELS[slot]}</div>
                  {character.equipped[slot]
                    ? <><GearIcon name={character.equipped[slot].name} size={28} rarity={character.equipped[slot].rarity}/>
                        <div style={{fontSize:".65rem",lineHeight:1.2,marginTop:".1rem"}}>{character.equipped[slot].name}</div>
                        <div style={{fontSize:".6rem",color:RARITY_COLORS[character.equipped[slot].rarity],fontWeight:700}}>{character.equipped[slot].rarity}</div></>
                    : <div style={{fontSize:"1.1rem",opacity:.3,lineHeight:1,overflow:"hidden"}}>{SLOT_ICONS[slot]}</div>}
                </div>
              ))}
            </div>
            <div className="equip-center">
              <div className="char-portrait" style={{borderColor:character.cls?.color||"var(--gold)",padding:".5rem .25rem"}}>
                <HeroSprite cls={character.cls} isHit={false} character={character}/>
                <div style={{fontSize:".7rem",color:"var(--text2)",marginTop:".3rem",textAlign:"center"}}>{character.displayName}</div>
                <div style={{fontSize:".85rem",fontWeight:700,fontFamily:"'Cinzel',serif",color:character.cls?.color}}>Lv.{level}</div>
              </div>
            </div>
            <div className="eslot-col">
              {["hands","necklace","ring","offhand"].map(slot => (
                <div key={slot} className={`eslot ${character.equipped[slot]?"filled":""} ${activeSlot===slot?"selected":""}`}
                  onClick={() => character.equipped[slot] ? openItem(character.equipped[slot], true) : openSlot(slot)}>
                  <div className="eslot-label">{SLOT_LABELS[slot]}</div>
                  {character.equipped[slot]
                    ? <><GearIcon name={character.equipped[slot].name} size={28} rarity={character.equipped[slot].rarity}/>
                        <div style={{fontSize:".65rem",lineHeight:1.2,marginTop:".1rem"}}>{character.equipped[slot].name}</div>
                        <div style={{fontSize:".6rem",color:RARITY_COLORS[character.equipped[slot].rarity],fontWeight:700}}>{character.equipped[slot].rarity}</div></>
                    : <div style={{fontSize:"1.1rem",opacity:.3,lineHeight:1,overflow:"hidden"}}>{SLOT_ICONS[slot]}</div>}
                </div>
              ))}
            </div>
          </div>
          {activeSlot && (
            <div className="slot-panel">
              <div className="sp-header">
                <span>{SLOT_ICONS[activeSlot]} {SLOT_LABELS[activeSlot]}</span>
                <button className="btn-x" onClick={() => setActiveSlot(null)}>✕</button>
              </div>

              {character.equipped[activeSlot] ? (
                <div className="sp-equipped">
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:".4rem"}}>
                    <div style={{display:"flex",alignItems:"center",gap:".4rem"}}><GearIcon name={character.equipped[activeSlot].name} size={24} rarity={character.equipped[activeSlot].rarity}/><span style={{fontWeight:600}}>{character.equipped[activeSlot].name}</span></div>
                    <span style={{color:RARITY_COLORS[character.equipped[activeSlot].rarity],fontSize:".75rem"}}>{character.equipped[activeSlot].rarity}</span>
                  </div>
                  <div style={{display:"flex",flexWrap:"wrap",gap:".4rem",marginBottom:".5rem"}}>
                    {Object.entries(character.equipped[activeSlot].stats).map(([k,v]) => {
                      const lbl = {hp:"HP",dodge:"Dodge%",crit:"Crit%",magicDmg:"Magic+",strength:"STR",dexterity:"DEX",intelligence:"INT",constitution:"CON",fortune:"Fortune"}[k]||k;
                      const suf = {dodge:"%",crit:"%"}[k]||"";
                      return <span key={k} style={{fontSize:".8rem",color:sc(v)}}>{lbl} {v>0?`+${v}`:v}{suf}</span>;
                    })}
                  </div>
                  <div style={{display:"flex",gap:".5rem"}}>
                    <button className="btn-detail" onClick={() => openItem(character.equipped[activeSlot], false)}>Details</button>
                    <button className="btn-unequip" onClick={() => onUnequip(activeSlot)}>Unequip</button>
                  </div>
                </div>
              ) : <p style={{color:"var(--text2)",fontSize:".85rem",fontStyle:"italic",marginBottom:".75rem"}}>Slot is empty.</p>}

              <div style={{fontSize:".75rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".05em",marginBottom:".4rem"}}>Available Items</div>
              {invForSlot(activeSlot).length===0
                ? <p style={{color:"var(--text2)",fontSize:".85rem",fontStyle:"italic"}}>No items for this slot.</p>
                : invForSlot(activeSlot).map(item => (
                  <div key={item.id} className="sp-inv-item" style={{borderLeftColor:RARITY_COLORS[item.rarity]}} onClick={() => openItem(item, true)}>
                    <div style={{display:"flex",alignItems:"center",gap:".4rem"}}><GearIcon name={item.name} size={20} rarity={item.rarity}/><span>{item.name}</span></div>
                    <span style={{color:RARITY_COLORS[item.rarity],fontSize:".75rem"}}>{item.rarity}</span>
                  </div>
                ))}
            </div>
          )}
        </div>
      )}

      {view==="stats" && (
        <div>
          {/* Unspent stat points banner */}
          {(character.statPoints||0) > 0 && (
            <div style={{background:"linear-gradient(135deg,#7f4f00,#c9860a)",borderRadius:"var(--radius)",padding:".75rem 1rem",marginBottom:"1rem",display:"flex",alignItems:"center",gap:".75rem"}}>
              <span style={{fontSize:"1.5rem"}}>⭐</span>
              <div>
                <div style={{fontFamily:"'Cinzel',serif",color:"#fff",fontWeight:700,fontSize:".95rem"}}>
                  {character.statPoints} Stat Point{character.statPoints!==1?"s":""} Available
                </div>
                <div style={{fontSize:".78rem",color:"rgba(255,255,255,.75)"}}>Tap + to invest in a stat</div>
              </div>
            </div>
          )}

          {/* Stat rows with + button */}
          {[
            ["Strength",    "strength",     "⚔️", "Melee damage"],
            ["Dexterity",   "dexterity",    "🏹", "Ranged dmg · Dodge · Crit"],
            ["Intelligence","intelligence", "🔮", "Magic damage"],
            ["Constitution","constitution", "⚡", "Max HP · Max Stamina (+0.5 per point)"],
            ["Fortune",    "fortune",     "✨", "Loot luck · Discount"],
          ].map(([label, key, icon, hint]) => {
            const val     = charStats[label];
            const alloc   = (character.allocatedStats||{})[key] || 0;
            const canAdd  = (character.statPoints||0) > 0;
            return (
              <div key={key} style={{display:"flex",alignItems:"center",gap:".6rem",padding:".6rem 0",borderBottom:"1px solid var(--border)"}}>
                <span style={{fontSize:"1.2rem",width:"24px",textAlign:"center"}}>{icon}</span>
                <div style={{flex:1}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:".3rem"}}>
                    <span style={{fontSize:".88rem",fontWeight:600}}>{label}</span>
                    <div style={{display:"flex",alignItems:"center",gap:".4rem"}}>
                      {alloc > 0 && (
                        <span style={{fontSize:".68rem",color:"var(--gold)",background:"var(--gold)22",borderRadius:"10px",padding:".1rem .4rem"}}>+{alloc} pts</span>
                      )}
                      <span style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontWeight:700,fontSize:".95rem"}}>{val}</span>
                    </div>
                  </div>
                  <div style={{height:5,background:"var(--surface2)",borderRadius:3,overflow:"hidden"}}>
                    <div style={{height:"100%",borderRadius:3,background:"linear-gradient(90deg,var(--gold),var(--gold2))",width:`${Math.min(100,(val/60)*100)}%`,transition:"width .3s"}}/>
                  </div>
                  <div style={{fontSize:".7rem",color:"var(--text2)",marginTop:".2rem"}}>{hint}</div>
                </div>
                <button
                  onClick={() => onAllocateStat(key)}
                  disabled={!canAdd}
                  style={{
                    width:32,height:32,borderRadius:"50%",border:"none",
                    background:canAdd?"linear-gradient(135deg,var(--gold),var(--gold2))":"var(--surface2)",
                    color:canAdd?"#000":"var(--text2)",
                    fontWeight:900,fontSize:"1.1rem",cursor:canAdd?"pointer":"not-allowed",
                    flexShrink:0,display:"flex",alignItems:"center",justifyContent:"center",
                    transition:"all .2s",
                    boxShadow:canAdd?"0 2px 8px rgba(201,168,76,.4)":"none",
                  }}>+</button>
              </div>
            );
          })}

          <div style={{fontSize:".68rem",color:"var(--text2)",fontStyle:"italic",textAlign:"center",marginTop:".5rem",padding:".3rem .5rem",background:"rgba(255,255,255,.04)",borderRadius:6}}>
            ⚠️ Stat points are permanent — allocate carefully
          </div>

          {/* Derived stats */}
          <div className="derived-grid" style={{marginTop:"1rem"}}>
            <div className="dstat"><span>Max HP</span><strong>{50+charStats.Constitution*8+level*10+(gc.hp||0)}</strong></div>
            <div className="dstat"><span>⚡ Max Stamina</span><strong>{20+Math.floor((8+(character.cls?.statBonuses||[]).filter(b=>b.stat==="constitution").reduce((s,b)=>s+b.amt,0)+Math.floor(level*0.9)+(character.allocatedStats?.constitution||0))*0.5)}</strong></div>
            <div className="dstat"><span>Dodge</span><strong>{Math.min(30,(charStats.Dexterity*0.2+(gc.dodge||0)*0.5)).toFixed(1)}%</strong></div>
            <div className="dstat"><span>Crit</span><strong>{(charStats.Dexterity*0.6+(gc.crit||0)).toFixed(1)}%</strong></div>
            <div className="dstat"><span>Magic+</span><strong>+{gc.magicDmg||0}</strong></div>
            <div className="dstat"><span>Discount</span><strong>{Math.min(40,charStats.Fortune*0.5).toFixed(1)}%</strong></div>
          </div>
        </div>
      )}

      {view==="inventory" && (
        <div>
          <div className="inv-consumables">
            <span>💰 {character.gold.toLocaleString()} Gold</span>
            {Object.entries(character.potions||{}).filter(([,v])=>v>0).map(([k,v]) => (
              <span key={k}>{POTION_TYPES[k]?.icon||"🧪"} {POTION_TYPES[k]?.name||k} ×{v}</span>
            ))}
            {Object.values(character.potions||{}).every(v=>v===0) && <span style={{color:"var(--text2)"}}>No potions</span>}
          </div>
          {character.inventory.length===0
            ? <div className="inv-empty-state"><span style={{fontSize:"3rem"}}>🎒</span><p>No items yet.</p><p style={{fontSize:".85rem",color:"var(--text2)"}}>Complete workouts to unlock dungeons, then fight for loot!</p></div>
            : <div className="inv-grid">
                {character.inventory.map(item => {
                  const isEq = character.equipped[item.slot]?.id === item.id;
                  return (
                    <div key={item.id} className="inv-grid-card" style={{borderColor:RARITY_COLORS[item.rarity]}} onClick={() => openItem(item, true)}>
                      {isEq && <div className="eq-badge">E</div>}
                      {(character.newItems||[]).includes(item.id) && <div className="eq-badge" style={{background:"#27ae60",right:"auto",left:".3rem"}}>NEW</div>}
                      <GearIcon name={item.name} size={36} rarity={item.rarity}/>
                      <div style={{fontSize:".82rem",fontWeight:600,lineHeight:1.2,marginTop:".2rem"}}>{item.name}</div>
                      <div style={{color:RARITY_COLORS[item.rarity],fontSize:".7rem",fontWeight:700,textTransform:"uppercase"}}>{item.rarity}</div>
                      <div style={{color:"var(--text2)",fontSize:".7rem"}}>{SLOT_LABELS[item.slot]}</div>
                      {item.dmg != null && <div style={{color:"#e74c3c",fontSize:".7rem",fontWeight:700}}>⚔️ {item.dmg} {(item.dmgTypes||["melee"])[0]}</div>}
                      <div style={{color:"var(--gold)",fontSize:".7rem"}}>💰 {sellValue(item)}g</div>
                    </div>
                  );
                })}
              </div>}
        </div>
      )}

      {view==="guild" && <GuildView character={character}/>}

      {modal && (
        <ItemModal item={modal.item} fromInventory={modal.fromInventory}
          currentlyEquipped={character.equipped[modal.item.slot]}
          onEquip={doEquip} onSellFromInventory={doSell}
          onClose={() => setModal(null)}/>
      )}
    </div>
  );
}


