const ACHIEVEMENT_RARITY_COLORS = {
  Common:"#95a5a6", Uncommon:"#27ae60", Rare:"#3498db", Epic:"#9b59b6", Legendary:"#c9a84c",
};

function computeEarnedAchievements(character) {
  const s = character;
  const level = xpToLevel(s.xp);
  const history = s.workoutHistory || [];
  const totalSets = history.reduce((sum,h) => sum+(h.exercises||[]).reduce((ss,e)=>ss+(e.sets||0),0),0);
  const totalWorkouts = history.filter(h => !h.isRestDay).length;
  const allLog = s.wellnessLog || [];
  const allItems = [...(s.inventory||[]), ...Object.values(s.equipped||{}).filter(Boolean)];
  const totalKills = s.sideQuestProgress?.sq_d03 || 0;
  const cleared = (s.clearedDungeons||[]).length;
  const wellnessStreak = (() => {
    let streak = 0; const d = new Date();
    for (let i=0;i<365;i++){
      const ds=new Date(d); ds.setDate(d.getDate()-i);
      const ds2=ds.toISOString().slice(0,10);
      if(new Set(allLog.filter(e=>e.date?.slice(0,10)===ds2).map(e=>e.type)).size>=2) streak++;
      else if(i>0) break;
    }
    return streak;
  })();
  const sleepRunOf7 = (() => {
    let run=0; const d=new Date();
    for(let i=0;i<30;i++){
      const ds=new Date(d); ds.setDate(d.getDate()-i);
      const sl=allLog.find(e=>e.type==="sleep"&&e.date?.slice(0,10)===ds.toISOString().slice(0,10));
      if(sl?.hrs>=8) run++; else if(i>0) break;
    }
    return run>=7;
  })();

  const checks = [
    ["first_workout",  totalWorkouts>=1],
    ["workouts_5",     totalWorkouts>=5],
    ["workouts_25",    totalWorkouts>=25],
    ["workouts_50",    totalWorkouts>=50],
    ["workouts_100",   totalWorkouts>=100],
    ["workouts_365",   totalWorkouts>=365],
    ["streak_7",       (s.bestStreak||0)>=7],
    ["streak_30",      (s.bestStreak||0)>=30],
    ["streak_100",     (s.bestStreak||0)>=100],
    ["heavy_first",    history.some(h=>h.hasHeavy)],
    ["sets_100",       totalSets>=100],
    ["sets_1000",      totalSets>=1000],
    ["sets_10000",     totalSets>=10000],
    ["rest_day",       history.some(h=>h.isRestDay)],
    ["dungeon_first",  Object.keys(s.floorClears||{}).length>0],
    ["kill_first",     (s.sideQuestProgress?.sq_d02||0)>=1],
    ["kills_50",       totalKills>=50],
    ["kills_250",      totalKills>=250],
    ["kills_1000",     totalKills>=1000],
    ["floor_first",    Object.values(s.floorClears||{}).some(f=>f.length>0)],
    ["dungeon_clear1", cleared>=1],
    ["dungeon_clear5", cleared>=5],
    ["dungeon_all",    cleared>=10],
    ["no_potion_boss", (s.sideQuestProgress?.sq_d16||0)>=1],
    ["first_item",     allItems.length>0],
    ["first_equip",    Object.keys(s.equipped||{}).length>0],
    ["rare_find",      allItems.some(i=>["Rare","Epic","Legendary","Mythic"].includes(i?.rarity))],
    ["epic_find",      allItems.some(i=>["Epic","Legendary","Mythic"].includes(i?.rarity))],
    ["legendary_find", allItems.some(i=>["Legendary","Mythic"].includes(i?.rarity))],
    ["mythic_find",    allItems.some(i=>i?.rarity==="Mythic")],
    ["full_gear",      Object.keys(s.equipped||{}).length>=8],
    ["level_5",        level>=5],
    ["level_10",       level>=10],
    ["level_25",       level>=25],
    ["level_50",       level>=50],
    ["level_100",      level>=100],
    ["gold_1000",      (s.gold||0)>=1000],
    ["gold_10000",     (s.gold||0)>=10000],
    ["alloc_all",      Object.values(s.allocatedStats||{}).reduce((a,b)=>a+b,0)>=20],
    ["checkin_first",  allLog.some(e=>e.type==="mood")],
    ["meditate_first", allLog.some(e=>e.type==="meditation")],
    ["wellness_7",     wellnessStreak>=7],
    ["wellness_30",    wellnessStreak>=30],
    ["sleep_great",    sleepRunOf7],
  ];

  const prevEarned = new Set(s.achievements||[]);
  const allEarned  = new Set(s.achievements||[]);
  const newlyEarned = [];
  checks.forEach(([id, cond]) => {
    if (cond) {
      allEarned.add(id);
      if (!prevEarned.has(id)) newlyEarned.push(id);
    }
  });
  return { allEarned, newlyEarned };
}


// ─── RIVAL SYSTEM ─────────────────────────────────────────────────────────────
// Local rivals — player creates them, system simulates their weekly XP.
// Rivals share your level range but train on a random schedule.

const RIVAL_TAUNTS = [
  "Think you can keep up?",
  "I've been training while you sleep.",
  "Your legend ends where mine begins.",
  "The dungeon fears me. Does it fear you?",
  "Every set you skip, I'm in the gym.",
  "Rest days are for the weak.",
  "I've cleared floors you haven't seen.",
  "Let's see who the iron respects.",
  "Your streak means nothing without results.",
  "I don't stop. Do you?",
];

const RIVAL_CLASSES = [
  { name:"Fighter",  icon:"⚔️",  color:"#e74c3c" },
  { name:"Ranger",   icon:"🏹",  color:"#27ae60" },
  { name:"Wizard",   icon:"🔮",  color:"#8e44ad" },
  { name:"Rogue",    icon:"🗡️",  color:"#2980b9" },
  { name:"Explorer", icon:"🧭",  color:"#d35400" },
  { name:"Nomad",    icon:"🌿",  color:"#7f8c8d" },
];

function generateRival(name, playerLevel) {
  const cls    = RIVAL_CLASSES[Math.floor(Math.random() * RIVAL_CLASSES.length)];
  const level  = Math.max(1, playerLevel + Math.floor(Math.random()*6) - 3);
  const taunt  = RIVAL_TAUNTS[Math.floor(Math.random() * RIVAL_TAUNTS.length)];
  // Simulate rival's XP earned this week (realistic range around player level)
  const baseWeeklyXP = 800 + level * 120;
  const variance     = Math.floor(baseWeeklyXP * 0.4);
  const weeklyXP     = baseWeeklyXP + Math.floor(Math.random() * variance * 2) - variance;
  const weekStr      = new Date().toISOString().slice(0,10).slice(0,7); // YYYY-MM
  return {
    id:        Date.now().toString(36) + Math.random().toString(36).slice(2,6),
    name,
    cls,
    level,
    taunt,
    weeklyXP:  Math.max(200, weeklyXP),
    weekKey:   weekStr,
    createdAt: new Date().toISOString(),
  };
}

// Get player's XP earned this week
function getPlayerWeeklyXP(character) {
  const weekStart = new Date();
  weekStart.setDate(weekStart.getDate() - weekStart.getDay()); // Sunday
  weekStart.setHours(0,0,0,0);
  return (character.workoutHistory||[])
    .filter(h => new Date(h.date) >= weekStart)
    .reduce((sum,h) => sum + (h.xp||0), 0);
}

function RivalCard({ rival, playerWeeklyXP, onRemove }) {
  const [showRemove, setShowRemove] = useState(false);
  const rc       = rival.cls?.color || "var(--gold)";
  const diff     = playerWeeklyXP - rival.weeklyXP;
  const winning  = diff >= 0;
  const diffAbs  = Math.abs(diff);
  const total    = Math.max(playerWeeklyXP, rival.weeklyXP, 100);
  const playerPct = Math.min(100, (playerWeeklyXP / total) * 100);
  const rivalPct  = Math.min(100, (rival.weeklyXP  / total) * 100);

  return (
    <div style={{
      background:"var(--surface)", borderRadius:12,
      border:`1px solid ${winning ? "#27ae6044" : "#e74c3c44"}`,
      padding:".85rem 1rem", position:"relative",
    }}>
      <div style={{display:"flex",alignItems:"center",gap:".65rem",marginBottom:".75rem"}}>
        <div style={{
          width:40,height:40,borderRadius:"50%",flexShrink:0,
          background:`${rc}22`,border:`2px solid ${rc}88`,
          display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.2rem",
        }}>{rival.cls?.icon}</div>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:".92rem"}}>{rival.name}</div>
          <div style={{fontSize:".7rem",color:rc,fontWeight:600}}>{rival.cls?.name} · Lv.{rival.level}</div>
        </div>
        <div style={{textAlign:"right",flexShrink:0}}>
          <div style={{
            fontSize:".7rem",fontWeight:700,fontFamily:"'Cinzel',serif",
            color: winning ? "#27ae60" : "#e74c3c",
          }}>
            {winning ? `▲ +${diffAbs.toLocaleString()} XP ahead` : `▼ ${diffAbs.toLocaleString()} XP behind`}
          </div>
          <div style={{fontSize:".62rem",color:"var(--text2)",marginTop:".1rem"}}>this week</div>
        </div>
      </div>

      {/* Head-to-head XP bars */}
      <div style={{marginBottom:".65rem"}}>
        <div style={{display:"flex",justifyContent:"space-between",fontSize:".65rem",color:"var(--text2)",marginBottom:".2rem"}}>
          <span>You — {playerWeeklyXP.toLocaleString()} XP</span>
          <span>{rival.name} — {rival.weeklyXP.toLocaleString()} XP</span>
        </div>
        <div style={{display:"flex",height:6,borderRadius:3,overflow:"hidden",gap:1,background:"var(--surface2)"}}>
          <div style={{width:`${playerPct}%`,background: winning?"#27ae60":"#e74c3c",borderRadius:"3px 0 0 3px",transition:"width .4s"}}/>
          <div style={{flex:1,background:winning?"#e74c3c33":"#e74c3c88",borderRadius:"0 3px 3px 0"}}/>
        </div>
      </div>

      {/* Rival's taunt */}
      <div style={{fontSize:".72rem",color:"var(--text2)",fontStyle:"italic",marginBottom:".5rem"}}>
        "{rival.taunt}"
      </div>

      {/* Remove */}
      {!showRemove ? (
        <button onClick={() => setShowRemove(true)} style={{
          background:"none",border:"none",color:"#666",fontSize:".65rem",
          cursor:"pointer",padding:0,textDecoration:"underline",
        }}>Remove rival</button>
      ) : (
        <div style={{display:"flex",gap:".4rem",marginTop:".25rem"}}>
          <button onClick={onRemove} style={{flex:1,padding:".3rem",background:"#e74c3c22",border:"1px solid #e74c3c66",borderRadius:6,color:"#e74c3c",fontSize:".72rem",cursor:"pointer",fontFamily:"'Cinzel',serif",fontWeight:700}}>Remove</button>
          <button onClick={() => setShowRemove(false)} style={{flex:1,padding:".3rem",background:"var(--surface2)",border:"1px solid var(--border)",borderRadius:6,color:"var(--text2)",fontSize:".72rem",cursor:"pointer"}}>Cancel</button>
        </div>
      )}
    </div>
  );
}

function RivalsSection({ character, onAddRival, onRemoveRival }) {
  const [adding,    setAdding]    = useState(false);
  const [rivalName, setRivalName] = useState("");
  const rivals       = character.rivals || [];
  const playerWeekXP = getPlayerWeeklyXP(character);
  const playerLevel  = xpToLevel(character.xp);

  function handleAdd() {
    if (!rivalName.trim()) return;
    const rival = generateRival(rivalName.trim(), playerLevel);
    onAddRival(rival);
    setRivalName("");
    setAdding(false);
  }

  return (
    <div style={{marginBottom:"1rem"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:".6rem"}}>
        <h3 style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontSize:".9rem",margin:0}}>⚔️ Rivals</h3>
        {rivals.length < 5 && (
          <button onClick={() => setAdding(a => !a)} style={{
            padding:".25rem .7rem",background:"var(--surface2)",border:"1px solid var(--border)",
            borderRadius:20,color:"var(--text2)",fontSize:".72rem",fontFamily:"'Cinzel',serif",
            cursor:"pointer",fontWeight:700,
          }}>{adding ? "Cancel" : "+ Add Rival"}</button>
        )}
      </div>

      {adding && (
        <div style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:12,padding:".85rem 1rem",marginBottom:".65rem"}}>
          <div style={{fontSize:".78rem",color:"var(--text2)",marginBottom:".5rem"}}>Enter your rival's name. They'll be generated at your level and compete for weekly XP.</div>
          <div style={{display:"flex",gap:".5rem"}}>
            <input
              value={rivalName}
              onChange={e => setRivalName(e.target.value)}
              onKeyDown={e => e.key==="Enter" && handleAdd()}
              placeholder="Rival's name..."
              style={{flex:1,background:"var(--surface2)",border:"1px solid var(--border)",borderRadius:8,padding:".5rem .75rem",color:"var(--text)",fontSize:".9rem"}}
            />
            <button onClick={handleAdd} disabled={!rivalName.trim()} style={{
              padding:".5rem 1rem",
              background: rivalName.trim() ? "linear-gradient(135deg,var(--gold),var(--gold2))" : "var(--surface2)",
              border:"none",borderRadius:8,color:rivalName.trim()?"#000":"var(--text2)",
              fontFamily:"'Cinzel',serif",fontSize:".82rem",fontWeight:700,cursor:rivalName.trim()?"pointer":"not-allowed",
            }}>Create</button>
          </div>
        </div>
      )}

      {rivals.length === 0 && !adding && (
        <div style={{textAlign:"center",padding:"1.25rem",color:"var(--text2)",fontSize:".82rem",fontStyle:"italic",background:"var(--surface)",borderRadius:12,border:"1px solid var(--border)"}}>
          No rivals yet. Add one to compete for weekly XP.
        </div>
      )}

      {rivals.length > 0 && (
        <div style={{marginBottom:".5rem",fontSize:".72rem",color:"var(--text2)",textAlign:"center"}}>
          Your XP this week: <span style={{color:"var(--gold)",fontWeight:700}}>{playerWeekXP.toLocaleString()}</span>
        </div>
      )}

      <div style={{display:"flex",flexDirection:"column",gap:".55rem"}}>
        {rivals.map(rival => (
          <RivalCard
            key={rival.id}
            rival={rival}
            playerWeeklyXP={playerWeekXP}
            onRemove={() => onRemoveRival(rival.id)}
          />
        ))}
      </div>
      {rivals.length > 0 && (
        <div style={{fontSize:".68rem",color:"var(--text2)",textAlign:"center",marginTop:".5rem",fontStyle:"italic"}}>
          Rival XP resets weekly · Train more to pull ahead
        </div>
      )}
    </div>
  );
}


// ─── WEEKLY RECAP ─────────────────────────────────────────────────────────────
// Shown every Sunday (or on demand from profile). Summarises the week.

function WeeklyRecapModal({ character, onClose }) {
  const weekStart = new Date();
  weekStart.setDate(weekStart.getDate() - weekStart.getDay());
  weekStart.setHours(0,0,0,0);

  const history   = (character.workoutHistory||[]);
  const thisWeek  = history.filter(h => new Date(h.date) >= weekStart && !h.isRestDay);
  const restDays  = history.filter(h => new Date(h.date) >= weekStart && h.isRestDay);
  const weekXP    = thisWeek.reduce((s,h) => s+(h.xp||0), 0);
  const weekSets  = thisWeek.reduce((s,h) => s+(h.exercises||[]).reduce((ss,e)=>ss+(e.sets||0),0), 0);
  const wellLog   = (character.wellnessLog||[]).filter(e => new Date(e.date) >= weekStart);
  const medMins   = wellLog.filter(e=>e.type==="meditation").reduce((s,e)=>s+(e.mins||0),0);
  const avgSleep  = (() => {
    const sleepLogs = wellLog.filter(e=>e.type==="sleep");
    if (!sleepLogs.length) return null;
    return (sleepLogs.reduce((s,e)=>s+(e.hrs||0),0)/sleepLogs.length).toFixed(1);
  })();
  const level     = xpToLevel(character.xp);
  const streak    = character.workoutStreak || 0;

  // Best lift this week
  const bestLift = (() => {
    let best = null;
    thisWeek.forEach(h => (h.exercises||[]).forEach(ex => {
      if (ex.weight && ex.weight !== "bodyweight" && parseFloat(ex.weight) > 0) {
        if (!best || parseFloat(ex.weight) > parseFloat(best.weight))
          best = { name:ex.name, weight:ex.weight };
      }
    }));
    return best;
  })();

  const dayNames = ["Sun","Mon","Tue","Wed","Thu","Fri","Sat"];
  const dayActivity = Array.from({length:7}, (_,i) => {
    const d = new Date(weekStart); d.setDate(d.getDate()+i);
    const ds = d.toISOString().slice(0,10);
    const trained = history.some(h => h.date?.slice(0,10)===ds && !h.isRestDay);
    const rested  = history.some(h => h.date?.slice(0,10)===ds && h.isRestDay);
    return { day:dayNames[i], trained, rested };
  });

  const tone = weekXP >= 2000 ? "great" : weekXP >= 800 ? "good" : weekXP > 0 ? "ok" : "miss";
  const toneMsg = {
    great: "Outstanding week. The dungeon trembles.",
    good:  "Solid effort. Keep building momentum.",
    ok:    "A start. Next week, push harder.",
    miss:  "The iron waited for you. Answer it next week.",
  }[tone];
  const toneBg = {
    great:"linear-gradient(135deg,#0a1a0a,#0d250d)",
    good: "linear-gradient(135deg,#0a1200,#0f1a00)",
    ok:   "linear-gradient(135deg,#1a1200,#251800)",
    miss: "linear-gradient(135deg,#1a0800,#250d00)",
  }[tone];
  const toneColor = { great:"#27ae60", good:"#2ecc71", ok:"#f39c12", miss:"#e74c3c" }[tone];

  return (
    <div style={{position:"fixed",inset:0,zIndex:300,background:"rgba(0,0,0,.85)",
      display:"flex",flexDirection:"column",justifyContent:"flex-end"}}
      onClick={onClose}>
      <div style={{background:"var(--bg)",borderRadius:"20px 20px 0 0",
        border:"1px solid var(--border)",borderBottom:"none",
        maxHeight:"92vh",overflowY:"auto",animation:"slideUp .25s ease"}}
        onClick={e=>e.stopPropagation()}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"1rem 1rem .25rem"}}>
          <span style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontSize:"1.1rem",fontWeight:700}}>Weekly Recap</span>
          <button onClick={onClose} style={{background:"none",border:"none",color:"var(--text2)",fontSize:"1.4rem",cursor:"pointer",lineHeight:1}}>×</button>
        </div>
        <div style={{padding:"0 1rem 2rem"}}>

          {/* Tone banner */}
          <div style={{background:toneBg,border:`1px solid ${toneColor}44`,borderRadius:12,
            padding:"1rem",textAlign:"center",marginBottom:"1rem"}}>
            <div style={{fontFamily:"'Cinzel',serif",fontSize:"1rem",fontWeight:700,color:toneColor,marginBottom:".25rem"}}>
              {new Date(weekStart).toLocaleDateString("en-US",{month:"long",day:"numeric"})} — {new Date().toLocaleDateString("en-US",{month:"long",day:"numeric"})}
            </div>
            <div style={{fontSize:".85rem",color:"var(--text2)",fontStyle:"italic"}}>{toneMsg}</div>
          </div>

          {/* Day activity strip */}
          <div style={{display:"flex",gap:".3rem",marginBottom:"1rem",justifyContent:"space-between"}}>
            {dayActivity.map(d => (
              <div key={d.day} style={{flex:1,textAlign:"center"}}>
                <div style={{
                  height:32,borderRadius:6,marginBottom:".2rem",
                  background: d.trained ? toneColor : d.rested ? "#3498db44" : "var(--surface2)",
                  border:`1px solid ${d.trained ? toneColor+"66" : d.rested ? "#3498db44" : "var(--border)"}`,
                  display:"flex",alignItems:"center",justifyContent:"center",
                  fontSize:".8rem",
                }}>
                  {d.trained ? "💪" : d.rested ? "🛌" : ""}
                </div>
                <div style={{fontSize:".58rem",color:"var(--text2)"}}>{d.day}</div>
              </div>
            ))}
          </div>

          {/* Stats grid */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:".5rem",marginBottom:"1rem"}}>
            {[
              { icon:"⚡", label:"XP Earned",   value: weekXP.toLocaleString(),                  color:"var(--gold)" },
              { icon:"💪", label:"Sessions",     value: thisWeek.length,                          color:"#27ae60"    },
              { icon:"📋", label:"Total Sets",   value: weekSets,                                 color:"#3498db"    },
              { icon:"🔥", label:"Current Streak",value:`${streak}d`,                             color:"#e67e22"    },
              { icon:"🧘", label:"Meditation",   value: medMins ? `${medMins} min` : "—",         color:"#9b59b6"    },
              { icon:"😴", label:"Avg Sleep",    value: avgSleep ? `${avgSleep}h` : "—",          color:"#3498db"    },
            ].map(s => (
              <div key={s.label} style={{background:"var(--surface)",border:"1px solid var(--border)",
                borderRadius:10,padding:".65rem .75rem",display:"flex",alignItems:"center",gap:".5rem"}}>
                <span style={{fontSize:"1.2rem"}}>{s.icon}</span>
                <div>
                  <div style={{fontFamily:"'Cinzel',serif",fontSize:".95rem",fontWeight:700,color:s.color}}>{s.value}</div>
                  <div style={{fontSize:".62rem",color:"var(--text2)"}}>{s.label}</div>
                </div>
              </div>
            ))}
          </div>

          {/* Best lift */}
          {bestLift && (
            <div style={{background:"var(--surface)",border:"1px solid var(--gold)33",borderRadius:10,
              padding:".65rem .85rem",marginBottom:"1rem",display:"flex",alignItems:"center",gap:".6rem"}}>
              <span style={{fontSize:"1.3rem"}}>🏋️</span>
              <div>
                <div style={{fontSize:".72rem",color:"var(--text2)"}}>Heaviest Lift This Week</div>
                <div style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontWeight:700,fontSize:".92rem"}}>
                  {bestLift.name} — {bestLift.weight} lbs
                </div>
              </div>
            </div>
          )}

          {/* Rival standings */}
          {(character.rivals||[]).length > 0 && (
            <div style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:10,
              padding:".65rem .85rem",marginBottom:"1rem"}}>
              <div style={{fontFamily:"'Cinzel',serif",fontSize:".75rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em",marginBottom:".5rem"}}>⚔️ Rival Standings</div>
              {(character.rivals||[]).map(r => {
                const ahead = weekXP - r.weeklyXP;
                return (
                  <div key={r.id} style={{display:"flex",alignItems:"center",gap:".5rem",
                    padding:".3rem 0",borderBottom:"1px solid var(--border)"}}>
                    <span style={{fontSize:".9rem"}}>{r.cls?.icon}</span>
                    <span style={{flex:1,fontSize:".82rem",fontWeight:600}}>{r.name}</span>
                    <span style={{fontSize:".75rem",fontWeight:700,
                      color: ahead >= 0 ? "#27ae60" : "#e74c3c"}}>
                      {ahead >= 0 ? `▲ +${ahead.toLocaleString()}` : `▼ ${Math.abs(ahead).toLocaleString()}`}
                    </span>
                  </div>
                );
              })}
            </div>
          )}

          <button onClick={onClose} style={{
            width:"100%",padding:".75rem",
            background:"linear-gradient(135deg,var(--gold),var(--gold2))",
            border:"none",borderRadius:10,color:"#000",
            fontFamily:"'Cinzel',serif",fontSize:".95rem",fontWeight:700,cursor:"pointer",
          }}>Close</button>
        </div>
      </div>
    </div>
  );
}


// ─── BOSS OF THE WEEK ─────────────────────────────────────────────────────────
// Appears every Monday, must be defeated by Sunday.
// Requires a XP threshold earned this week to unlock the battle.
// Rewards rare loot + gold on defeat.

const WEEKLY_BOSSES = [
  { name:"The Iron Titan",     icon:"⚙️",  theme:"Colossus",  color:"#95a5a6", xpReq:500,  reward:{ gold:300, lootRarity:"Rare"      } },
  { name:"Veldrath the Undying",icon:"💀", theme:"Undead",    color:"#8e44ad", xpReq:800,  reward:{ gold:450, lootRarity:"Rare"      } },
  { name:"The Gilded Serpent", icon:"🐍",  theme:"Poison",    color:"#27ae60", xpReq:1000, reward:{ gold:550, lootRarity:"Epic"      } },
  { name:"Stormcaller Karath", icon:"⛈️", theme:"Lightning", color:"#3498db", xpReq:1200, reward:{ gold:650, lootRarity:"Epic"      } },
  { name:"Malachar the Fallen",icon:"😈",  theme:"Chaos",     color:"#e74c3c", xpReq:1500, reward:{ gold:800, lootRarity:"Epic"      } },
  { name:"The Obsidian Wyrm",  icon:"🐉",  theme:"Dragon",    color:"#c0392b", xpReq:2000, reward:{ gold:1000,lootRarity:"Legendary" } },
  { name:"Vorath, God of Iron",icon:"👑",  theme:"Legendary", color:"#c9a84c", xpReq:3000, reward:{ gold:1500,lootRarity:"Legendary" } },
];

function getWeekBoss(level) {
  const weekNum = Math.floor(Date.now() / (7 * 24 * 3600 * 1000));
  const idx     = weekNum % WEEKLY_BOSSES.length;
  const boss    = WEEKLY_BOSSES[idx];
  // Weekly bosses are elite — 4x HP, 2.5x damage vs regular dungeon bosses
  return {
    ...boss,
    hp:  800 + level * 120,
    atk:  40 + level * 8,
    xpReq: Math.max(300, boss.xpReq - Math.max(0, 10-level) * 50),
  };
}

// Get the week key (YYYY-WW)
function getWeekKey() {
  const d = new Date();
  const startOfYear = new Date(d.getFullYear(), 0, 1);
  const week = Math.ceil(((d - startOfYear) / 86400000 + startOfYear.getDay() + 1) / 7);
  return `${d.getFullYear()}-W${String(week).padStart(2,"0")}`;
}

function BossOfTheWeekCard({ character, onFight, onClose }) {
  const level      = xpToLevel(character.xp);
  const boss       = getWeekBoss(level);
  const weekKey    = getWeekKey();
  const weeklyXP   = getPlayerWeeklyXP(character);
  const botw       = character.bossOfTheWeek || {};
  const beaten     = botw.weekKey === weekKey && botw.beaten;
  const attempted  = botw.weekKey === weekKey && botw.attempted;
  const unlocked   = true; // always accessible
  const pct        = Math.min(100, (weeklyXP / boss.xpReq) * 100);
  const rc         = boss?.color || "#c9a84c";
  if (!boss) return null;

  return (
    <div style={{background:"var(--surface)",border:`2px solid ${rc}66`,borderRadius:14,padding:"1rem",marginBottom:"1rem",position:"relative"}}>
      {/* Background glow */}
      <div style={{position:"absolute",inset:0,background:`radial-gradient(ellipse at top right, ${rc}15, transparent 60%)`,pointerEvents:"none"}}/>

      <div style={{display:"flex",alignItems:"flex-start",gap:".75rem",marginBottom:".85rem",position:"relative"}}>
        <div style={{
          width:52,height:52,borderRadius:12,flexShrink:0,
          background:`${rc}22`,border:`2px solid ${rc}66`,
          display:"flex",alignItems:"center",justifyContent:"center",
          fontSize:"1.8rem",
          filter: beaten ? "grayscale(60%)" : unlocked ? `drop-shadow(0 0 6px ${rc}88)` : "none",
        }}>{boss.icon}</div>
        <div style={{flex:1}}>
          <div style={{display:"flex",alignItems:"center",gap:".4rem",marginBottom:".2rem"}}>
            <span style={{fontFamily:"'Cinzel',serif",fontSize:".72rem",color:rc,fontWeight:700,textTransform:"uppercase",letterSpacing:".05em"}}>Boss of the Week</span>
            {beaten && <span style={{fontSize:".62rem",color:"#27ae60",fontWeight:700,background:"#27ae6022",border:"1px solid #27ae6044",borderRadius:10,padding:"1px 6px"}}>Defeated ✓</span>}
          </div>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:"1.05rem",fontWeight:700,color:"var(--text)"}}>{boss.name}</div>
          <div style={{fontSize:".72rem",color:"var(--text2)",marginTop:".1rem"}}>{boss.theme} · {boss.hp} HP · Lv.{level}</div>
        </div>
      </div>

      {/* Rewards */}
      <div style={{display:"flex",gap:".4rem",marginBottom:".85rem"}}>
        {[
          { icon:"💰", label:`${boss.reward.gold}g` },
          { icon:"🎁", label:`${boss.reward.lootRarity} Loot` },
          { icon:"⚡",  label:`+${Math.round(boss.xpReq * 0.5)} XP` },
        ].map(r => (
          <div key={r.label} style={{flex:1,background:"var(--surface2)",border:"1px solid var(--border)",borderRadius:8,padding:".3rem .4rem",textAlign:"center"}}>
            <div style={{fontSize:".9rem"}}>{r.icon}</div>
            <div style={{fontSize:".62rem",color:"var(--text2)",fontWeight:600}}>{r.label}</div>
          </div>
        ))}
      </div>

      {/* Weekly XP progress — flavour, not a gate */}
      {!beaten && (
        <div style={{marginBottom:".75rem"}}>
          <div style={{display:"flex",justifyContent:"space-between",fontSize:".68rem",color:"var(--text2)",marginBottom:".25rem"}}>
            <span>Weekly training</span>
            <span style={{color:rc,fontWeight:700}}>{weeklyXP.toLocaleString()} / {boss.xpReq.toLocaleString()} XP</span>
          </div>
          <div style={{height:5,background:"var(--surface2)",borderRadius:3,overflow:"hidden"}}>
            <div style={{height:"100%",width:`${pct}%`,background:rc,borderRadius:3,transition:"width .4s"}}/>
          </div>
          {pct >= 100
            ? <div style={{fontSize:".65rem",color:"#27ae60",marginTop:".25rem",fontStyle:"italic"}}>✓ Fully trained — you're at peak power!</div>
            : <div style={{fontSize:".65rem",color:"var(--text2)",marginTop:".25rem",fontStyle:"italic"}}>Train more this week to reach peak power before the fight</div>
          }
        </div>
      )}

      {beaten ? (
        <div style={{textAlign:"center",color:"#27ae60",fontSize:".85rem",fontStyle:"italic",padding:".5rem 0"}}>
          ⚔️ Vanquished — return next Monday for a new challenger
        </div>
      ) : (
        <button onClick={onFight} style={{
          width:"100%",padding:".85rem",
          background:`linear-gradient(135deg,${rc},${rc}cc)`,
          border:"none",borderRadius:10,color:"#000",
          fontFamily:"'Cinzel',serif",fontSize:"1rem",fontWeight:700,cursor:"pointer",
          position:"relative",zIndex:10,
          boxShadow:`0 4px 15px ${rc}55`,
        }}>
          ⚔️ Fight {boss.name}
        </button>
      )}
    </div>
  );
}


