// ─── WORKOUT ANALYTICS ────────────────────────────────────────────────────────
// Visual charts of XP over time, muscle frequency, and volume trends.

function AnalyticsView({ character }) {
  const history = character.workoutHistory || [];
  if (history.length < 2) return (
    <div style={{textAlign:"center",padding:"2rem 1rem",color:"var(--text2)"}}>
      <div style={{fontSize:"2rem",marginBottom:".5rem"}}>📊</div>
      <p style={{fontSize:".88rem"}}>Log at least 2 workouts to see your analytics.</p>
    </div>
  );

  // Last 8 sessions XP bar chart
  const recent = [...history].filter(h=>!h.isRestDay).slice(-8);
  const maxXP  = Math.max(...recent.map(h=>h.xp||0), 1);

  // Muscle frequency this month
  const monthAgo = new Date(); monthAgo.setDate(monthAgo.getDate()-30);
  const monthHistory = history.filter(h => new Date(h.date)>=monthAgo && !h.isRestDay);
  const muscleFreq = {};
  monthHistory.forEach(h => (h.exercises||[]).forEach(ex => {
    const found = ALL_EXERCISES.find(e=>e.name===ex.name);
    if (found) muscleFreq[found.muscle] = (muscleFreq[found.muscle]||0) + (ex.sets||1);
  }));
  const muscleEntries = Object.entries(muscleFreq).sort((a,b)=>b[1]-a[1]).slice(0,6);
  const maxMuscle = Math.max(...muscleEntries.map(e=>e[1]),1);

  // Weekly volume trend
  const weeks = {};
  history.filter(h=>!h.isRestDay).forEach(h => {
    const d = new Date(h.date);
    const wk = new Date(d); wk.setDate(d.getDate()-d.getDay());
    const wkKey = wk.toISOString().slice(0,10);
    weeks[wkKey] = (weeks[wkKey]||0) + (h.xp||0);
  });
  const weekEntries = Object.entries(weeks).sort((a,b)=>a[0].localeCompare(b[0])).slice(-6);
  const maxWeek = Math.max(...weekEntries.map(e=>e[1]),1);

  return (
    <div style={{marginBottom:"1rem"}}>

      {/* XP per session */}
      <div style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:12,padding:"1rem",marginBottom:"1rem"}}>
        <div style={{fontFamily:"'Cinzel',serif",fontSize:".78rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em",marginBottom:".75rem"}}>Last {recent.length} Sessions</div>
        <div style={{display:"flex",gap:".3rem",alignItems:"flex-end",height:80}}>
          {recent.map((h,i) => {
            const pct = ((h.xp||0)/maxXP)*100;
            const d   = new Date(h.date);
            return (
              <div key={i} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:".2rem"}}>
                <div style={{fontSize:".55rem",color:"var(--gold)",fontWeight:700}}>{h.xp}</div>
                <div style={{width:"100%",borderRadius:"3px 3px 0 0",background:"var(--gold)",height:`${Math.max(4,pct*0.65)}px`,transition:"height .3s"}}/>
                <div style={{fontSize:".5rem",color:"var(--text2)"}}>{d.toLocaleDateString("en-US",{weekday:"short"})}</div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Weekly volume */}
      {weekEntries.length >= 2 && (
        <div style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:12,padding:"1rem",marginBottom:"1rem"}}>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:".78rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em",marginBottom:".75rem"}}>Weekly XP Trend</div>
          <div style={{display:"flex",gap:".3rem",alignItems:"flex-end",height:70}}>
            {weekEntries.map(([wk,xp],i) => {
              const pct = (xp/maxWeek)*100;
              const d   = new Date(wk);
              const isLast = i===weekEntries.length-1;
              return (
                <div key={wk} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:".2rem"}}>
                  <div style={{fontSize:".52rem",color:isLast?"var(--gold)":"var(--text2)",fontWeight:isLast?700:400}}>{(xp/1000).toFixed(1)}k</div>
                  <div style={{width:"100%",borderRadius:"3px 3px 0 0",
                    background:isLast?"var(--gold)":"#c9a84c66",
                    height:`${Math.max(4,pct*0.56)}px`,transition:"height .3s"}}/>
                  <div style={{fontSize:".5rem",color:"var(--text2)"}}>W{i+1}</div>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {/* Muscle frequency */}
      {muscleEntries.length > 0 && (
        <div style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:12,padding:"1rem",marginBottom:"1rem"}}>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:".78rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em",marginBottom:".75rem"}}>Muscle Focus (30 days)</div>
          <div style={{display:"flex",flexDirection:"column",gap:".35rem"}}>
            {muscleEntries.map(([muscle,sets]) => (
              <div key={muscle} style={{display:"flex",alignItems:"center",gap:".5rem"}}>
                <div style={{fontSize:".72rem",color:"var(--text2)",minWidth:76,textAlign:"right"}}>{muscle}</div>
                <div style={{flex:1,height:8,background:"var(--surface2)",borderRadius:4,overflow:"hidden"}}>
                  <div style={{height:"100%",width:`${(sets/maxMuscle)*100}%`,background:"#3498db",borderRadius:4,transition:"width .4s"}}/>
                </div>
                <div style={{fontSize:".68rem",color:"#3498db",fontWeight:700,minWidth:28}}>{sets}</div>
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}


