function getChallengeProgress(challenge, character) {
  const weekStart = new Date(); weekStart.setDate(weekStart.getDate()-weekStart.getDay()); weekStart.setHours(0,0,0,0);
  const history   = (character.workoutHistory||[]).filter(h=>new Date(h.date)>=weekStart);
  const wellLog   = (character.wellnessLog||[]).filter(e=>new Date(e.date)>=weekStart);
  const floorLog  = Object.values(character.floorClears||{}).flat();
  switch(challenge.type) {
    case "workouts":   return history.filter(h=>!h.isRestDay).length;
    case "sets":       return history.reduce((s,h)=>s+(h.exercises||[]).reduce((ss,e)=>ss+(e.sets||0),0),0);
    case "streak":     return character.workoutStreak||0;
    case "meditation": return wellLog.filter(e=>e.type==="meditation").length;
    case "sleep7":     return wellLog.filter(e=>e.type==="sleep"&&e.hrs>=7).length;
    case "floors":     return floorLog.filter(f => {
      // Count floors cleared this week — approximate via dungeon history
      return true; // simplified
    }).length;
    default: return 0;
  }
}

function PersonalChallengesView({ character, onSaveChallenge, onClaimChallenge }) {
  const [creating, setCreating] = useState(false);
  const [template, setTemplate] = useState(null);
  const [target,   setTarget]   = useState("");
  const challenges = character.personalChallenges || [];
  const weekKey    = getWeekKey();

  function handleCreate() {
    if (!template || !parseInt(target)) return;
    const ch = {
      id:       Date.now().toString(36),
      templateId: template.id,
      type:     template.type,
      icon:     template.icon,
      label:    template.label.replace("X", target),
      target:   parseInt(target),
      xp:       template.xp,
      gold:     template.gold,
      weekKey,
      claimed:  false,
    };
    onSaveChallenge(ch);
    setCreating(false);
    setTemplate(null);
    setTarget("");
  }

  const thisWeekChallenges = challenges.filter(c => c.weekKey === weekKey);

  return (
    <div style={{marginBottom:"1rem"}}>
      <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:".6rem"}}>
        <div style={{fontFamily:"'Cinzel',serif",fontSize:".78rem",color:"var(--text2)",textTransform:"uppercase",letterSpacing:".06em"}}>🎯 Personal Challenges</div>
        {thisWeekChallenges.length < 3 && (
          <button onClick={() => setCreating(c=>!c)} style={{padding:".25rem .65rem",background:"var(--surface2)",border:"1px solid var(--border)",borderRadius:20,color:"var(--text2)",fontSize:".68rem",fontFamily:"'Cinzel',serif",cursor:"pointer",fontWeight:700}}>
            {creating ? "Cancel" : "+ New"}
          </button>
        )}
      </div>

      {creating && (
        <div style={{background:"var(--surface)",border:"1px solid var(--border)",borderRadius:12,padding:".85rem",marginBottom:".65rem"}}>
          <div style={{fontSize:".72rem",color:"var(--text2)",marginBottom:".5rem"}}>Choose a challenge type:</div>
          <div style={{display:"flex",flexDirection:"column",gap:".3rem",marginBottom:".65rem"}}>
            {CHALLENGE_TEMPLATES.map(t => (
              <button key={t.id} onClick={() => { setTemplate(t); setTarget(String(t.defaultTarget)); }}
                style={{display:"flex",alignItems:"center",gap:".5rem",padding:".45rem .65rem",
                  background: template?.id===t.id ? "#c9a84c22" : "var(--surface2)",
                  border:`1px solid ${template?.id===t.id ? "var(--gold)" : "var(--border)"}`,
                  borderRadius:8,cursor:"pointer",textAlign:"left",
                }}>
                <span>{t.icon}</span>
                <span style={{flex:1,fontSize:".78rem",color:"var(--text)"}}>{t.label}</span>
                <span style={{fontSize:".65rem",color:"var(--gold)",fontWeight:700}}>+{t.xp}XP</span>
              </button>
            ))}
          </div>
          {template && (
            <div style={{display:"flex",gap:".5rem",alignItems:"center"}}>
              <span style={{fontSize:".8rem",color:"var(--text2)",flex:1}}>{template.label.replace("X","")}</span>
              <input type="number" value={target} onChange={e=>setTarget(e.target.value)} min="1"
                style={{width:60,background:"var(--surface2)",border:"1px solid var(--border)",borderRadius:7,padding:".35rem .5rem",color:"var(--text)",fontSize:".9rem",textAlign:"center"}}/>
              <button onClick={handleCreate} style={{padding:".4rem .9rem",background:"linear-gradient(135deg,var(--gold),var(--gold2))",border:"none",borderRadius:8,color:"#000",fontFamily:"'Cinzel',serif",fontSize:".78rem",fontWeight:700,cursor:"pointer"}}>
                Set
              </button>
            </div>
          )}
        </div>
      )}

      {thisWeekChallenges.length === 0 && !creating && (
        <div style={{textAlign:"center",padding:"1rem",color:"var(--text2)",fontSize:".8rem",fontStyle:"italic",background:"var(--surface)",borderRadius:10,border:"1px solid var(--border)"}}>
          No challenges this week. Set up to 3 personal goals.
        </div>
      )}

      <div style={{display:"flex",flexDirection:"column",gap:".45rem"}}>
        {thisWeekChallenges.map(ch => {
          const progress = getChallengeProgress(ch, character);
          const pct      = Math.min(100,(progress/ch.target)*100);
          const done     = progress >= ch.target;
          return (
            <div key={ch.id} style={{background:"var(--surface)",border:`1px solid ${done&&!ch.claimed?"var(--gold)":"var(--border)"}`,borderRadius:10,padding:".65rem .85rem",opacity:ch.claimed?0.6:1}}>
              <div style={{display:"flex",alignItems:"center",gap:".5rem",marginBottom:".4rem"}}>
                <span style={{fontSize:"1rem"}}>{ch.icon}</span>
                <span style={{flex:1,fontSize:".82rem",fontWeight:600}}>{ch.label}</span>
                {ch.claimed ? (
                  <span style={{fontSize:".7rem",color:"#27ae60",fontWeight:700}}>✓ Claimed</span>
                ) : done ? (
                  <button onClick={() => onClaimChallenge(ch)} style={{padding:".25rem .65rem",background:"linear-gradient(135deg,var(--gold),var(--gold2))",border:"none",borderRadius:6,color:"#000",fontFamily:"'Cinzel',serif",fontSize:".7rem",fontWeight:700,cursor:"pointer",animation:"pulse .8s ease infinite alternate"}}>
                    Claim!
                  </button>
                ) : (
                  <span style={{fontSize:".7rem",color:"var(--text2)"}}>{progress}/{ch.target}</span>
                )}
              </div>
              <div style={{height:4,background:"var(--surface2)",borderRadius:2,overflow:"hidden"}}>
                <div style={{height:"100%",borderRadius:2,background:done?"var(--gold)":"#c9a84c88",width:`${pct}%`,transition:"width .4s"}}/>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}


// ─── CHARACTER JOURNAL ────────────────────────────────────────────────────────
// Auto-generated narrative entries after each workout session.

const JOURNAL_TEMPLATES = {
  light: [
    "A quick session today, but the iron never lies. I moved weight, and the dungeon took notice.",
    "Not my best day, but I showed up. The Rusted King won't defeat itself.",
    "Short and focused. Quality over quantity — that's what the old masters said.",
  ],
  moderate: [
    "The sets stacked up. My arms remember every rep, whether I want them to or not.",
    "Solid work today. The {exercise} felt strong. Getting closer to something.",
    "Another day forged in sweat. The dungeon waits, but I'm not ready to face it weak.",
  ],
  heavy: [
    "The {exercise} nearly broke me today. Nearly. I loaded the bar heavier than before and didn't die. Progress.",
    "Heavy day. Everything hurts in the right way. This is what becoming looks like.",
    "I pushed past what I thought I could do today. {sets} sets of {exercise}. My body will remember this.",
  ],
  streak: [
    "Day {streak} of consecutive training. The streak has become the mission now.",
    "{streak} days in a row. I don't remember what rest feels like anymore — and I don't miss it.",
  ],
  levelup: [
    "Level {level}. The numbers climb, but the real change is in the mirror. Slowly. Surely.",
    "Reached level {level} today. Every level is just the last one with more weight on the bar.",
  ],
};

function generateJournalEntry(session, character) {
  const sets     = session.exercises?.reduce((s,e)=>s+(e.sets||0),0) || 0;
  const hasHeavy = session.hasHeavy;
  const streak   = character.workoutStreak || 0;
  const level    = xpToLevel(character.xp);
  const mainEx   = session.exercises?.[0]?.name || "the bar";

  let pool;
  if      (hasHeavy && sets >= 15) pool = JOURNAL_TEMPLATES.heavy;
  else if (streak >= 7)            pool = JOURNAL_TEMPLATES.streak;
  else if (sets >= 10)             pool = JOURNAL_TEMPLATES.moderate;
  else                             pool = JOURNAL_TEMPLATES.light;

  const template = pool[Math.floor(Math.random() * pool.length)];
  return template
    .replace("{exercise}", mainEx)
    .replace("{sets}", sets)
    .replace("{streak}", streak)
    .replace("{level}", level);
}

function JournalView({ character, onSaveNote, onDeleteNote }) {
  const notes = [...(character.journalNotes || [])].reverse();
  const [text, setText] = useState("");
  const [title, setTitle] = useState("");
  const [writing, setWriting] = useState(false);
  const [editId, setEditId] = useState(null);

  function saveNote() {
    if (!text.trim()) return;
    const note = {
      id: editId || Date.now().toString(),
      title: title.trim() || null,
      text: text.trim(),
      date: new Date().toISOString(),
    };
    onSaveNote(note, editId);
    setText("");
    setTitle("");
    setWriting(false);
    setEditId(null);
  }

  function startEdit(note) {
    setEditId(note.id);
    setTitle(note.title || "");
    setText(note.text);
    setWriting(true);
  }

  if (writing) return (
    <div style={{display:"flex",flexDirection:"column",gap:".75rem"}}>
      <div style={{display:"flex",alignItems:"center",gap:".5rem"}}>
        <button onClick={() => { setWriting(false); setEditId(null); setText(""); setTitle(""); }}
          style={{background:"none",border:"none",color:"var(--text2)",fontSize:"1.2rem",cursor:"pointer",padding:".2rem .4rem"}}>←</button>
        <span style={{fontFamily:"'Cinzel',serif",color:"var(--gold)",fontSize:"1rem",fontWeight:700}}>
          {editId ? "Edit Note" : "New Note"}
        </span>
      </div>
      <input
        value={title}
        onChange={e => setTitle(e.target.value)}
        placeholder="Title (optional)"
        style={{
          background:"var(--surface)", border:"1px solid var(--border)",
          borderRadius:8, padding:".65rem .85rem", color:"var(--text)",
          fontSize:".9rem", fontFamily:"'Cinzel',serif",
          outline:"none", width:"100%", boxSizing:"border-box",
        }}
      />
      <textarea
        value={text}
        onChange={e => setText(e.target.value)}
        placeholder="Write about your workout, how you felt, what to improve, goals for next session..."
        rows={8}
        style={{
          background:"var(--surface)", border:"1px solid var(--border)",
          borderRadius:8, padding:".75rem .85rem", color:"var(--text)",
          fontSize:".88rem", lineHeight:1.6, resize:"none",
          outline:"none", width:"100%", boxSizing:"border-box",
          fontFamily:"inherit",
        }}
      />
      <button onClick={saveNote} disabled={!text.trim()} style={{
        background: text.trim() ? "linear-gradient(135deg,#c9a84c,#f0c96a)" : "var(--surface2)",
        border:"none", borderRadius:10, padding:".75rem",
        color: text.trim() ? "#000" : "var(--text2)",
        fontFamily:"'Cinzel',serif", fontSize:".95rem", fontWeight:700,
        cursor: text.trim() ? "pointer" : "not-allowed",
      }}>{editId ? "Save Changes" : "Save Note"}</button>
    </div>
  );

  return (
    <div style={{display:"flex",flexDirection:"column",gap:".65rem"}}>
      <button onClick={() => setWriting(true)} style={{
        display:"flex", alignItems:"center", gap:".5rem", justifyContent:"center",
        background:"#c9a84c18", border:"1px solid #c9a84c55",
        borderRadius:10, padding:".75rem",
        color:"var(--gold)", fontFamily:"'Cinzel',serif",
        fontSize:".9rem", fontWeight:700, cursor:"pointer",
        marginBottom:".25rem",
      }}>✏️ New Note</button>

      {notes.length === 0 ? (
        <div style={{textAlign:"center",padding:"2rem 1rem",color:"var(--text2)"}}>
          <div style={{fontSize:"2rem",marginBottom:".5rem"}}>📖</div>
          <p style={{fontSize:".88rem"}}>Your journal is empty. Write about your workouts, goals, or anything on your mind.</p>
        </div>
      ) : notes.map(note => {
        const d = new Date(note.date);
        return (
          <div key={note.id} style={{
            background:"var(--surface)", border:"1px solid var(--border)",
            borderRadius:10, padding:".85rem 1rem",
          }}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:".4rem"}}>
              <div>
                {note.title && <div style={{fontFamily:"'Cinzel',serif",fontSize:".88rem",fontWeight:700,color:"var(--gold)",marginBottom:".15rem"}}>{note.title}</div>}
                <span style={{fontSize:".68rem",color:"var(--text2)"}}>
                  {d.toLocaleDateString("en-US",{weekday:"short",month:"short",day:"numeric"})} · {d.toLocaleTimeString("en-US",{hour:"2-digit",minute:"2-digit"})}
                </span>
              </div>
              <div style={{display:"flex",gap:".3rem",flexShrink:0}}>
                <button onClick={() => startEdit(note)} style={{
                  background:"none", border:"1px solid var(--border)", borderRadius:6,
                  padding:"3px 8px", color:"var(--text2)", fontSize:".72rem", cursor:"pointer",
                }}>Edit</button>
                <button onClick={() => onDeleteNote(note.id)} style={{
                  background:"none", border:"1px solid rgba(231,76,60,.3)", borderRadius:6,
                  padding:"3px 8px", color:"#e74c3c", fontSize:".72rem", cursor:"pointer",
                }}>✕</button>
              </div>
            </div>
            <p style={{fontSize:".84rem",color:"var(--text)",lineHeight:1.65,margin:0,whiteSpace:"pre-wrap"}}>{note.text}</p>
          </div>
        );
      })}
    </div>
  );
}

